    public List<Customers> getCustomerByUsername(String username) {
        //Active, InActive,Suspend, NewActivaition customer status can be login for cwsc
        return customersRepository.findByTrimmedNameIgnoreCase(username).stream().filter(customer -> (!customer.getStatus().equalsIgnoreCase("Terminate") && !customer.getStatus().equalsIgnoreCase("Rejected")) && (customer.getMvnoId() == getMvnoIdFromCurrentStaff().intValue() || customer.getMvnoId() == null) && (customer.getMvnoId() == 1 || getBUIdsFromCurrentStaff().size() == 0 || getBUIdsFromCurrentStaff().contains(customer.getBuId()))).collect(Collectors.toList());
    }

