    public void deleteCustomerWithFlag(Customers customers) {
        getEntityForUpdateAndDelete(customers.getId(),customers.getMvnoId());
        List<Case> caseList = caseRepository.findAllByCustomers_IdAndIsDeleteIsFalseOrderByCaseIdDesc(customers.getId());
        if (caseList != null && caseList.size() > 0) {
            for (Case caseDb : caseList) {
                caseDb.setIsDelete(true);
                caseRepository.save(caseDb);
            }
        }
        customers.setIsDeleted(true);
        customers.setAadhar(updatedAadhar(customers.getId(), customers.getAadhar()));
        customers.setPan(updatedPan(customers.getId(), customers.getPan()));
        customers.setGst(updatedGst(customers.getId(), customers.getGst()));
        Customers cust = customersRepository.save(customers);
        CustomMessage customMessage = new CustomMessage(customerMapper.domainToDTO(cust, new CycleAvoidingMappingContext()));
        //messageSender.send(customMessage, RabbitMqConstants.QUEUE_APIGW_CUSTOMER);
        kafkaMessageSender.send(new KafkaMessageData(customMessage, customMessage.getClass().getSimpleName(), "CUSTOMER_CREATE"));


        //send message
        if (customers.getStatus() != null && !customers.getStatus().equalsIgnoreCase("NewActivation")) {
            CustomerMessage customerMessage = new CustomerMessage();
            customerMessage.setId(customers.getId());
            customerMessage.setTitle(customers.getTitle());
            customerMessage.setUsername(customers.getUsername());
            customerMessage.setPassword(customers.getPassword());
            customerMessage.setFirstname(customers.getFirstname());
            customerMessage.setLastname(customers.getLastname());
            customerMessage.setStatus(customers.getStatus());
            customerMessage.setMvnoId(customers.getMvnoId());
            customerMessage.setBuId(customers.getBuId() != null ? customers.getBuId().intValue() : 0);
            customerMessage.setIsDeleted(true);
//            this.messageSender.send(customerMessage, RabbitMqConstants.QUEUE_APIGW_SEND_CUSTOMER);
            kafkaMessageSender.send(new KafkaMessageData(customerMessage, CustomerMessage.class.getSimpleName()));
        }

    }

