    public String forgotPass(Customers customers) throws Exception {
        Random random = new Random();
        String otp = String.format("%04d", random.nextInt(10000));
        customers.setOtp(otp);

        LocalDateTime now = LocalDateTime.now();
        DateTimeFormatter format = DateTimeFormatter.ofPattern("dd-MM-yyyy HH:mm:ss");
        String formatDateTime = now.format(format);
        LocalDateTime validate = LocalDateTime.parse(formatDateTime, format);
        customers.setOtpvalidate(validate);
        customers.setAadhar(updatedAadhar(customers.getId(), customers.getAadhar()));
        customers.setPan(updatedPan(customers.getId(), customers.getPan()));
        customers.setGst(updatedGst(customers.getId(), customers.getGst()));
        // TODO: pass mvnoID manually 6/5/2025
        customers.setMvnoId(getMvnoIdFromCurrentStaff(null));
        update(customers);
        CommunicationHelper communicationHelper = new CommunicationHelper();
        Map<String, String> map = new HashMap<>();
        map.put(CommunicationConstant.DESTINATION, customers.getMobile());
        map.put(CommunicationConstant.EMAIL, customers.getEmail());
        map.put(CommunicationConstant.OTP, otp);
        communicationHelper.generateCommunicationDetails(CommunicationConstant.PASSWORD_OTP, Collections.singletonList(map));
        return "Success---" + otp;
    }

    public String validateForgotPassword(Customers customers, ForgotPassowrdDTO dto) throws Exception {
        String response;
        LocalDateTime time = customers.getOtpvalidate();
        LocalDateTime now = LocalDateTime.now();
        DateTimeFormatter format = DateTimeFormatter.ofPattern("dd-MM-yyyy HH:mm:ss");
        String formatDateTime = now.format(format);
        LocalDateTime validate = LocalDateTime.parse(formatDateTime, format);
        LocalDateTime tempDateTime = customers.getOtpvalidate();
        long minutes = tempDateTime.until(validate, ChronoUnit.MINUTES);
        long min = Long.parseLong(messagesProperty.get("customer.validate.time"));
        if (customers.getOtp().equalsIgnoreCase(dto.getOtp()) && minutes <= min) {
            response = "Success--" + customers.getOtp();
        } else {
            response = "Fail";
        }
        return response;
    }

