    public CustAccountProfile fetchSubscriberAccountProfileDetail(Long profileId) {
        /*CustAccountProfile custAccountProfile = custAccountProfileRepository.findByProfileId(profileId).orElse(null);
        return custAccountProfile;*/
        String cacheKey = cacheKeys.ACCOUNTPROFILE_PROFILEID + profileId; // Create a unique cache key
        CustAccountProfile custAccountProfile = null;

        try {
            custAccountProfile = (CustAccountProfile) cacheService.getFromCache(cacheKey, CustAccountProfile.class);

            if (custAccountProfile != null) {
                return custAccountProfile;
            }
            custAccountProfile = custAccountProfileRepository.findByProfileId(profileId).orElse(null);

            if (custAccountProfile != null) {
                cacheService.putInCacheWithExpire(cacheKey, custAccountProfile);
            }
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
        return custAccountProfile;

    }

