//                                    workflowAssignStaffMappingService.assignWorkflowToStaff(Integer.parseInt(map.get("eventId").toString()), CommonConstants.WORKFLOW_EVENT_NAME.CAF, savedCustomer, map);
                                   workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId").toString()) : null, CommonConstants.WORKFLOW_EVENT_NAME.CAF, savedCustomer.getId(), savedCustomer.getUsername(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.ASSIGNED, LocalDateTime.now(), "Assigned to :- " + currentStaff.getUsername());
