    public Customers savePaymentXMLDocument(Customers savedCustomer) {
        String SUBMODULE = MODULE + " [savePaymentXMLDocument()] ";
        try {
            // Set PaymentXML For CreditDoc
            if (null != savedCustomer && null != savedCustomer.getCreditDocuments() && 0 < savedCustomer.getCreditDocuments().size()) {
                CustomerAddress presentAddress = savedCustomer.getAddressList().stream().filter(address -> null != address.getAddressType() && address.getAddressType().equalsIgnoreCase(UtilsCommon.ADDR_TYPE_PRESENT)).collect(Collectors.toList()).get(0);
                for (CreditDocument creditDocument : savedCustomer.getCreditDocuments()) {
                    creditDocument.setXmldocument(creditDocService.assemblePaymentXML(creditDocument, presentAddress.getAddressType(), presentAddress, null,savedCustomer.getMvnoId().intValue()));
                    this.creditDocService.updateById(creditDocument.getId(), creditDocument);
                }
                return savedCustomer;
            }
        } catch (Exception ex) {
            ApplicationLogger.logger.error("Unable to save payment XML detsild response{},exception{}", APIConstants.FAIL, ex.getStackTrace());
            throw ex;
        }
        return null;
    }

    // Call Bill Run
    public void billRunForCreditDoc(List<CreditDocument> creditDocumentList) throws Exception {
        try {
            if (null != creditDocumentList && 0 < creditDocumentList.size()) {
                for (CreditDocument creditDocument : creditDocumentList) {
                    billRunService.generatePaymentReceipt(creditDocument.getId().toString());
                }
            }
        } catch (Exception ex) {
            ApplicationLogger.logger.error("Unable to geneate billrun for credit doc ", APIConstants.FAIL, ex.getStackTrace());
            throw ex;
        }
    }

