    public void validateRequest(CustomersPojo pojo, Integer operation) {

        String mobileRegex = null;
        int min = 0;
        int max = 0;
//        if (pojo.getMvnoId() != null) {
//            mvnoId = customersRepository.findMvnoIdById(pojo.getMvnoId());
//        }
        if (pojo == null) {
            throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.required.object.not.set"), null);
        }
        Integer mvnoId = pojo.getMvnoId();
        if (mvnoId == null) {
            mvnoId = getLoggedInMvnoId();
        }
        // TODO: pass mvnoID manually 6/5/2025
        mobileRegex = clientServiceSrv.getCurrencyByNameAadMvnoId("MOBILE_NUMBER",mvnoId).getValue();

        if (pojo != null && operation.equals(CommonConstants.OPERATION_ADD)) {
            if (pojo.getId() != null)
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.id.validation"), null);
        }
//        if (!(pojo.getStatus().equalsIgnoreCase("ACTIVE") || pojo.getStatus().equalsIgnoreCase("INACTIVE") || pojo.getStatus().equalsIgnoreCase("BLOCK"))) {
//            throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.inproper.value.for.status"), null);
//        }
        if (operation.equals(CommonConstants.OPERATION_ADD) && pojo.getCountry() != null) {
            if (countryService.get(pojo.getCountry(),mvnoId) == null) {
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.country.not.found"), null);
            }
        }
        if (operation.equals(CommonConstants.OPERATION_ADD) && pojo.getState() != null) {
            if (stateService.get(pojo.getState(),mvnoId) == null) {
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.state.not.found"), null);
            }
        }
        if (operation.equals(CommonConstants.OPERATION_ADD) && pojo.getCity() != null) {
            if (cityService.get(pojo.getCity(),mvnoId) == null) {
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.city.not.found"), null);
            }
        }
        if (null != pojo && pojo.getCusttype().isEmpty()) {
            throw new CustomValidationException(APIConstants.FAIL, "Please select customer type", null);
        }
        if (!operation.equals(CommonConstants.OPERATION_DELETE) && !(pojo.getCusttype().equalsIgnoreCase("Postpaid") || (pojo.getCusttype().equalsIgnoreCase("Prepaid")))) {
            throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.inproper.value.for.customer.type"), null);
        }
//        if (null != pojo && pojo.getTitle().isEmpty()) {
//            throw new CustomValidationException(APIConstants.FAIL, "Please select title", null);
//        }
//        if (null != pojo && pojo.getCafno().isEmpty()) {
//            throw new CustomValidationException(APIConstants.FAIL, "Please enter CAFNo", null);
//        }
        if (null != pojo && (pojo.getMobile().isEmpty())) {
            throw new CustomValidationException(APIConstants.FAIL, "Please enter mobile", null);
        }
        Pattern pattern = Pattern.compile("\\\\d\\{(\\d+)(?:,(\\d+))?\\}");
        Matcher matcher = pattern.matcher(mobileRegex);
        if (matcher.find()) {
            min = Integer.parseInt(matcher.group(1));
            if (matcher.group(2) != null) {
                max = Integer.parseInt(matcher.group(2));
            } else {
                max = min;
            }
        }
        mobileRegex = mobileRegex.replace("\\\\", "\\");
        if (pojo != null && pojo.getMobile() != null && !pojo.getMobile().isEmpty()) {
            String mobile = pojo.getMobile().trim();

            if (!mobile.matches(mobileRegex)) {
                String msg;
                if (min == max) {
                    msg = "Mobile number must be exactly " + min + " digits.";
                } else {
                    msg = "Mobile number must be between " + min + " to " + max + " digits.";
                }
                throw new CustomValidationException(APIConstants.FAIL, msg, null);
            }
        }
        if (operation.equals(CommonConstants.OPERATION_UPDATE) && pojo.getId() != null) {
            if (customersRepository.getOne(pojo.getId()) == null) {
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.customer.not.found"), null);
            }
        }
        if (pojo != null && (operation.equals(CommonConstants.OPERATION_UPDATE) || operation.equals(CommonConstants.OPERATION_DELETE)) && pojo.getId() == null) {
            throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.id.cannot.set.null"), null);
        }
    }

    public int getLoggedInUserId() {
        int loggedInUserId = -1;
        try {
            SecurityContext securityContext = SecurityContextHolder.getContext();
            if (null != securityContext.getAuthentication()) {
                loggedInUserId = ((LoggedInUser) securityContext.getAuthentication().getPrincipal()).getUserId();
            }
        } catch (Exception e) {
            loggedInUserId = -1;
        }
        return loggedInUserId;
    }

    public List<java.lang.Long> getServiceAreaIdsList() {
        List<java.lang.Long> serviceAreaIds = new ArrayList<>();
        try {
            SecurityContext securityContext = SecurityContextHolder.getContext();
            if (null != securityContext.getAuthentication()) {
                serviceAreaIds = ((LoggedInUser) securityContext.getAuthentication().getPrincipal()).getServiceAreaIdList().stream().map(Long::valueOf).collect(Collectors.toList());
            }
        } catch (Exception e) {
            serviceAreaIds = new ArrayList<>();
        }
        return serviceAreaIds;
    }

    public LocalDate getNextBillDate(Customers customer) {
        LocalDate nextBillDate = null;
        LocalDate minNextBillDate = LocalDate.now().plusDays(400);
        if (customer != null && customer.getPlanMappingList() != null && customer.getPlanMappingList().size() > 0) {
            for (int i = 0; i < customer.getPlanMappingList().size(); i++) {
                PostpaidPlan plan = planService.get(customer.getPlanMappingList().get(i).getPlanId(),customer.getMvnoId());
                LocalDate today = LocalDate.now();
                int billingCycle = plan.getChargeList().get(0).getBillingCycle();
                int billDay = customer.getBillday();
                if (today.getDayOfMonth() < billDay && billingCycle == 1) {
                    nextBillDate = today.withDayOfMonth(billDay);
                    if (nextBillDate.isBefore(minNextBillDate)) minNextBillDate = nextBillDate;
                } else if (plan != null && plan.getChargeList() != null && plan.getChargeList().size() > 0) {
                    for (int j = 0; j < plan.getChargeList().size(); j++) {
                        if (plan.getChargeList().get(j).getCharge().getChargetype().equals(CommonConstants.CHARGE_TYPE_RECURRING) || plan.getChargeList().get(j).getCharge().getChargetype().equals(CommonConstants.CHARGE_TYPE_ADVANCE)) {
                            nextBillDate = LocalDate.now().plusMonths(plan.getChargeList().get(j).getBillingCycle()).withDayOfMonth(customer.getBillday());
                            if (nextBillDate.isBefore(minNextBillDate)) minNextBillDate = nextBillDate;
                        }
                        if (plan.getChargeList().get(j).getCharge().getChargetype().equals(CommonConstants.CHARGE_TYPE_NONRECURRING)) {
                            nextBillDate = LocalDate.now().plusMonths(plan.getChargeList().get(j).getBillingCycle()).withDayOfMonth(customer.getBillday());
                            if (nextBillDate.isBefore(minNextBillDate)) minNextBillDate = nextBillDate;
                        }
                    }
                } else ApplicationLogger.logger.info("Plan or plan charges are not available for Plan:" + plan);
            }
        } else ApplicationLogger.logger.info("Customer or mapping is null, NextBillDate Not set");
        ApplicationLogger.logger.info("Next Bill Date:" + nextBillDate);
        return minNextBillDate;
    }

