    public LocalDate getNextQuotaResetDate(Customers customer, LocalDate custNextBillDate) {
//        List<CustPlanMappping> custPlanMapppings = custPlanMappingRepository.findAllByCustomerId(customer.getId()).stream().sorted(Comparator.comparing(CustPlanMappping::getStartDate)).filter(planMappping -> planMappping.getPurchaseType().equalsIgnoreCase("New") && planMappping.getCustPlanStatus().equalsIgnoreCase("Active") && planMappping.getExpiryDate().isAfter(LocalDateTime.now())).collect(Collectors.toList());
        List<Object[]> custPlanMapppings = custPlanMappingRepository.findActiveNewPlansByCustomerId(customer.getId());
        LocalDate minQuotaResetDate = custNextBillDate;//LocalDate.now();
        if (customer.getCusttype().equalsIgnoreCase("Postpaid")) {
            if (!CollectionUtils.isEmpty(custPlanMapppings)) {
                for (Object[] custPlanMappping : custPlanMapppings) {
                    Integer planId = (custPlanMappping[1] != null) ? (Integer) custPlanMappping[1] : null;

                    if (planId != null) {
                        LocalDate quotaResetDate = calculateCustomerQuotaResetDate(custPlanMappping, custNextBillDate);
                        if (quotaResetDate.isBefore(minQuotaResetDate)) minQuotaResetDate = quotaResetDate;
                    }
                }
            }
            return minQuotaResetDate;
        } else {
            if (!CollectionUtils.isEmpty(custPlanMapppings)) {
                for (Object[] custPlanMappping : custPlanMapppings) {
                    Integer planId = (custPlanMappping[1] != null) ? (Integer) custPlanMappping[1] : null;

                    if (planId != null) {
                        LocalDate quotaResetDate = calculateCustomerQuotaResetDate(custPlanMappping, LocalDate.from((LocalDateTime) custPlanMappping[3]));
                        if (quotaResetDate.isBefore(minQuotaResetDate)) minQuotaResetDate = quotaResetDate;
                    }
                }
            }
            return minQuotaResetDate;

        }
    }

    public LocalDate getNextQuotaResetDate(String custtype, List<CustPlanMapppingPojo> custPlanMapppingPojoList, LocalDate custNextBillDate) {
        List<CustPlanMapppingPojo> custPlanMapppings = custPlanMapppingPojoList.stream().sorted(Comparator.comparing(CustPlanMapppingPojo::getStartDate)).filter(planMappping -> planMappping.getPurchaseType().equalsIgnoreCase("New") && planMappping.getCustPlanStatus().equalsIgnoreCase("Active") && planMappping.getExpiryDate().isAfter(LocalDateTime.now())).collect(Collectors.toList());

        LocalDate minQuotaResetDate = custNextBillDate;//LocalDate.now();
        if (custtype.equalsIgnoreCase("Postpaid")) {
            if (!CollectionUtils.isEmpty(custPlanMapppings)) {
                for (CustPlanMapppingPojo custPlanMappping : custPlanMapppings) {
                    LocalDate quotaResetDate = calculateCustomerQuotaResetDate(custPlanMappping, custNextBillDate);
                    if (quotaResetDate.isBefore(minQuotaResetDate)) minQuotaResetDate = quotaResetDate;
                }
            }
            return minQuotaResetDate;
        } else {
            if (!CollectionUtils.isEmpty(custPlanMapppings)) {
                for (CustPlanMapppingPojo custPlanMappping : custPlanMapppings) {
                    LocalDate quotaResetDate = calculateCustomerQuotaResetDate(custPlanMappping, custPlanMappping.getEndDate().toLocalDate());
                    if (quotaResetDate.isBefore(minQuotaResetDate)) minQuotaResetDate = quotaResetDate;
                }
            }
            return minQuotaResetDate;

        }
    }

    public LocalDate calculateCustomerQuotaResetDate(Object[] custPlanMappping, LocalDate endDate) {
        LocalDate nextBillDate = LocalDate.now();
        Integer planId = (Integer) custPlanMappping[1];
        LocalDateTime planStartDate = (LocalDateTime) custPlanMappping[2];
        LocalDateTime planExpireDate = (LocalDateTime) custPlanMappping[4];
        LocalDate startDate = planStartDate.toLocalDate();
        LocalDate expireDate = planExpireDate.toLocalDate();
//        PostpaidPlan plan = postpaidPlanRepo.getOne(planId);
        String quotaResetInterval = postpaidPlanRepo.findQuotaResetIntervalByPlanId(planId);
        LocalDate today = LocalDate.now();
        quotaResetInterval = quotaResetInterval.toLowerCase();
//        LocalDate startDate = custPlanMappping.getStartDate().toLocalDate();
        switch (quotaResetInterval) {
            case "daily":
                //add daily quota reset
                nextBillDate = startDate.plusDays(1);
                break;
            case "weekly":
                nextBillDate = startDate.plusWeeks(1);
                break;
            case "monthly":
                nextBillDate = startDate.plusMonths(1);
                break;
            default:
                nextBillDate = LocalDate.now().minusDays(1);
                break;
        }

        if (nextBillDate != null && nextBillDate.isAfter(endDate)) {
            nextBillDate = endDate;
        }
        return nextBillDate;
    }

    public LocalDate calculateCustomerQuotaResetDate(CustPlanMapppingPojo custPlanMappping, LocalDate endDate) {
        LocalDate nextBillDate = LocalDate.now();
//        PostpaidPlan plan = postpaidPlanRepo.getOne(custPlanMappping.getPlanId());
//        String quotaResetInterval = postpaidPlanRepo.findQuotaResetIntervalByPlanId(custPlanMappping.getPlanId());
        String quotaResetInterval = postpaidPlanService.getQuotaResetInterval(custPlanMappping.getPlanId());
        // for vas plan unlimited quota
        if(custPlanMappping.getPlanId() == null && custPlanMappping.getVasId() != null){
            quotaResetInterval = "total";
        }
        LocalDate today = LocalDate.now();
//        String quotaResetInterval = plan.getQuotaResetInterval().toLowerCase();
        LocalDate startDate = custPlanMappping.getStartDate().toLocalDate();
        switch (quotaResetInterval.toLowerCase()) {
            case "daily":
                //add daily quota reset
                if (startDate.isEqual(today) || startDate.isAfter(today)) {
                    nextBillDate = today;
                } else {
                    nextBillDate = startDate.plusDays(1);
                }
                break;
            case "weekly":
                nextBillDate = startDate.plusWeeks(1);
                break;
            case "monthly":
                nextBillDate = startDate.plusMonths(1);
                break;
            default:
                nextBillDate = LocalDate.now().minusDays(1);
                break;
        }

        if (nextBillDate != null && nextBillDate.isAfter(endDate)) {
            nextBillDate = endDate;
        }
        return nextBillDate;
    }

    public NextBillDatinfo getNextBillDateChargeType(Customers customer) {
        LocalDate nextBillDate = null;
        LocalDate minNextBillDate = LocalDate.now().plusDays(400);
        String chargeType = null;
        if (customer != null && customer.getPlanMappingList() != null && customer.getPlanMappingList().size() > 0) {
            for (int i = 0; i < customer.getPlanMappingList().size(); i++) {
                PostpaidPlan plan = planService.get(customer.getPlanMappingList().get(i).getPlanId(),customer.getMvnoId());
                LocalDate today = LocalDate.now();
                int billingCycle = plan.getChargeList().get(0).getBillingCycle();
                int billDay = customer.getBillday();
                if (today.getDayOfMonth() < billDay && billingCycle == 1) {
                    nextBillDate = today.withDayOfMonth(billDay);
                    if (nextBillDate.isBefore(minNextBillDate)) minNextBillDate = nextBillDate;
                } else if (plan != null && plan.getChargeList() != null && plan.getChargeList().size() > 0) {
                    for (int j = 0; j < plan.getChargeList().size(); j++) {
                        if (plan.getChargeList().get(j).getCharge().getChargetype().equals(CommonConstants.CHARGE_TYPE_RECURRING) || plan.getChargeList().get(j).getCharge().getChargetype().equals(CommonConstants.CHARGE_TYPE_ADVANCE)) {
                            nextBillDate = LocalDate.now().plusMonths(plan.getChargeList().get(j).getBillingCycle()).withDayOfMonth(customer.getBillday());
                            if (nextBillDate.isBefore(minNextBillDate)) {
                                minNextBillDate = nextBillDate;
                                chargeType = plan.getChargeList().get(j).getCharge().getChargetype();
                            }
                        }
                        if (plan.getChargeList().get(j).getCharge().getChargetype().equals(CommonConstants.CHARGE_TYPE_NONRECURRING)) {
                            nextBillDate = LocalDate.now().plusMonths(plan.getChargeList().get(j).getBillingCycle()).withDayOfMonth(customer.getBillday());
                            if (nextBillDate.isBefore(minNextBillDate)) minNextBillDate = nextBillDate;
                        }
                    }
                } else ApplicationLogger.logger.info("Plan or plan charges are not available for Plan:" + plan);
            }
        } else ApplicationLogger.logger.info("Customer or mapping is null, NextBillDate Not set");
        ApplicationLogger.logger.info("Next Bill Date:" + nextBillDate);
        log.debug("Minimum Next bill Date for: " + customer.getUsername() + " is: " + minNextBillDate);
        return new NextBillDatinfo(minNextBillDate, chargeType);
    }

