    public Map<String, Long> networkDetailsFileBulkupload(MultipartFile networkDetailsFile) throws IOException {
        Map<String, Long> result = new HashMap<String, Long>();
        // try {
        Path resolve = validateFile(networkDetailsFile);
        Files.copy(networkDetailsFile.getInputStream(), resolve);
        final String SAMPLE_CSV_FILE = "./networkdetailscsvissue.csv";
        try (Reader reader = Files.newBufferedReader(Paths.get(resolve.toString())); CSVParser csvParser = new CSVParser(reader, CSVFormat.EXCEL.withHeader("no", "username", "servicearea", "olt", "slot", "port").withIgnoreHeaderCase().withSkipHeaderRecord().withTrim()); BufferedWriter writer = Files.newBufferedWriter(Paths.get(SAMPLE_CSV_FILE)); CSVPrinter csvPrinter = new CSVPrinter(writer, CSVFormat.DEFAULT.withHeader("line", "missing"))) {
            long line = 0;
            String missing = "";
            long successCount = 0;
            long failCount = 0;
            for (CSVRecord csvRecord : csvParser) {

                String no = csvRecord.get("no");
                String username = csvRecord.get("username");
                String servicearea = csvRecord.get("servicearea");
                String olt = csvRecord.get("olt");
                String slot = csvRecord.get("slot");
                String port = csvRecord.get("port");

                if (!isNullOrEmpty(no) && !isNullOrEmpty(username) && !isNullOrEmpty(servicearea) && !isNullOrEmpty(olt) && !isNullOrEmpty(slot) && !isNullOrEmpty(port)) {
                    NetworkDeviceDetailsBulkPojo networkDevice = new NetworkDeviceDetailsBulkPojo();
                    networkDevice.setNo(no);
                    networkDevice.setUsername(username);
                    networkDevice.setServicearea(servicearea);
                    networkDevice.setOlt(olt);
                    networkDevice.setSlot(slot);
                    networkDevice.setPort(port);

                    Customers customer = customersRepository.findByUserName(username);

                    NetworkDevices networkDevices = networkDeviceService.findByNameAndDeviceType(networkDevice.getOlt(), "OLT");
                    if (networkDevices != null) {
                        ServiceArea serviceArea = networkDevices.getServicearea();
                        if (networkDevices.getOltslotsList() != null && networkDevices.getOltslotsList().size() > 0) {
                            List<Oltslots> oltslotsList = networkDevices.getOltslotsList().stream().filter(dto -> null != dto.getName() && dto.getName().equalsIgnoreCase(networkDevice.getSlot())).collect(Collectors.toList());
                            if (oltslotsList != null && oltslotsList.size() > 0) {
                                Oltslots oltslots = oltslotsList.get(0);
                                List<OLTPortDetails> oltPortDetailsList = oltslots.getOltPortDetailsList().stream().filter(dto -> null != dto.getName() && dto.getName().equalsIgnoreCase(networkDevice.getPort())).collect(Collectors.toList());
                                if (oltPortDetailsList != null) {
                                    OLTPortDetails oltPortDetails = oltPortDetailsList.get(0);
                                    customer.setServicearea(serviceArea);
                                    customer.setOltslotid(oltslots.getId());
                                    customer.setOltportid(oltPortDetails.getId());
                                    customer.setAadhar(updatedAadhar(customer.getId(), customer.getAadhar()));
                                    customer.setPan(updatedPan(customer.getId(), customer.getPan()));
                                    customer.setGst(updatedGst(customer.getId(), customer.getGst()));
                                    customersRepository.save(customer);
                                } else {
                                    throw new CustomValidationException(APIConstants.FAIL, "OLT port is not match!", null);
                                }
                            } else {
                                throw new CustomValidationException(APIConstants.FAIL, "OLT slot is not match!", null);
                            }
                        } else {
                            throw new CustomValidationException(APIConstants.FAIL, "OLT slot list is not found by given OLT!", null);
                        }
                    }
                    successCount++;
                } else {
                    failCount++;
                    if (isNullOrEmpty(no)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "no value is missing,";
                    }
                    if (isNullOrEmpty(username)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "username value is missing,";
                    }
                    if (isNullOrEmpty(servicearea)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "servicearea value is missing,";
                    }
                    if (isNullOrEmpty(olt)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "olt value is missing,";
                    }
                    if (isNullOrEmpty(slot)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "slot value is missing,";
                    }
                    if (isNullOrEmpty(port)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "port value is missing,";
                    }
                    csvPrinter.printRecord(line, missing);
                    line = 0;
                    missing = "";
                    csvPrinter.flush();
                }
            }
            result.put("successCount", successCount);
            result.put("failCount", failCount);
        }
        return result;
    }

