    public Path validateFile(MultipartFile file) {
        bulkcsv = clientServiceSrv.getClientSrvByName(ClientServiceConstant.BULKCSV_PATH).get(0).getValue();
        File directory = new File(bulkcsv);
        if (!directory.exists()) {
            directory.mkdir();
        }
        Path root = Paths.get(bulkcsv);
        Path resolve = root.resolve(file.getOriginalFilename());
        if (resolve.toFile().exists()) {
            throw new CustomValidationException(APIConstants.FAIL, "File already exists: " + file.getOriginalFilename(), null);
        }
        return resolve;
    }

    public List<AuditForResponseModel> getCustomerListForAuditFor() {
        String SUBMODULE = MODULE + " [getCustomerListForAuditFor()] ";
        List<AuditForResponseModel> responseList = new ArrayList<>();
        try {
            List<Customers> customersList = getAllCustomers();
            if (null != customersList && 0 < customersList.size()) {
                for (Customers customers : customersList) {
                    AuditForResponseModel responseModel = new AuditForResponseModel();
                    responseModel.setId(customers.getId());
                    responseModel.setName(customers.getFullName());
                    responseList.add(responseModel);
                }
            }
        } catch (Exception ex) {
            ApplicationLogger.logger.error("Unable to get customer list for Audit response{};exception{}", APIConstants.FAIL, ex.getStackTrace());
            throw ex;
        }
        return responseList;
    }

