    public List<CustomersBasicDetailsPojo> findCustomerByPartner(Integer partner, String s) {
        String SUBMODULE = MODULE + " [findCustomerByPartner] ";
        try {
            QCustomers qCustomers = QCustomers.customers;
            BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false)).and(qCustomers.servicearea.id.in(super.getServiceAreaIdList())).and(qCustomers.partner.id.eq(partner));
            // TODO: pass mvnoID manually 6/5/2025
            if (getMvnoIdFromCurrentStaff(null) != 1)
                // TODO: pass mvnoID manually 6/5/2025
                booleanExpression = booleanExpression.and(qCustomers.mvnoId.in(getMvnoIdFromCurrentStaff(null), 1));
            if (!s.isEmpty()) {
                booleanExpression = booleanExpression.and((qCustomers.username.contains(s).or(qCustomers.mobile.contains(s).or(qCustomers.firstname.contains(s)))));
            }
            if (getBUIdsFromCurrentStaff().size() != 0)
                // TODO: pass mvnoID manually 6/5/2025
                booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(null)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
            List<Customers> customersList = IterableUtils.toList(customersRepository.findAll(booleanExpression));
            if (null != customersList && 0 < customersList.size()) {
                return customersList.stream().map(data -> {
                    try {
                        return subscriberMapper.domainToDTO(data, new CycleAvoidingMappingContext());
                    } catch (NoSuchFieldException e) {
                        e.printStackTrace();
                    }
                    return null;
                }).collect(Collectors.toList());
            }
        } catch (Exception e) {
            ApplicationLogger.logger.error("Unable to find customer by partner response{};exception{}", APIConstants.FAIL, e.getStackTrace());
            throw e;
        }
        return new ArrayList<>();
    }

