    public Map<String, Long> macResetBulkupload(MultipartFile networkDetailsFile) throws IOException {
        Map<String, Long> result = new HashMap<String, Long>();
        // try {
        Path resolve = validateFile(networkDetailsFile);
        Files.copy(networkDetailsFile.getInputStream(), resolve);
        final String SAMPLE_CSV_FILE = "./macResetdetailscsvissue.csv";
        try (Reader reader = Files.newBufferedReader(Paths.get(resolve.toString())); CSVParser csvParser = new CSVParser(reader, CSVFormat.EXCEL.withHeader("no", "username").withIgnoreHeaderCase().withSkipHeaderRecord().withTrim()); BufferedWriter writer = Files.newBufferedWriter(Paths.get(SAMPLE_CSV_FILE)); CSVPrinter csvPrinter = new CSVPrinter(writer, CSVFormat.DEFAULT.withHeader("line", "missing"))) {
            long line = 0;
            String missing = "";
            long successCount = 0;
            long failCount = 0;
            for (CSVRecord csvRecord : csvParser) {

                String no = csvRecord.get("no");
                String username = csvRecord.get("username");

                if (!isNullOrEmpty(no) && !isNullOrEmpty(username)) {
                    Customers customer = customersRepository.findByUserName(username);
                    if (customer != null) {
                        try {
                            subscriberService.resetMacDetails(customer.getId(), "");
                        } catch (Exception e) {
                            e.printStackTrace();
                        }
                    } else {
                        throw new CustomValidationException(APIConstants.FAIL, "Customer is not found by username!", null);
                    }
                    successCount++;
                } else {
                    failCount++;
                    if (isNullOrEmpty(no)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "no value is missing,";
                    }
                    if (isNullOrEmpty(username)) {
                        line = csvParser.getCurrentLineNumber();
                        missing = missing + "username value is missing,";
                    }
                    csvPrinter.printRecord(line, missing);
                    line = 0;
                    missing = "";
                    csvPrinter.flush();
                }
            }
            result.put("successCount", successCount);
            result.put("failCount", failCount);
        }
        return result;
    }

