    @Transactional
    public String bindNetworkDevices(Integer customerId, Long networkDeviceId) throws Exception {
        String SUBMODULE = MODULE + " [bindNetworkDevices()] ";
        try {
            Customers customers = getEntityForUpdateAndDelete(customerId,getMvnoIdFromCurrentStaff(customerId));
            NetworkDeviceDTO oldNetworkDeviceDTO = null;

            // Release port from old Network Device
            if (customers.getNetworkdevices() != null) {
                oldNetworkDeviceDTO = networkDeviceService.getEntityById(customers.getNetworkdevices().getId(),customers.getMvnoId());
                oldNetworkDeviceDTO.setAvailableOutPorts((oldNetworkDeviceDTO.getAvailableOutPorts() == null) || (oldNetworkDeviceDTO.getAvailableOutPorts() == -1) ? -1 : (oldNetworkDeviceDTO.getAvailableOutPorts() + 1));
                networkDeviceService.updateEntity(oldNetworkDeviceDTO);
            }

            // Add port in new Network Device
            NetworkDeviceDTO newNetworkDeviceDTO = networkDeviceService.getEntityById(networkDeviceId,customers.getMvnoId());
            if (newNetworkDeviceDTO != null) {
                if (newNetworkDeviceDTO.getAvailableOutPorts() == 0)
                    throw new CustomValidationException(HttpStatus.NOT_ACCEPTABLE.value(), newNetworkDeviceDTO.getId() + "-" + newNetworkDeviceDTO.getName() + MessageConstants.PORTS_UNAVAILABLE, null);
                newNetworkDeviceDTO.setAvailableOutPorts((newNetworkDeviceDTO.getAvailableOutPorts() == null) || (newNetworkDeviceDTO.getAvailableOutPorts() == -1) ? -1 : (newNetworkDeviceDTO.getAvailableOutPorts() - 1));
                networkDeviceService.updateEntity(newNetworkDeviceDTO);
            }
            NetworkDevices networkDevices = networkDeviceMapper.dtoToDomain(newNetworkDeviceDTO, new CycleAvoidingMappingContext());

            customers.setNetworkdevices(networkDevices);
            customers.setAadhar(updatedAadhar(customers.getId(), customers.getAadhar()));
            customers.setPan(updatedPan(customers.getId(), customers.getPan()));
            customers.setGst(updatedGst(customers.getId(), customers.getGst()));
            update(customers);
            return "Success : Network device bound with customer";
        } catch (Exception ex) {
            ApplicationLogger.logger.error("Unable to bind Networkdevice for customer response{};exception{}", APIConstants.FAIL, ex.getStackTrace());
            throw new CustomValidationException(APIConstants.FAIL, ex.getMessage(), null);
        }
    }

    public String getPaymentUrl(Long orderId, Double txnAmount, Customers customer) throws Exception {
        try {
            TreeMap<String, String> parameters = new TreeMap<>();
            parameters.put("CHANNEL_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_CHANNEL_ID,customer.getMvnoId()));
            parameters.put("INDUSTRY_TYPE_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_INDUSTRY_TYPE_ID,customer.getMvnoId()));
            parameters.put("MID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_ID,customer.getMvnoId()));
            parameters.put("WEBSITE", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_WEBSITE,customer.getMvnoId()));
            parameters.put("CALLBACK_URL", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_CALLBACK_URL,customer.getMvnoId()));

            if (customer != null) parameters.put("EMAIL", customer.getEmail());
            parameters.put("MOBILE_NO", customer.getMobile());
            parameters.put("ORDER_ID", orderId.toString());
            parameters.put("TXN_AMOUNT", txnAmount.toString());
            parameters.put("CUST_ID", customer.getId().toString());
            String checkSum = getCheckSum(parameters,customer.getMvnoId());
            parameters.put("CHECKSUMHASH", checkSum);

            HttpUriRequest httpGetForAccessToken = RequestBuilder.get().setUri(new URI(clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_URL,customer.getMvnoId()))).addParameter("CHANNEL_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_CHANNEL_ID,customer.getMvnoId())).addParameter("CHECKSUMHASH", checkSum).addParameter("ORDER_ID", orderId.toString()).addParameter("TXN_AMOUNT", txnAmount.toString()).addParameter("CUST_ID", customer.getId().toString()).addParameter("INDUSTRY_TYPE_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_INDUSTRY_TYPE_ID)).addParameter("CHANNEL_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_CHANNEL_ID)).addParameter("MID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_ID)).addParameter("MOBILE_NO", customer.getMobile()).addParameter("EMAIL", (customer != null) ? customer.getEmail() : "").addParameter("WEBSITE", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_WEBSITE)).addParameter("CALLBACK_URL", clientServiceSrv.getByName("paymentIpAddress").getValue() + ":30085/paytm/pgresponse").build();
            return httpGetForAccessToken.getURI().toString();
        } catch (Exception e) {
            ApplicationLogger.logger.error("Unable to get payment url: response{};exception{}", APIConstants.FAIL, e.getStackTrace());
            //  e.printStackTrace();
            return null;
        }
    }

    private String getCheckSum(TreeMap<String, String> parameters, Integer mvnoId) throws Exception {
        return PaytmChecksum.generateSignature(parameters, clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_KEY,mvnoId));
    }

    public String getLink(Long orderId, Double txtAmount, Customers customers) throws Exception {
        HashMap<String, String> map = new HashMap<>();
        //DateTimeFormatter format = DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm:ss");
        JSONObject paytmParams = new JSONObject();
        JSONObject body = new JSONObject();
        JSONObject head = new JSONObject();
        JSONObject contact = new JSONObject();

        contact.put("customerMobile", customers.getMobile());
        //contact.put("customerEmail",customers.getEmail());
        contact.put("customerName", customers.getCustname());

        body.put("mid", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_ID,customers.getMvnoId()));
        body.put("linkType", "FIXED");
        body.put("linkDescription", "Payment for Adopt");
        body.put("linkName", "adopt");
        body.put("amount", txtAmount);
        body.put("sendSms", true);
        //body.put("sendEmail",true);
        //body.put("expiryDate",LocalDateTime.now().plusMinutes(expiryTime).format(format));
        body.put("customerContact", contact);
        body.put("bindLinkIdMobile", true);
        body.put("statusCallbackUrl", clientServiceSrv.getByName("callbackLinkUrl").getValue());

        String checksum = PaytmChecksum.generateSignature(body.toString(), clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_KEY,customers.getMvnoId()));

        head.put("tokenType", "AES");
        head.put("signature", checksum);
        paytmParams.put("body", body);
        paytmParams.put("head", head);
        String post_data = paytmParams.toString();
        URL url = new URL(clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_LINK_URL,customers.getMvnoId()));
        String linkId = null;
        try {
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("POST");
            connection.setRequestProperty("Content-Type", "application/json");
            connection.setDoOutput(true);
            DataOutputStream requestWriter = new DataOutputStream(connection.getOutputStream());
            requestWriter.writeBytes(post_data);
            requestWriter.close();
            String responseData = "";
            InputStream is = connection.getInputStream();
            BufferedReader responseReader = new BufferedReader(new InputStreamReader(is));
            if ((responseData = responseReader.readLine()) != null) {
                JSONObject object = new JSONObject(responseData);
                if (object.getJSONObject("body").getJSONObject("resultInfo").get("resultCode").equals("200")) {
                    linkId = object.getJSONObject("body").get("linkId").toString();
                    updatePaymentLinkAndAmount(orderId, linkId, txtAmount);
                }
            }
            responseReader.close();
        } catch (Exception exception) {
            return linkId;
        }
        //sending message to notification
        //sendCustPaymentLinkMessage(customers.getFullName(),txtAmount,linkId,customers.getMvnoId(), customers.getMobile(),customers.getEmail());
        return linkId;


    }

    public String reSendLink(String linkId, Customers customers) {
        JSONObject paytmParams = new JSONObject();
        JSONObject body = new JSONObject();
        body.put("mid", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_ID));
        body.put("linkId", linkId);
        body.put("sendSms", "true");
        JSONObject notifyContact = new JSONObject();
        notifyContact.put("customerMobile", customers.getMobile());
        notifyContact.put("customerName", customers.getCustname());
        body.put("notifyContact", notifyContact);
        String checksum = null;
        try {
            checksum = PaytmChecksum.generateSignature(body.toString(), clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_KEY,customers.getMvnoId()));
        } catch (Exception e) {
            ApplicationLogger.logger.error("Unable to Sed link response{};exception{}", APIConstants.FAIL, e.getStackTrace());
            //  e.printStackTrace();
        }
        JSONObject head = new JSONObject();
        head.put("tokenType", "AES");
        head.put("signature", checksum);
        paytmParams.put("body", body);
        paytmParams.put("head", head);
        String post_data = paytmParams.toString();
        URL url = null;
        try {
            url = new URL("https://securegw.paytm.in/link/resendNotification");
        } catch (MalformedURLException e) {
            ApplicationLogger.logger.error("Unable to Sed link response{};exception{}", APIConstants.FAIL, e.getStackTrace());
            // e.printStackTrace();
        }
        try {
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("POST");
            connection.setRequestProperty("Content-Type", "application/json");
            connection.setDoOutput(true);

            DataOutputStream requestWriter = new DataOutputStream(connection.getOutputStream());
            requestWriter.writeBytes(post_data);
            requestWriter.close();
            String responseData = "";
            InputStream is = connection.getInputStream();
            BufferedReader responseReader = new BufferedReader(new InputStreamReader(is));
            if ((responseData = responseReader.readLine()) != null) {
                JSONObject object = new JSONObject(responseData);
                if (object.getJSONObject("body").getJSONObject("resultInfo").get("resultCode").equals("200")) {
                    return "success";
                }
            }
            responseReader.close();
        } catch (Exception exception) {
            return "failed";
        }
        return "failed";
    }

