    private void updatePaymentLinkAndAmount(Long orderId, String linkId, Double amount) {
        Optional<CustomerPayment> customerPayment = customerPaymentRepository.findById(orderId);
        if (customerPayment.isPresent()) {
            CustomerPayment payment = customerPayment.get();
            payment.setLinkId(linkId);
            payment.setPayment(amount);
            customerPaymentRepository.save(payment);
        }
    }

    public void isMobileAlreadyExist(String mobileNumber) throws Exception {
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression expression = qCustomers.isNotNull();
        expression = expression.and(qCustomers.mobile.eq(mobileNumber)).and(qCustomers.isDeleted.eq(false));
        List<Customers> customers = (List<Customers>) customersRepository.findAll(expression);
        if (customers.size() > 0) throw new Exception("User exist with this same mobile number");
    }

    public void sendCustPaymentLinkMessage(String message, String customerName, Double paymentAmount, String url, Integer mvnoId, String countryCode, String mobileNumber, String emailId,Long staffId) {
        try {
            {
                String currencySymbol = RabbitMqConstants.CURRENCY_SYMBOLE;
                // if (!currencySymbol.isEmpty()) {
                Optional<TemplateNotification> optionalTemplate = templateRepository.findByTemplateName(RabbitMqConstants.CUSTOMER_PAYMENT_LINK);
                if (optionalTemplate.isPresent()) {
                    if (optionalTemplate.get().isSmsEventConfigured() || optionalTemplate.get().isEmailEventConfigured()) {
                        // Set message in queue to send notification after opt generated successfully.
                        Long buId = null;
                        if (getBUIdsFromCurrentStaff() != null && getBUIdsFromCurrentStaff().size() > 0) {
                            buId = getBUIdsFromCurrentStaff().get(0);
                        }
                        PaymentLinkMessage paymentLinkMessage = new PaymentLinkMessage(message, customerName, currencySymbol, paymentAmount, url, mvnoId, optionalTemplate.get(), RabbitMqConstants.SOURCE_NAME_ADOPT_BSS_GATEWAY, countryCode, mobileNumber, emailId, buId,staffId);
                        Gson gson = new Gson();
                        gson.toJson(paymentLinkMessage);
                        kafkaMessageSender.send(new KafkaMessageData(paymentLinkMessage, PaymentLinkMessage.class.getSimpleName()));
//                        messageSender.send(paymentLinkMessage, RabbitMqConstants.QUEUE_BSS_CUSTOMER_PAYMENT_LINK);
                    }
                }
                // }
            }
        } catch (Throwable e) {
            throw new RuntimeException(e.getMessage());
        }
    }

    public void sendCustPaymentSuccessMessage(String message, String customerName, Double paymentAmount, String paymentMode, Integer mvnoId, String countryCode, String mobileNumber, String emailId, Integer userId, String reciptNo, String paymentdate, Long buId, Integer planId,Long staffId,Integer id) {
        try {
            {
                String currencySymbol = RabbitMqConstants.CURRENCY_SYMBOLE;
                if (!currencySymbol.isEmpty()) {
                    Optional<TemplateNotification> optionalTemplate = templateRepository.findByTemplateName(RabbitMqConstants.CUSTOMER_PAYMENT_SUCCESS);
                    if (optionalTemplate.isPresent()) {
                        if (optionalTemplate.get().isSmsEventConfigured() || optionalTemplate.get().isEmailEventConfigured()) {
                            // Set message in queue to send notification after opt generated successfully.
                            String planName = "";
                            if (planId != null) {
                                Optional<PostpaidPlan> postpaidPlan = postpaidPlanRepo.findById(planId);
                                if (postpaidPlan.isPresent()) {
                                    planName = postpaidPlan.get().getName();
                                }
                            }
                            String password = "";
                            Optional<Customers> customers = customersRepository.findById(userId);
                            if (customers.isPresent()) {
                                password = customers.get().getPassword();
                            }

                            PaymentSuccess paymentSuccessMessage = new PaymentSuccess(message, customers.get().getUsername(), currencySymbol, paymentAmount, paymentMode, mvnoId, optionalTemplate.get(), RabbitMqConstants.SOURCE_NAME_ADOPT_BSS_GATEWAY, countryCode, mobileNumber, emailId, userId, reciptNo, paymentdate, buId, planName, password,staffId,customers.get(),id,customers.get().getCusttype());
                            Gson gson = new Gson();
                            gson.toJson(paymentSuccessMessage);
                            kafkaMessageSender.send(new KafkaMessageData(paymentSuccessMessage, PaymentSuccess.class.getSimpleName()));
//                            messageSender.send(paymentSuccessMessage, RabbitMqConstants.QUEUE_BSS_CUSTOMER_PAYMENT_SUCCESS);
                        }
                    }
                }
            }
        } catch (Throwable e) {
            ApplicationLogger.logger.error("Unable to Sed Payment response  response{};exception{}", APIConstants.FAIL, e.getStackTrace());
            throw new RuntimeException(e.getMessage());
        }
    }

