    @Override
    public Page<Customers> getList(Integer pageNumber, Integer customPageSize, String sortBy, Integer sortOrder, List<GenericSearchModel> filterList,Integer mvnoId) {
        Page<Customers> customers = null;
        PageRequest pageRequest = generatePageRequest(pageNumber, customPageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false).and(qCustomers.status.lower().notIn(CommonConstants.TERMINATED_STATUS)));
        if (getLoggedInUserId() != 1) {
            if (!super.getServiceAreaIdList().isEmpty())
                booleanExpression = booleanExpression.and(qCustomers.servicearea.id.in(super.getServiceAreaIdList()));
        }

        if (!getLoggedInUser().getLco()) booleanExpression = booleanExpression.and(qCustomers.lcoId.isNull());
        else booleanExpression = booleanExpression.and(qCustomers.lcoId.eq(getLoggedInUserPartnerId()));

        // TODO: pass mvnoID manually 6/5/2025
        if (getMvnoIdFromCurrentStaff(null) != 1)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.in(getMvnoIdFromCurrentStaff(null), 1));
        if (getBUIdsFromCurrentStaff().size() != 0)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(null)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        if (getLoggedInUserPartnerId() == CommonConstants.DEFAULT_PARTNER_ID) {
            customers = customersRepository.findAll(booleanExpression, pageRequest);
        } else {
            booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
            customers = customersRepository.findAll(booleanExpression, pageRequest);
        }
        return customers;
    }

    public String changeStatus(Integer customerId, String Status, HttpServletRequest request, String remark) {
        try {
            Optional<StaffUser> staffUser = staffUserRepository.findById(getLoggedInUserId());
            Customers customers = customersRepository.findById(customerId)
                    .orElseThrow(() -> new RuntimeException("No Customer Found With Id " + customerId));
            List<CreditDocument> creditDocuments = creditDocRepository.findAllByCustId(customerId);
            if (creditDocuments.size() > 0 && Status.equalsIgnoreCase("Terminate")) {
                Boolean paymentStatus = creditDocuments.stream().anyMatch(i -> i.getStatus().equalsIgnoreCase("pending"));
                if (paymentStatus) {
                    throw new CustomValidationException(HttpStatus.NOT_FOUND.value(), "Termination not allowed as Payment is Pending for Approval!", null);
                }
            }
            if (customers.getStatus().equalsIgnoreCase("Terminate")) {
                throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "Customer is Already terminated.", null);
            }
            List<CustomerApprove> customerApproves = customerApproveRepo.findAllByCustomerIDIsAndCurrentStaffIsNotNullAndParentStaffIsNotNullAndStatus(customers.getId(), "pending");
            List<CustomerApprove> customerApprove1 = customerApproveRepo.findAllByCustomerIDIsAndCurrentStaffIsNotNullAndStatusEquals(customers.getId(), "pending");
            if (customerApproves.size() > 0 || customerApprove1.size() > 0) {
                throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "Change status already in process.", null);
            }

            String msg = "";
            StaffUser assignedUser = null;
            Map<String, String> map = null;
            if (Status.equalsIgnoreCase("Terminate")) {
                CustomerApprove customerApprove = new CustomerApprove();
                map = hierarchyService.getTeamForNextApproveForAuto(customers.getMvnoId(), customers.getBuId(), CommonConstants.WORKFLOW_EVENT_NAME.TERMINATION, CommonConstants.HIERARCHY_TYPE, false, true, customerMapper.domainToDTO(customers, new CycleAvoidingMappingContext()));
                if (clientServiceSrv.getValueByName(ClientServiceConstant.WORKFLOW_AUTOMATIC_ASSIGN,customers.getMvnoId()).equals("TRUE")) {
                    int staffId = 0;
                    if (map.containsKey("staffId") && map.containsKey("nextTatMappingId")) {
                        staffId = Integer.parseInt(map.get("staffId"));
                        StaffUser staffUsers = staffUserService.get(staffId,customers.getMvnoId());
                        assignedUser = staffUsers;
                        customers.setNextTeamHierarchyMapping(Integer.valueOf(map.get("nextTatMappingId")));
                        CustomerCafAssignmentService customerCafAssignmentService = SpringContext.getBean(CustomerCafAssignmentService.class);
//                        if (customers != null) {
//                            customerCafAssignmentService.assignCustomerTerminate(customers, staffId);
//                        }
                        String action = CommonConstants.WORKFLOW_MSG_ACTION.CUSTOMER + " with name : " + " ' " + customers.getFullName() + " '";
                        hierarchyService.sendWorkflowAssignActionMessage(assignedUser.getCountryCode(), assignedUser.getPhone(), assignedUser.getEmail(), assignedUser.getMvnoId(), assignedUser.getFullName(), action,staffUser.get().getId().longValue());
                        workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.TERMINATION, customers.getId(), customers.getUsername(), staffUsers.getId(), staffUsers.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.ASSIGNED, LocalDateTime.now(), "Assigned to :- " + staffUsers.getUsername());
                        customerApprove.setCustomerID(customerId);
                        customerApprove.setStatus("pending");
                        customerApprove.setCurrentStatus(customers.getStatus());
                        customerApprove.setActiveStatus(SubscriberConstants.TERMINATE);
                        if (staffUsers.getStaffUserparent() != null) {
                            customerApprove.setParentStaff(staffUsers.getStaffUserparent().getFirstname());
                        } else {
                            customerApprove.setParentStaff(null);
                        }
                        customerApprove.setCurrentStaff(staffUser.get().getUsername());
                        customerApprove.setFirstName(staffUsers.getFirstname());
                        customerApprove.setLastName(staffUsers.getLastname());
                        customerApprove.setCustName(customers.getUsername());
                        customerApprove.setRemark(remark);

                    } else {
                        StaffUser currentStaff = staffUser.get();
                        assignedUser = currentStaff;
                        customers.setNextTeamHierarchyMapping(null);
//                        CustomerCafAssignmentService customerCafAssignmentService = SpringContext.getBean(CustomerCafAssignmentService.class);
//                        if (currentStaff != null) {
//                            customerCafAssignmentService.assignCustomerTerminate(customers, getLoggedInUserId());
//                        }
                        workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.TERMINATION, customers.getId(), customers.getUsername(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.ASSIGNED, LocalDateTime.now(), "Assigned to :- " + currentStaff.getUsername());
                        customerApprove.setCustomerID(customerId);
                        customerApprove.setStatus("pending");
                        customerApprove.setCurrentStatus(customers.getStatus());
                        customerApprove.setActiveStatus(SubscriberConstants.TERMINATE);
                        if (currentStaff.getStaffUserparent() != null) {
                            customerApprove.setParentStaff(currentStaff.getStaffUserparent().getFirstname());
                        } else {
                            customerApprove.setParentStaff(null);
                        }
                        customerApprove.setCurrentStaff(staffUser.get().getUsername());
                        customerApprove.setFirstName(currentStaff.getFirstname());
                        customerApprove.setLastName(currentStaff.getLastname());
                        customerApprove.setCustName(customers.getUsername());
                        customerApprove.setRemark(remark);
                    }
                    //TAT functionality
                    if (map.containsKey("nextTatMappingId")) {
                        if (assignedUser.getStaffUserparent() != null && !CollectionUtils.isEmpty(map)) {
                            if (map.get("current_tat_id") != null && map.get("current_tat_id") != "null")
                                map.put("tat_id", map.get("current_tat_id"));
                            tatUtils.saveOrUpdateDataForTatMatrix(map, assignedUser, customers.getId(), null);
                        }
                    }
                } else {
                    StaffUser currentStaff = staffUser.get();
                    assignedUser = currentStaff;
                    customers.setNextTeamHierarchyMapping(null);
                    HashMap<String, String> tatMapDetails = new HashMap<>();
                    if (!CollectionUtils.isEmpty(map) && !map.get("tat_id").equals("null")) {
                        Long tat_id = Long.valueOf(String.valueOf(map.get("tat_id")));
                        Optional<Matrix> matrix = matrixRepository.findById(tat_id);
                        Hierarchy hierarchy = null;
                        if (matrix.isPresent()) {
                            if (getBUIdsFromCurrentStaff() != null) {
                                hierarchy = hierarchyRepository.findByBuIdIsNullAndMvnoIdAndEventNameAndIsDeleted(customers.getMvnoId(), CommonConstants.WORKFLOW_EVENT_NAME.TERMINATION, false);
                            } else {
                                hierarchy = hierarchyRepository.findByMvnoIdAndBuIdInAndEventNameAndIsDeleted(customers.getMvnoId(), getBUIdsFromCurrentStaff(), CommonConstants.WORKFLOW_EVENT_NAME.TERMINATION, false);
                            }
                            if (hierarchy != null) {
                                if (matrix.isPresent()) {
                                    Matrix matrix1 = matrix.get();
                                    customers.setSlaUnit(matrix1.getRunit());
                                    long hours = 0;
                                    long minutes = 0;
                                    if (matrix1.getRunit().equalsIgnoreCase("MIN")) {
                                        minutes = matrix1.getRtime();
                                        // Get the current time
                                        LocalTime currentTime = LocalTime.now();
                                        // Calculate the next follow-up time
                                        LocalTime nextFollowupTime = currentTime.plusMinutes(minutes);
                                        // Check if the next follow-up time goes beyond the current day
                                        if (nextFollowupTime.getHour() < currentTime.getHour() || (nextFollowupTime.getHour() == currentTime.getHour() && nextFollowupTime.getMinute() < currentTime.getMinute())) {
                                            // If so, add one day to the next follow-up date
                                            LocalDate nextFollowupDate = LocalDate.now().plusDays(1);
                                            // Set the next follow-up date and time
                                            customers.setNextfollowupdate(nextFollowupDate);
                                            customers.setNextfollowuptime(nextFollowupTime);
                                        } else {
                                            // Set the next follow-up date to the current date
                                            customers.setNextfollowupdate(LocalDate.now());
                                            // Set the next follow-up time to the calculated time
                                            customers.setNextfollowuptime(nextFollowupTime);
                                        }
                                    } else if (matrix1.getRunit().equalsIgnoreCase("HOUR")) {
                                        hours = matrix1.getRtime();
                                        LocalTime currentTime = LocalTime.now();
                                        long total_hours = currentTime.getHour() + hours;
                                        if (total_hours >= 24) {
                                            long days = total_hours / 24;
                                            long remainingHours = total_hours % 24;
                                            long remainingMinutes = currentTime.getMinute();
                                            customers.setNextfollowupdate(LocalDate.now().plusDays(days));
                                            customers.setNextfollowuptime(LocalTime.of((int) remainingHours, (int) remainingMinutes));
                                        } else {
                                            customers.setNextfollowupdate(LocalDate.now());
                                            customers.setNextfollowuptime(currentTime.plusHours(hours));
                                        }
                                    } else {
                                        customers.setNextfollowupdate(LocalDate.now().plusDays(matrix1.getRtime()));
                                    }
                                    if (staffUser.get().getStaffUserparent() != null && !CollectionUtils.isEmpty(map)) {
                                        tatMapDetails.put("workFlowId", map.get("workFlowId"));
                                        tatMapDetails.put("eventId", map.get("eventId"));
                                        tatMapDetails.put("eventName", map.get("eventName"));
                                        tatMapDetails.put("tat_id", map.get("tat_id"));
                                        tatMapDetails.put("orderNo", map.get("orderNo"));

                                        TatMatrixWorkFlowDetails tatMatrixWorkFlowDetails = new TatMatrixWorkFlowDetails(Long.valueOf("1"), "Level 1", currentStaff.getId(), Long.valueOf(tatMapDetails.get("workFlowId")), Long.valueOf(tatMapDetails.get("tat_id")), (currentStaff != null && currentStaff.getStaffUserparent() != null) ? currentStaff.getStaffUserparent().getId() : null, LocalDateTime.now(), matrix1.getRtime().toString(), matrix1.getRunit(), "Notification", true, tatMapDetails.get("nextTatMappingId") != null ? Integer.valueOf(tatMapDetails.get("nextTatMappingId")) : null, customers.getId(), tatMapDetails.get("eventName"), tatMapDetails.get("eventId") != null ? Integer.valueOf(tatMapDetails.get("eventId")) : null, CommonConstants.NOTIFICATION_TYPE_STAFF, null, true);
//                                               tatUtils.saveOrUpdateDataForTatMatrix( tatMapDetails, staffUser.get(),subscriber.getId(),null);
                                        tatMatrixWorkFlowDetailsRepo.save(tatMatrixWorkFlowDetails);
                                        //tatUtils.saveOrUpdateDataForTatMatrix( tatMapDetails, staffUser.get(),customers.getId(),null);
                                    }

                                }
                            }
                        }

//                    CustomerCafAssignmentService customerCafAssignmentService = SpringContext.getBean(CustomerCafAssignmentService.class);
//                    if (currentStaff != null) {
//                        customerCafAssignmentService.assignCustomerTerminate(customers, getLoggedInUserId());
//                    }
                    }
                    workflowAuditService.saveAudit(null, CommonConstants.WORKFLOW_EVENT_NAME.TERMINATION, customers.getId(), customers.getUsername(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.ASSIGNED, LocalDateTime.now(), "Assigned to :- " + currentStaff.getUsername());
                    customerApprove.setCustomerID(customerId);
                    customerApprove.setStatus("pending");
                    customerApprove.setCurrentStatus(customers.getStatus());
                    customerApprove.setActiveStatus(SubscriberConstants.TERMINATE);
                    if (currentStaff.getStaffUserparent() != null) {
                        customerApprove.setParentStaff(currentStaff.getStaffUserparent().getFirstname());
                    } else {
                        customerApprove.setParentStaff(null);
                    }
                    customerApprove.setCurrentStaff(staffUser.get().getUsername());
                    customerApprove.setFirstName(currentStaff.getFirstname());
                    customerApprove.setLastName(currentStaff.getLastname());
                    customerApprove.setCustName(customers.getUsername());
                    customerApprove.setRemark(remark);
                }
                customerApproveRepo.save(customerApprove);
            }

//            if (Status.equals("Active")) {
//                msg = "Customer " + customers.getCustname() + " status has been changed.";
//                customers.setStatus(CommonConstants.CUSTOMER_STATUS.ACTIVE);
//            } else if (Status.equals("InActive")) {
//                msg = "Customer " + customers.getCustname() + " status has been changed.";
//                customers.setStatus(CommonConstants.CUSTOMER_STATUS.INAVCTIVE);
//            } else if (Status.equals("Terminate")) {
//                msg = "Customer " + customers.getCustname() + " status has been assing to approval to Process";
//            } else if (Status.equals("Suspend")) {
//                msg = "Customer " + customers.getCustname() + " status has been changed.";
//                customers.setStatus(CommonConstants.CUSTOMER_STATUS.SUSPEND);
//            } else {
//                msg = "Please enter valid Status :" + customers.getCustname();
//            }

            if (Status.equalsIgnoreCase("Terminate")) {
                msg = "Customer " + customers.getCustname() + " status has been assing to approval to Process";
            } else {
                msg = "Customer " + customers.getCustname() + " status has been changed.";
                custPlanMappingService.changeCustomerStatus(Collections.singletonList(customers), Status);
                List<CustomerServiceMapping> customerServiceMapping = customerServiceMappingRepository.findAllByCustId(customerId);
                for (CustomerServiceMapping serviceMapping : customerServiceMapping) {
                    if (serviceMapping.getUuid() != null) {
                        customersService.sendDeleteRequestForNMS(serviceMapping.getCustId(), serviceMapping.getId());
                    }
                }
            }

            customersRepository.save(customers);
            childCustomerimpl.changeStatusChildCustByParentID(customerId ,Status);
//            CustomMessage customMessage = new CustomMessage(customerMapper.domainToDTO(customers, new CycleAvoidingMappingContext()));
//            //messageSender.send(customMessage, RabbitMqConstants.QUEUE_APIGW_CUSTOMER);
//            kafkaMessageSender.send(new KafkaMessageData(customMessage,customMessage.getClass().getSimpleName(),"CUSTOMER_CREATE"));


            CustomerMessageKpi customerMessageKpi = new CustomerMessageKpi(customers);
            //messageSender.send(customerMessageKpi, RabbitMqConstants.QUEUE_APIGW_SEND_CUSTOMER_KPI);
            //Send customer status to radius
            CustomerUpdateMessage message = new CustomerUpdateMessage(customers);
            //messageSender.send(message, RabbitMqConstants.QUEUE_APIGW_CUSTOMER_STATUS_UPDATE_RADIUS);
            kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));

            if (customers.getStatus().equalsIgnoreCase("Active")) {
                if (Status.equalsIgnoreCase("Active")) {

                    LocalDateTime latestInvoiceEndDateTime = debitDocRepository.findLatestEndDateFromDetails(customers.getId());
                    boolean generateInvoice = true;
                    LocalDate startDate = LocalDate.now();
                    LocalDate endDate = startDate.with(TemporalAdjusters.lastDayOfMonth());
                    if (latestInvoiceEndDateTime != null) {
                        LocalDate lastInvoiceEndDate = latestInvoiceEndDateTime.toLocalDate();

                        if (startDate.getYear() == lastInvoiceEndDate.getYear() &&
                                startDate.getMonth() == lastInvoiceEndDate.getMonth()) {
                            logger.warn("Customer ID: {} reactivated in the SAME month ({}) as the last invoice period end date ({}). Skipping new invoice generation per business rule.",
                                    customers.getId(), startDate.getMonth(), lastInvoiceEndDate.getMonth());
                            generateInvoice = false;
                        }

                    }
                    if (generateInvoice){
                        CustomPeriodInvoiceDTO customPeriodInvoiceDTO = new CustomPeriodInvoiceDTO();
                        customPeriodInvoiceDTO.setCustomerId(customers.getId());
                        customPeriodInvoiceDTO.setCustomStartDate(startDate);
                        customPeriodInvoiceDTO.setCustomEndDate(endDate);
//                        kafkaMessageSender.sendRevenueInvoiceRequest(new KafkaMessageData(customPeriodInvoiceDTO, customPeriodInvoiceDTO.getClass().getSimpleName(), "GENERATE_CUSTOM_INVOICE"));

                    }
                }
                kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));
            }
            if (customers.getStatus().equalsIgnoreCase("Suspend"))
                kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));

            //Notification for customer status Inactive.
            if (customers.getStatus().equalsIgnoreCase("InActive")) {
                kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));
                sendCustStatusInActiveMessage(customers.getUsername(), customers.getMobile(), customers.getEmail(), customers.getStatus(), customers.getMvnoId(),staffUser.get().getId().longValue());
            }

            return msg;

        } catch (Throwable exception) {
            throw new CustomValidationException(APIConstants.INTERNAL_SERVER_ERROR, exception.getMessage(), null);
        }

    }


