    public HashMap<String, Object> validateCustomerLogin(CustomerLoginPojo pojo) {
        HashMap<String, Object> result = new HashMap<String, Object>();
        // TODO: pass mvnoID manually 6/5/2025
        Optional<Customers> custOpt = customersRepository.findByUsernameAndMvnoId(pojo.getUsername(), getMvnoIdFromCurrentStaff(null));
        if (!custOpt.isPresent()) {
            result.put("status", APIConstants.NOT_FOUND);
            result.put("message", "Invalid username!");
            return result;
        } else {
            result.put("status", APIConstants.SUCCESS);
            result.put("message", "Login success!");
        }
        Customers customer = custOpt.get();
        if (pojo.getPassword() != null) {
            if (!customer.getPassword().equals(pojo.getPassword())) {
                result.put("status", APIConstants.FAIL);
                result.put("message", "Invalid password!");
            }
        }

        //validate customer plan
        List<CustPlanMappping> planMapppingList = custPlanMappingRepository.findAllByCustomerId(customer.getId());
        if (CollectionUtils.isEmpty(planMapppingList)) {
            result.put("status", APIConstants.FAIL);
            result.put("message", "Quota not available for customer, Please contact admin!");
            return result;
        } else {
            if (!validateCustomerPlanAndQuota(planMapppingList)) {
                result.put("status", APIConstants.FAIL);
                result.put("message", "Quota not available for customer, Please contact admin!");
                return result;
            }
        }


        result.put("data", customerMapper.domainToDTO(customer, new CycleAvoidingMappingContext()));
        return result;
    }

    public boolean validateCustomerPlanAndQuota(List<CustPlanMappping> planMapppingList) {
        planMapppingList.sort(Comparator.comparing(CustPlanMappping::getExpiryDate));
        planMapppingList.removeIf(l -> !validateCustomerPlan(l));
        if (CollectionUtils.isEmpty(planMapppingList)) {
            return false;
        }
        HashSet<CustQuotaDetails> custQuotaDetails = new HashSet<CustQuotaDetails>();
        for (CustPlanMappping planM : planMapppingList) {
            List<CustQuotaDetails> quotaDetails = planM.getQuotaList();
            quotaDetails.removeIf(q -> !validateCustomerQuota(q));
            if (!CollectionUtils.isEmpty(quotaDetails)) {
                custQuotaDetails.addAll(quotaDetails);
            }
        }
        return !CollectionUtils.isEmpty(custQuotaDetails);
    }

    public boolean validateCustomerPlan(CustPlanMappping CustPlanMappping) {
        return !CustPlanMappping.getExpiryDate().isBefore(LocalDateTime.now()) || !CustPlanMappping.getIsDelete().equals(true) || !CustPlanMappping.getStartDate().isAfter(LocalDateTime.now());
    }

    public boolean validateCustomerQuota(CustQuotaDetails q) {

        if (q.getCustPlanMappping().equals(null)) return false;
        if (q.getIsDelete().equals(true)) return false;

        if (q.getQuotaType().equalsIgnoreCase(Constants.TIME)) {
            return !(q.getTimeTotalQuota() - q.getTimeQuotaUsed() <= 0);
        } else if (q.getQuotaType().equalsIgnoreCase(Constants.DATA)) {
            return !(q.getTotalQuota() - q.getUsedQuota() <= 0);
        } else if (q.getQuotaType().equalsIgnoreCase(Constants.BOTH)) {
            return !(q.getTotalQuota() - q.getUsedQuota() <= 0) && !(q.getTimeTotalQuota() - q.getTimeQuotaUsed() <= 0);
        }
        return true;
    }

    public List<Customers> getCustomersForDunning(String dunningType, String dunningSector, String dunningCategory, Integer dateDiff, String customerPayType, List<Long> branchIds, List<Long> partnerIds) {
        List<Customers> finalCustomerList = new ArrayList<>();
        List<Customers> customersListWithBranchPrepaid = new ArrayList<>();
        List<Customers> customersListWithBranchpostpaid = new ArrayList<>();
        List<Customers> customersListWithPartnerPrepaid = new ArrayList<>();
        List<Customers> customersListWithPartnerPostpaid = new ArrayList<>();
        if (!branchIds.isEmpty()) {
            if (customerPayType.equalsIgnoreCase("Prepaid")) {
                if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                    customersListWithBranchPrepaid = customersRepository.getCustomersForDunningPrepaid(dunningType, dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranchPrepaid = customersRepository.getCustomersForDunningSectorPrepaid(dunningSector, dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                    customersListWithBranchPrepaid = customersRepository.getCustomersForDunningPrepaid(dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranchPrepaid = customersRepository.getCustomersForDunningPrepaid(dunningType, dunningCategory, dunningSector, dateDiff, customerPayType, branchIds);
                }
            }
            if (customerPayType.equalsIgnoreCase("Postpaid")) {
                if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                    customersListWithBranchpostpaid = customersRepository.getCustomersForDunningPostpaid(dunningType, dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                     List<Object[]> rows= customersRepository.getCustomersForDunningSectorPostpaid(dunningSector, dunningCategory, dateDiff, customerPayType, branchIds);
                    customersListWithBranchpostpaid  = rows.stream()
                            .map(row -> new Customers(
                                    row[0] != null ? ((Number) row[0]).intValue() : null,    // custid
                                    (String) row[1],                                         // mobile
                                    (String) row[2],                                         // email
                                    (String) row[3],                                         // countryCode
                                    (String) row[4],                                         // username
                                    row[5] != null ? ((Number) row[5]).intValue() : null,    // mvnoId
                                    (String) row[6],                                         // status
                                    (String) row[7],                                         // custtype
                                    row[8] != null ? ((Number) row[8]).doubleValue() : null, // walletbalance
                                    row[9] != null ? ((Number) row[9]).longValue() : null,    // buId
                                    (String) row[10],
                                    (String) row[11],
                                    (String) row[12]
                            ))
                            .collect(Collectors.toList());
                    System.out.println("Total Size"+customersListWithBranchpostpaid.size());
                }
                if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                    customersListWithBranchpostpaid = customersRepository.getCustomersForDunningPostpaid(dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranchpostpaid = customersRepository.getCustomersForDunningPostpaid(dunningType, dunningCategory, dunningSector, dateDiff, customerPayType, branchIds);
                }
            }
        }

        if (!partnerIds.isEmpty()) {
            List<Integer> finalpartnerIds = partnerIds.stream().map(aLong -> aLong.intValue()).collect(Collectors.toList());
            if (customerPayType.equalsIgnoreCase("Prepaid")) {
                if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                    customersListWithPartnerPrepaid = customersRepository.getCustomersForDunningForPartnerPrepaid(dunningType, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
                }
                if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithPartnerPrepaid = customersRepository.getCustomersForDunningSectorForPartnerPrepaid(dunningSector, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
                }
                if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                    customersListWithPartnerPrepaid = customersRepository.getCustomersForDunningForPartnerPrepaid(dunningCategory, dateDiff, customerPayType, finalpartnerIds);
                }
                if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithPartnerPrepaid = customersRepository.getCustomersForDunningForPartnerPrepaid(dunningType, dunningCategory, dunningSector, dateDiff, customerPayType, finalpartnerIds);
                }
            }
            if (customerPayType.equalsIgnoreCase("Postpaid")) {
                if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                    customersListWithPartnerPostpaid = customersRepository.getCustomersForDunningForPartnerPostpaid(dunningType, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
                }
                if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithPartnerPostpaid = customersRepository.getCustomersForDunningSectorForPartnerPostpaid(dunningSector, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
                }
                if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                    customersListWithPartnerPostpaid = convertObjectToCustomer(customersRepository.getCustomersForDunningForPartnerPostpaid(dunningCategory, dateDiff, customerPayType, finalpartnerIds));
                }
                if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithPartnerPostpaid = customersRepository.getCustomersForDunningForPartnerPostpaid(dunningType, dunningCategory, dunningSector, dateDiff, customerPayType, finalpartnerIds);
                }
            }
        }
        finalCustomerList.addAll(customersListWithPartnerPostpaid);
        finalCustomerList.addAll(customersListWithPartnerPrepaid);
        finalCustomerList.addAll(customersListWithBranchPrepaid);
        finalCustomerList.addAll(customersListWithBranchpostpaid);
        return finalCustomerList;


    }

    public List<Customers> getAdvanceNotificationForDunning(String dunningType, String dunningSector, String dunningCategory, Integer dateDiff, String customerPayType, List<Long> branchIds, List<Long> partnerIds) {
        List<Customers> finalCustomerList = new ArrayList<>();
        List<Customers> customersListWithBranch = new ArrayList<>();
        List<Customers> customersListWithPartner = new ArrayList<>();
        if (!branchIds.isEmpty()) {
            if (customerPayType.equalsIgnoreCase("Postpaid")) {
                if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                    customersListWithBranch = customersRepository.getAdvanceNotificationForPostPaidDunning(dunningType, dateDiff, customerPayType, branchIds);
                }
                if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranch = convertObjectToCustomer(customersRepository.getAdvanceNotificationForPostPaidDunningDunningSector(dunningSector, dunningCategory, dateDiff, customerPayType, branchIds));
                }
                if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                    customersListWithBranch = convertObjectToCustomer(customersRepository.getAdvanceNotificationForPostPaidDunningNative(dunningCategory, dateDiff, customerPayType, branchIds));
                }
                if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranch = customersRepository.getAdvanceNotificationForPostPaidDunningDunningType(dunningType, dunningSector, dateDiff, customerPayType, branchIds);
                }
            } else {
                if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                    customersListWithBranch = customersRepository.getAdvanceNotificationForDunning(dunningType, dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranch = customersRepository.getAdvanceNotificationForDunningSector(dunningSector, dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                    customersListWithBranch = customersRepository.getAdvanceNotificationForDunning(dunningCategory, dateDiff, customerPayType, branchIds);
                }
                if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                    customersListWithBranch = customersRepository.getAdvanceNotificationForDunning(dunningType, dunningSector, dunningCategory, dateDiff, customerPayType, branchIds);
                }
            }
        }
        if (!partnerIds.isEmpty()) {
            List<Integer> finalpartnerIds = partnerIds.stream().map(aLong -> aLong.intValue()).collect(Collectors.toList());
            if (Objects.isNull(dunningSector) && Objects.nonNull(dunningType)) {
                customersListWithPartner = customersRepository.getAdvanceNotificationForDunningForPartner(dunningType, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
            }
            if (Objects.isNull(dunningType) && Objects.nonNull(dunningSector)) {
                customersListWithPartner = customersRepository.getAdvanceNotificationForDunningSectorForPartner(dunningSector, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
            }
            if (Objects.isNull(dunningType) && Objects.isNull(dunningSector)) {
                customersListWithPartner = customersRepository.getAdvanceNotificationForDunningForPartner(dunningCategory, dateDiff, customerPayType, finalpartnerIds);
            }
            if (Objects.nonNull(dunningType) && Objects.nonNull(dunningSector)) {
                customersListWithPartner = customersRepository.getAdvanceNotificationForDunningForPartner(dunningType, dunningSector, dunningCategory, dateDiff, customerPayType, finalpartnerIds);
            }
        }
        finalCustomerList.addAll(customersListWithPartner);
        finalCustomerList.addAll(customersListWithBranch);
        return finalCustomerList;


    }

