    public void addOrUpdateMacFromRadius(CustMacMessage message) {
        try {
            if (message.getUserName() != null && message.getUserName() != "null" && message.getMac() != null) {
                Customers customer = customersRepository.findByUserName(message.getUserName());
                Integer custsermappingid = null;
                if (message.getCustPlanMapId() != null) {
                    CustPlanMappping custPlanMappping = custPlanMappingRepository.findById(message.getCustPlanMapId());
                    if (custPlanMappping != null) {
                        custsermappingid = custPlanMappping.getCustServiceMappingId();
                    }
                }
                //update mac
                HashMap<String, Timestamp> mac = message.getMac();
                if (message.isUpdate()) {
                    logger.info("In Update mac from radius, user: " + message.getUserName());
                    for (Entry<String, Timestamp> entry : mac.entrySet()) {
                        //check old mac exists
                        List<CustMacMappping> optionalCustMacMappping = custMacMgmtService.getMacbyCustId(entry.getKey(), customer);
                        List<CustMacMappping> optionalCustMacMapppingForOldMac = null;
                        if (message.getOldMac() != null && message.getOldMac().length() > 0) {
                            optionalCustMacMapppingForOldMac = custMacMgmtService.getMacbyCustId(message.getOldMac(), customer);
                        }
                        if (optionalCustMacMappping != null) {
                            logger.info("In Update mac from radius, user: " + message.getUserName() + " mac: " + entry.getKey());
                            if (entry.getValue() != null) {
                                optionalCustMacMappping = optionalCustMacMappping.stream().peek(custMacMappping -> custMacMappping.setMacRetentionDate(Timestamp.valueOf(entry.getValue().toLocalDateTime()))).collect(Collectors.toList());
                            }
                            custMacMapppingRepository.saveAll(optionalCustMacMappping);
                        } else if (optionalCustMacMapppingForOldMac != null && !CollectionUtils.isEmpty(optionalCustMacMapppingForOldMac)) {
                            logger.info("In Update mac from radius, user: " + message.getUserName() + " mac: " + entry.getKey() + " old Mac: " + message.getOldMac());
                            if (entry.getValue() != null) {
                                optionalCustMacMapppingForOldMac = optionalCustMacMapppingForOldMac.stream().peek(custMacMappping -> {
                                    custMacMappping.setMacRetentionDate(Timestamp.valueOf(entry.getValue().toLocalDateTime()));
                                    custMacMappping.setMacAddress(entry.getKey());
                                }).collect(Collectors.toList());
                            }
                            custMacMapppingRepository.saveAll(optionalCustMacMapppingForOldMac);
                        } else {
                            saveNewMac(entry, customer, custsermappingid);
                        }
                    }

                } else {
                    //save mac
                    for (Entry<String, Timestamp> entry : mac.entrySet()) {
                        saveNewMac(entry, customer, custsermappingid);
                    }
                }
            }
        } catch (Exception ex) {
            ex.printStackTrace();
            logger.error("Error to save or update customer mac from radius user: " + message.getUserName() + " ex: " + ex.getMessage());
        }
    }

    public void saveNewMac(Entry<String, Timestamp> entry, Customers customer, Integer custsermappingid) {
        logger.info("Save new Mac user: " + customer.getUsername() + " ,mac: " + entry.getKey());
        CustMacMappping macMappping = new CustMacMappping();
        macMappping.setCustomer(customer);
        macMappping.setMacAddress(entry.getKey());
        macMappping.setIsDeleted(false);
        macMappping.setCreatedById(1);
        macMappping.setCreatedByName("Admin");
        if (entry.getValue() != null)
            macMappping.setMacRetentionDate(Timestamp.valueOf(entry.getValue().toLocalDateTime()));
        macMappping.setCreatedate(LocalDateTime.now());
        macMappping.setLastModifiedById(1);
        macMappping.setLastModifiedByName("Admin");
        macMappping.setUpdatedate(LocalDateTime.now());
        if (custsermappingid != null) macMappping.setCustsermappingid(custsermappingid);
        custMacMapppingRepository.save(macMappping);
    }

    public void addMacFromRadius(CustMacMessage message) {
        try {
            if (message.getUserName() != null && message.getUserName() != "null" && message.getMac() != null) {
                Customers customer = customersRepository.findByUserName(message.getUserName());
                Integer custsermappingid = null;
                if (message.getCustPlanMapId() != null) {
                    CustPlanMappping custPlanMappping = custPlanMappingRepository.findById(message.getCustPlanMapId());
                    if (custPlanMappping != null) {
                        custsermappingid = custPlanMappping.getCustServiceMappingId();
                    }
                }
                if (customer != null) {
                    List<CustMacMappping> macList = new ArrayList<CustMacMappping>();
                    HashMap<String, Timestamp> mac = message.getMac();
                    for (Entry<String, Timestamp> entry : mac.entrySet()) {
                        if (macList.stream().filter(m -> m.getMacAddress().equalsIgnoreCase(entry.getKey())).count() < 1) {

                            List<CustMacMappping> optionalCustMacMappping = custMacMgmtService.getMacbyCustId(entry.getKey(), customer);
                            if (!CollectionUtils.isEmpty(optionalCustMacMappping)) {
                                if (entry.getValue() != null) {
                                    optionalCustMacMappping.stream().peek(custMacMappping -> custMacMappping.setMacRetentionDate(Timestamp.valueOf(entry.getValue().toLocalDateTime()))).collect(Collectors.toList());
                                    custMacMapppingRepository.saveAll(optionalCustMacMappping);
                                }
                            } else {
                                CustMacMappping macMappping = new CustMacMappping();
                                macMappping.setCustomer(customer);
                                macMappping.setMacAddress(entry.getKey());
                                macMappping.setIsDeleted(false);
                                macMappping.setCreatedById(1);
                                macMappping.setCreatedByName("Admin");
                                if (entry.getValue() != null)
                                    macMappping.setMacRetentionDate(Timestamp.valueOf(entry.getValue().toLocalDateTime()));
                                macMappping.setCreatedate(LocalDateTime.now());
                                macMappping.setLastModifiedById(1);
                                macMappping.setLastModifiedByName("Admin");
                                macMappping.setUpdatedate(LocalDateTime.now());
                                if (custsermappingid != null) macMappping.setCustsermappingid(custsermappingid);

                                if (!message.isCheckConcurrency() || !custMacMgmtService.checkMaximumConcurrecyReached(customer, macMappping)) {
                                    custMacMapppingRepository.save(macMappping);
                                } else {
                                    List<CustMacMappping> custMacMapppings = custMacMapppingRepository.findAllByCustsermappingidAndIsDeletedFalse(custsermappingid);
                                    if (!CollectionUtils.isEmpty(custMacMapppings)) {
                                        CustMacMappping custMacMappping = custMacMapppings.get(0);
                                        custMacMappping.setMacAddress(entry.getKey());
                                        custMacMapppingRepository.save(custMacMappping);
                                    } else {
                                        logger.error("councurrency reached so not save or update new Mac from Radius: " + entry.getKey());
                                    }
                                }
                            }

                        }
                    }
//                    custMacMapppingService.deleteByCustomerId(customer.getId());
//                    custMacMapppingService.saveAll(macList);

                }
            }
        } catch (Exception e) {
            e.printStackTrace();
            logger.error("Unable to add MAC from radius : responce{};Exception:{}", APIConstants.ERROR_TAG, e.getStackTrace());
        }
    }

    public Page<SpecialCustomerDTO> getCustomersByServiceArea(Integer pageNumber, Integer customPageSize, String sortBy, Integer sortOrder, List<GenericSearchModel> filterList, Long serviceAreaId) {
        Page<Customers> customers = null;
        PageRequest pageRequest = generatePageRequest(pageNumber, customPageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false));
        booleanExpression = booleanExpression.and(qCustomers.servicearea.id.eq(serviceAreaId));
        List<SpecialCustomerDTO> specialCustomerDTOList = new ArrayList<>();

        if (getBUIdsFromCurrentStaff().size() != 0)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(null)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        customers = customersRepository.findAll(booleanExpression, pageRequest);
        if (customers.isEmpty()) {
            throw new RuntimeException("Customers not Found");
        }

//        List<SpecialCustomerDTO>specialCustomerDTOList =  new ArrayList<>();
        for (Customers customers1 : customers) {
            SpecialCustomerDTO specialCustomerDTO = new SpecialCustomerDTO();
            specialCustomerDTO.setFirstname(customers1.getFirstname());
            specialCustomerDTO.setId(customers1.getId());
            specialCustomerDTO.setUsername(customers1.getUsername());
            specialCustomerDTOList.add(specialCustomerDTO);
        }
        return new PageImpl<>(specialCustomerDTOList, pageRequest, customers.getTotalPages());
    }

    public List<ParentCustomerPojo> getParentCustomerList(String type) {
        List<ParentCustomerPojo> parentCustomerList = new ArrayList<>();
        try {
            List<Customers> customers = null;
            // TODO: pass mvnoID manually 6/5/2025
            if (getMvnoIdFromCurrentStaff(null) == 1) customersRepository.findParentCustomerList(type);
            else if (getBUIdsFromCurrentStaff().size() == 0)
                // TODO: pass mvnoID manually 6/5/2025
                customersRepository.findParentCustomerList(type, Arrays.asList(getMvnoIdFromCurrentStaff(null), 1));
            else
                // TODO: pass mvnoID manually 6/5/2025
                customersRepository.findParentCustomerList(type, getMvnoIdFromCurrentStaff(null), getBUIdsFromCurrentStaff());
            if (customers != null && customers.size() > 0) {
                customers.stream().forEach(x -> {
                    parentCustomerList.add(new ParentCustomerPojo(x.getId(), x.getFullName()));
                });
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return parentCustomerList;
    }

    public Page<Customers> getParentableList(Integer pageNumber, Integer customPageSize, String sortBy, Integer sortOrder, List<GenericSearchModel> filterList) {
        Page<Customers> customers = null;
        PageRequest pageRequest = generatePageRequest(pageNumber, customPageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false)).and(qCustomers.parentCustomers.id.isNull());
        if (getLoggedInUserId() != 1) {
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.servicearea.id.in(super.getServiceAreaIdList())).and(qCustomers.mvnoId.in(getMvnoIdFromCurrentStaff(null)));
        }
        if (getBUIdsFromCurrentStaff().size() != 0)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(null)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        if (getLoggedInUserPartnerId() == CommonConstants.DEFAULT_PARTNER_ID) {
            customers = customersRepository.findAll(booleanExpression, pageRequest);
        } else {
            booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
            customers = customersRepository.findAll(booleanExpression, pageRequest);
        }
        return customers;
    }

