    public void saveCustomerChargeHistory(PostpaidPlan plan, CustomersPojo customer, CustPlanMappping custPlanMappping, Integer plangroupId, Boolean isNewService, boolean changePlanDate, String purchaseType, CustPlanMapppingPojo planMapppingPojo) {
//        String cusotmerUsername = customersRepository.findCustomerName(customer.getId());
        String cusotmerUsername = customer.getUsername();
        log.debug("Initializing process for saving customer charge history for customer : " + cusotmerUsername);
        Integer minPlanGroupCycle = 1;
        if (plangroupId != null) {
            List<PostpaidPlanCharge> postpaidPlanCharges = new ArrayList<>();
            PlanGroup planGroup = planGroupService.get(plangroupId,customer.getMvnoId());
            planGroup.getPlanMappingList().stream().forEach(x -> {
                postpaidPlanCharges.addAll(x.getPlan().getChargeList());
            });

            minPlanGroupCycle = postpaidPlanCharges.stream().mapToInt(y -> y.getBillingCycle()).min().getAsInt();
        }
//        log.warn("PlangroupId is null while saving customer charge history for customer : " + cusotmerUsername);


        Integer finalMinPlanGroupCycle = minPlanGroupCycle;
        if(plan != null) {
            plan.getChargeList().forEach(postpaidPlanCharge -> {
                Charge charge = postpaidPlanCharge.getCharge();
                Integer count = debitDocRepository.getCount(charge.getId(), customer.getId());
                log.debug("total debitdoc count based on customer : " + cusotmerUsername);
                if (!(charge.getChargetype().equalsIgnoreCase(CommonConstants.CHARGE_TYPE_NONRECURRING) && count > 0) || ((charge.getChargetype().equalsIgnoreCase(CommonConstants.CHARGE_TYPE_NONRECURRING) && count > 0 && (isNewService || !isChargeAlreadyExistForCustId(charge.getId(), customer.getId())))) || purchaseType.equalsIgnoreCase("Addon")) {
                    Integer locationId = null;
                    if (!CollectionUtils.isEmpty(customer.getAddressList())) {
                        locationId = customer.getAddressList().stream().filter(data -> data.getAddressType().equalsIgnoreCase(SubscriberConstants.CUST_ADDRESS_PRESENT)).findFirst().orElse(null).getStateId();
                    }
                    TaxDetailCountReqDTO taxDetailCountReqDTO = new TaxDetailCountReqDTO(postpaidPlanCharge.getPlan().getId(), locationId, customer.getId(), postpaidPlanCharge.getCharge().getId());
                    try {
                        CustomerChargeHistory customerChargeHistory = new CustomerChargeHistory();
                        customerChargeHistory.setCustomerId(customer.getId());
                        customerChargeHistory.setChargeId(charge.getId());
                        customerChargeHistory.setTaxId(charge.getTax().getId());
                        customerChargeHistory.setTaxAmount(taxService.taxCalculationByCharge(taxDetailCountReqDTO, charge));
                        customerChargeHistory.setPlanId(plan.getId());
                        customerChargeHistory.setPlanName(plan.getName());
                        customerChargeHistory.setChargeType(charge.getChargetype());
                        customerChargeHistory.setCharge_desc(charge.getDesc());
                        customerChargeHistory.setBillingCycle(postpaidPlanCharge.getBillingCycle());
                        customerChargeHistory.setChargeName(charge.getName());
                        customerChargeHistory.setSaccode(charge.getSaccode());
                        customerChargeHistory.setIsFirstChargeApply(false);
                        if (charge.getRoyalty_payable() != null)
                            customerChargeHistory.setIsRoyaltyApply(charge.getRoyalty_payable());
                        else customerChargeHistory.setIsRoyaltyApply(false);
                        Optional<Integer> minCycle = null;
                        if (plan != null && plan.getChargeList() != null && plan.getChargeList().size() > 0) {
                            for (PostpaidPlanCharge pojo : plan.getChargeList()) {
                                if (pojo.getBillingCycle() != null)
                                    minCycle = Optional.ofNullable(plan.getChargeList().stream().mapToInt(x -> x.getBillingCycle()).min().getAsInt());
                            }
                        }
                        if (customer.getCusttype().equalsIgnoreCase("Postpaid")) {
                            if (customer.getParentCustomers() != null && customer.getInvoiceType().equalsIgnoreCase("Group")) {
                                Integer parentBillDay = customer.getParentCustomers().getBillday();
                                if (parentBillDay < customer.getBillday()) {
                                    if (plangroupId != null) {
                                        customerChargeHistory.setNextBillDate(LocalDate.now().plusMonths(finalMinPlanGroupCycle).withDayOfMonth(parentBillDay));
                                    } else {
                                        if (minCycle.isPresent())
                                            customerChargeHistory.setNextBillDate(LocalDate.now().plusMonths(minCycle.get()).withDayOfMonth(parentBillDay));
                                    }
                                    customerChargeHistory.setCustomerBillDay(parentBillDay);
                                } else {
                                    if (plangroupId != null) {
                                        customerChargeHistory.setNextBillDate(LocalDate.now().plusMonths(finalMinPlanGroupCycle).withDayOfMonth(customer.getBillday()));
                                    } else {
                                        if (minCycle.isPresent())
                                            customerChargeHistory.setNextBillDate(LocalDate.now().plusMonths(minCycle.get()).withDayOfMonth(customer.getBillday()));
                                    }
                                    customerChargeHistory.setCustomerBillDay(customer.getBillday());
                                }
                                customerChargeHistory.setLastBillDate(null);
                            } else {
                                if (plangroupId != null) {
                                    customerChargeHistory.setNextBillDate(LocalDate.now().plusMonths(finalMinPlanGroupCycle).withDayOfMonth(customer.getBillday()));
                                } else {
                                    if (minCycle.isPresent())
                                        customerChargeHistory.setNextBillDate(LocalDate.now().plusMonths(minCycle.get()).withDayOfMonth(Math.min(customer.getBillday(), LocalDate.now().plusMonths(minCycle.get()).lengthOfMonth())));
                                }
                                customerChargeHistory.setCustomerBillDay(customer.getBillday());
                                customerChargeHistory.setLastBillDate(null);
                            }

                            if (changePlanDate) {
                                customerChargeHistory.setLastBillDate(customerChargeHistory.getNextBillDate());
                            }
                        } else {
                            customerChargeHistory.setNextBillDate(null);
                            customerChargeHistory.setCustomerBillDay(null);
                            customerChargeHistory.setLastBillDate(null);
                        }
                        double discount = 0.0;
                        Double amount = taxService.getChargeAmount(charge.getId(), postpaidPlanCharge.getPlan().getId(), charge.getActualprice());
                        log.debug("Fetching charge amount : " + amount);
                        if (plangroupId != null) {
                            if (plan.getId() != null && plangroupId != null) {
                                QPlanGroupMapping qPlanGroupMapping = QPlanGroupMapping.planGroupMapping;
                                BooleanExpression exp = qPlanGroupMapping.isNotNull().and(qPlanGroupMapping.plan.id.eq(plan.getId())).and(qPlanGroupMapping.planGroup.planGroupId.eq(plangroupId));
                                List<PlanGroupMapping> planGroupMappingList = (List<PlanGroupMapping>) planGroupMappingRepository.findAll(exp);
                                if (planGroupMappingList.size() > 0) {
                                    List<Integer> planGroupMappingids = planGroupMappingList.stream().map(PlanGroupMapping::getPlanGroupMappingId).collect(Collectors.toList());
                                    for (Integer id : planGroupMappingids) {
                                        if (id != null && charge.getId() != null) {
                                            QPlanGroupMappingChargeRel qPlanGroupMappingChargeRel = QPlanGroupMappingChargeRel.planGroupMappingChargeRel;
                                            BooleanExpression exp1 = qPlanGroupMappingChargeRel.isNotNull().and(qPlanGroupMappingChargeRel.planGroupMapping.planGroupMappingId.eq(id));
                                            exp1 = exp1.and(qPlanGroupMappingChargeRel.planId.eq(plan.getId())).and(qPlanGroupMappingChargeRel.charge.id.eq(charge.getId()));
                                            List<PlanGroupMappingChargeRel> planGroupMappingChargeRel = (List<PlanGroupMappingChargeRel>) planGroupMappingChargeRelRepo.findAll(exp1);
                                            if (planGroupMappingChargeRel.size() > 0) {
                                                amount = planGroupMappingChargeRel.get(0).getPrice();
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        if (custPlanMappping.getDiscount() != null) {
                            discount = custPlanMappping.getDiscount();
                            if (custPlanMappping.getDiscount() < 0) {
                                discount = (amount * discount) / 100;
                                customerChargeHistory.setChargeAmount(amount);
                            } else {
                                customerChargeHistory.setChargeAmount(amount);
                                customerChargeHistory.setDiscount(discount);
                            }
                        } else if (plangroupId != null) {
                            discount = customer.getDiscount();
                            if (discount < 0) {
                                discount = (amount * discount) / 100;
                                customerChargeHistory.setChargeAmount(amount);
                            } else {
                                customerChargeHistory.setChargeAmount(amount);
                                customerChargeHistory.setDiscount(discount);
                            }
                        } else if (custPlanMappping.getDiscount() == null) {
                            customerChargeHistory.setChargeAmount(amount);
                            customerChargeHistory.setDiscount(discount);
                        }
                        if (custPlanMappping.getBillTo() != null && custPlanMappping.getBillTo().equalsIgnoreCase(Constants.ORGANIZATION)) {
                            Double actualPrice1 = (amount * custPlanMappping.getNewAmount()) / plan.getOfferprice();
                            Double actualPrice = (charge.getPrice() * custPlanMappping.getNewAmount()) / plan.getOfferprice();
                            if (postpaidPlanCharge.getPlan() != null && postpaidPlanCharge.getPlan().getCategory() != null && postpaidPlanCharge.getPlan().getCategory().equalsIgnoreCase("Business Promotion") && customer.getId() != 1 && customer.getId() != 2)
                                actualPrice = amount;
                            if (postpaidPlanCharge.getPlan() != null && postpaidPlanCharge.getPlan().getCategory() != null && postpaidPlanCharge.getPlan().getCategory().equalsIgnoreCase("Business Promotion") && (customer.getId() == 1 || customer.getId() == 2))
                                actualPrice = charge.getPrice() - postpaidPlanCharge.getChargeprice();

                            if (custPlanMappping.getDiscount() != null && custPlanMappping.getDiscount() < 0) {
                                discount = (actualPrice * custPlanMappping.getDiscount()) / 100;
                                customerChargeHistory.setChargeAmount(actualPrice);
                            } else {
                                customerChargeHistory.setChargeAmount(actualPrice);
                                customerChargeHistory.setDiscount(custPlanMappping.getDiscount());
                            }
                        }

                        Double totalAmount = 0.0d;
                        Charge charge1 = chargeRepository.findById(customerChargeHistory.getChargeId()).orElse(null);
                        if (charge != null) {
                            totalAmount = taxService.getTaxAmountFromChargeAndPrice(charge1, customerChargeHistory.getChargeAmount());
                            log.debug("Get tax amount from charge and price :" + totalAmount);
                        }
                        customerChargeHistory.setTaxAmount(totalAmount);

                        if (plangroupId != null) customerChargeHistory.setPlanGroupId(plangroupId);
                        customerChargeHistory.setCustPlanMapppingId(custPlanMappping.getId());
                        CustomerChargeHistory saveCustomerChargeHistory = customerChargeHistoryRepo.save(customerChargeHistory);
                        if (planMapppingPojo != null) {
                            if (planMapppingPojo.getInstallmentFrequency() != null && !planMapppingPojo.getInstallmentFrequency().isEmpty()) {
                                CustChargeInstallment custChargeInstallment = new CustChargeInstallment();
                                custChargeInstallment.setCustomerId(customerChargeHistory.getCustomerId());
                                custChargeInstallment.setCustChargeHistory(saveCustomerChargeHistory);

                                custChargeInstallment.setInstallmentFrequency(planMapppingPojo.getInstallmentFrequency());
                                custChargeInstallment.setInstallmentNo(-1);
                                custChargeInstallment.setTotalInstallments(planMapppingPojo.getTotalInstallments());

                                BigDecimal amountPerInstallment = custChargeService.calculateAmountPerInstallment(customerChargeHistory.getChargeAmount(), planMapppingPojo.getTotalInstallments());
                                custChargeInstallment.setAmountPerInstallment(amountPerInstallment);

                                custChargeInstallment.setInstallmentEnabled(true);
                                custChargeInstallmentRepository.save(custChargeInstallment);
                            }
                        }
                    } catch (Exception e) {
                        log.error("error encounterd while saving charge history for the customer : " + cusotmerUsername + " " + e.getMessage());
                        throw new RuntimeException(e);
                    }
                }
            });
        }
        for(CustPlanMapppingPojo planmapping : customer.getPlanMappingList()){

            if(planmapping.getVasId() != null ){
                Boolean flag = customerChargeHistoryRepo.existsByCustPlanMapppingId(planmapping.getId());
                if(flag == true){
                    continue;
                }
                List<VasPlanCharge> mappings = vasPlanChargeRepository.findByVasPlanId(planmapping.getVasId());
                List<Integer> chargeId = mappings.stream()
                        .map(v -> v.getCharge().getId()) // assuming getCharge() returns Charge entity, and getId() gives charge ID
                        .collect(Collectors.toList());

                Charge charge = null;
                if (!CollectionUtils.isEmpty(chargeId)) {
                    charge = chargeRepository.findById(chargeId.get(0)).orElse(null);
                }
                if(charge != null) {
                    Integer count = debitDocRepository.getCount(charge.getId(), customer.getId());
                    log.debug("total debitdoc count based on customer : " + cusotmerUsername);
                    if (!(charge.getChargetype().equalsIgnoreCase(CommonConstants.CHARGE_TYPE_NONRECURRING) && count > 0) || ((charge.getChargetype().equalsIgnoreCase(CommonConstants.CHARGE_TYPE_NONRECURRING) && count > 0 && (isNewService || !isChargeAlreadyExistForCustId(charge.getId(), customer.getId())))) || purchaseType.equalsIgnoreCase("Addon")) {
                        Integer locationId = null;
                        if (!CollectionUtils.isEmpty(customer.getAddressList())) {
                            locationId = customer.getAddressList().stream().filter(data -> data.getAddressType().equalsIgnoreCase(SubscriberConstants.CUST_ADDRESS_PRESENT)).findFirst().orElse(null).getStateId();
                        }
                        TaxDetailCountReqDTO taxDetailCountReqDTO = new TaxDetailCountReqDTO(null, locationId, customer.getId(), chargeId.get(0));
                        try {
                            CustomerChargeHistory customerChargeHistory = new CustomerChargeHistory();
                            customerChargeHistory.setCustomerId(customer.getId());
                            customerChargeHistory.setChargeId(charge.getId());
                            customerChargeHistory.setTaxId(charge.getTax().getId());
                            customerChargeHistory.setTaxAmount(taxService.taxCalculationByCharge(taxDetailCountReqDTO, charge));
                            customerChargeHistory.setPlanId(null);
                            customerChargeHistory.setPlanName(null);
                            customerChargeHistory.setChargeType(charge.getChargetype());
                            customerChargeHistory.setCharge_desc(charge.getDesc());
                            customerChargeHistory.setBillingCycle(null);
                            customerChargeHistory.setChargeName(charge.getName());
                            customerChargeHistory.setSaccode(charge.getSaccode());
                            customerChargeHistory.setIsFirstChargeApply(false);
                            if (charge.getRoyalty_payable() != null)
                                customerChargeHistory.setIsRoyaltyApply(charge.getRoyalty_payable());
                            else customerChargeHistory.setIsRoyaltyApply(false);

                            customerChargeHistory.setNextBillDate(null);
                            customerChargeHistory.setCustomerBillDay(null);
                            customerChargeHistory.setLastBillDate(null);

                            double discount = 0.0;
                            Double amount = charge.getActualprice();
                            log.debug("Fetching charge amount : " + amount);
                            if (plangroupId != null) {
                                if (plan.getId() != null && plangroupId != null) {
                                    QPlanGroupMapping qPlanGroupMapping = QPlanGroupMapping.planGroupMapping;
                                    BooleanExpression exp = qPlanGroupMapping.isNotNull().and(qPlanGroupMapping.plan.id.eq(plan.getId())).and(qPlanGroupMapping.planGroup.planGroupId.eq(plangroupId));
                                    List<PlanGroupMapping> planGroupMappingList = (List<PlanGroupMapping>) planGroupMappingRepository.findAll(exp);
                                    if (planGroupMappingList.size() > 0) {
                                        List<Integer> planGroupMappingids = planGroupMappingList.stream().map(PlanGroupMapping::getPlanGroupMappingId).collect(Collectors.toList());
                                        for (Integer id : planGroupMappingids) {
                                            if (id != null && charge.getId() != null) {
                                                QPlanGroupMappingChargeRel qPlanGroupMappingChargeRel = QPlanGroupMappingChargeRel.planGroupMappingChargeRel;
                                                BooleanExpression exp1 = qPlanGroupMappingChargeRel.isNotNull().and(qPlanGroupMappingChargeRel.planGroupMapping.planGroupMappingId.eq(id));
                                                exp1 = exp1.and(qPlanGroupMappingChargeRel.planId.eq(plan.getId())).and(qPlanGroupMappingChargeRel.charge.id.eq(charge.getId()));
                                                List<PlanGroupMappingChargeRel> planGroupMappingChargeRel = (List<PlanGroupMappingChargeRel>) planGroupMappingChargeRelRepo.findAll(exp1);
                                                if (planGroupMappingChargeRel.size() > 0) {
                                                    amount = planGroupMappingChargeRel.get(0).getPrice();
                                                }
                                            }
                                        }
                                    }
                                }
                            }

                            if (planmapping.getDiscount() != null) {
                                discount = planmapping.getDiscount();
                                if (planmapping.getDiscount() < 0) {
                                    discount = (amount * discount) / 100;
                                    customerChargeHistory.setChargeAmount(amount);
                                } else {
                                    customerChargeHistory.setChargeAmount(amount);
                                    customerChargeHistory.setDiscount(discount);
                                }
                            } else if (plangroupId != null) {
                                discount = customer.getDiscount();
                                if (discount < 0) {
                                    discount = (amount * discount) / 100;
                                    customerChargeHistory.setChargeAmount(amount);
                                } else {
                                    customerChargeHistory.setChargeAmount(amount);
                                    customerChargeHistory.setDiscount(discount);
                                }
                            } else if (planmapping.getDiscount() == null) {
                                customerChargeHistory.setChargeAmount(amount);
                                customerChargeHistory.setDiscount(discount);
                            }

                            Double totalAmount = 0.0d;
                            Charge charge1 = chargeRepository.findById(customerChargeHistory.getChargeId()).orElse(null);
                            if (charge != null) {
                                totalAmount = taxService.getTaxAmountFromChargeAndPrice(charge1, customerChargeHistory.getChargeAmount());
                                log.debug("Get tax amount from charge and price :" + totalAmount);
                            }
                            customerChargeHistory.setTaxAmount(totalAmount);

                            if (plangroupId != null) customerChargeHistory.setPlanGroupId(plangroupId);
                            customerChargeHistory.setCustPlanMapppingId(planmapping.getId());
                            CustomerChargeHistory saveCustomerChargeHistory = customerChargeHistoryRepo.save(customerChargeHistory);
                            if(planmapping != null){
                                if(planmapping.getInstallmentFrequency() != null && !planmapping.getInstallmentFrequency().isEmpty()){
                                    CustChargeInstallment custChargeInstallment = new CustChargeInstallment();
                                    custChargeInstallment.setCustomerId(customerChargeHistory.getCustomerId());
                                    custChargeInstallment.setCustChargeHistory(saveCustomerChargeHistory);

                                    custChargeInstallment.setInstallmentFrequency(planmapping.getInstallmentFrequency());
                                    custChargeInstallment.setInstallmentNo(-1);
                                    custChargeInstallment.setTotalInstallments(planmapping.getTotalInstallments());

                                    BigDecimal amountPerInstallment = custChargeService.calculateAmountPerInstallment(customerChargeHistory.getChargeAmount(), planmapping.getTotalInstallments());
                                    custChargeInstallment.setAmountPerInstallment(amountPerInstallment);

                                    custChargeInstallment.setInstallmentEnabled(true);
                                    custChargeInstallmentRepository.save(custChargeInstallment);
                                }
                            }
                        } catch (Exception e) {
                            log.error("error encounterd while saving charge history for the customer : " + cusotmerUsername + " " + e.getMessage());
                            throw new RuntimeException(e);
                        }
                    }
                }
            }

        }
    }
