    public Page<Customers> getAllChildCustomer(Integer customerId, PaginationRequestDTO paginationDTO, String invoiceType) {

        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isDeleted.eq(false).and(qCustomers.parentCustomers.id.eq(customerId)).and(qCustomers.status.eq(CommonConstants.ACTIVE_STATUS));
        List<Integer> custIds = new ArrayList<>();
        custIds = ((List<Customers>) customersRepository.findAll(booleanExpression)).stream().map(i -> i.getId()).collect(Collectors.toList());

        if (invoiceType != null) {
            QCustomerServiceMapping qCustomerServiceMapping = QCustomerServiceMapping.customerServiceMapping;
            BooleanExpression exp = qCustomerServiceMapping.isNotNull();
            exp = exp.and(qCustomerServiceMapping.custId.in(custIds)).and(qCustomerServiceMapping.invoiceType.eq(invoiceType));
            custIds = ((List<CustomerServiceMapping>) customerServiceMappingRepository.findAll(exp)).stream().map(i -> i.getCustId()).collect(Collectors.toList());
        }

        BooleanExpression exp3 = qCustomers.id.in(custIds);


        if (getBUIdsFromCurrentStaff().size() != 0)
            // TODO: pass mvnoID manually 6/5/2025
            exp3 = exp3.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(customerId)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        PageRequest pageRequest = generatePageRequest(paginationDTO.getPage(), paginationDTO.getPageSize(), "createdate", CommonConstants.SORT_ORDER_DESC);
        return customersRepository.findAll(exp3, pageRequest);
    }

