    @Transactional
    public void removeParent(List<Integer> listOfCustomerIds) {
        listOfCustomerIds.forEach(customerId -> {
            Customers customers = customersRepository.findByIdAndIsDeletedIsFalse(customerId);
            customers.setParentCustomers(null);
            customers.setInvoiceType(null);
            customersRepository.save(customers);
        });
    }

    @Transactional
    public void updateParent1(Integer oldParentId, Integer newParentId) {
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isDeleted.eq(false).and(qCustomers.parentCustomers.id.eq(oldParentId));
        Customers newParentCustomer = customersRepository.findByIdAndIsDeletedIsFalse(newParentId);
        Customers oldParent = customersRepository.findByIdAndIsDeletedIsFalse(oldParentId);
        List<Customers> customers = (List<Customers>) customersRepository.findAll(booleanExpression);
        customers.add(oldParent);
        customers.forEach(customer -> {
            customer.setParentCustomers(newParentCustomer);
            customer.setInvoiceType("Group");
            customersRepository.save(customer);
        });
        newParentCustomer.setParentCustomers(null);
        newParentCustomer.setInvoiceType(null);
        customersRepository.save(newParentCustomer);
    }

    @Transactional
    public void updateParent(Integer oldParentId, Integer newParentId) {
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isDeleted.eq(false).and(qCustomers.parentCustomers.id.eq(oldParentId));
        Customers newParentCustomer = customersRepository.findByIdAndIsDeletedIsFalse(newParentId);

        Customers oldParent = customersRepository.findByIdAndIsDeletedIsFalse(oldParentId);

        List<CustomerServiceMapping> newCustomerServiceMappings = customerServiceMappingRepository.findAllByCustIdAndInvoiceType(newParentId, Constants.GROUP_INVOICE_TYPE);

        //fetch old parent all service match with child service
        if (!CollectionUtils.isEmpty(newCustomerServiceMappings)) {
            List<Long> serviceIds = newCustomerServiceMappings.stream().map(CustomerServiceMapping::getServiceId).collect(Collectors.toList());
            if (!CollectionUtils.isEmpty(serviceIds)) {
                List<CustomerServiceMapping> oldCustomerServiceMappings = customerServiceMappingRepository.findAllByCustIdAndServiceIdIn(oldParentId, serviceIds);
                if (!CollectionUtils.isEmpty(oldCustomerServiceMappings)) {
                    oldCustomerServiceMappings = oldCustomerServiceMappings.stream().peek(customerServiceMapping -> customerServiceMapping.setInvoiceType(Constants.GROUP_INVOICE_TYPE)).collect(Collectors.toList());
                    customerServiceMappingRepository.saveAll(oldCustomerServiceMappings);
                }
            }
            newCustomerServiceMappings = newCustomerServiceMappings.stream().peek(customerServiceMapping -> customerServiceMapping.setInvoiceType(null)).collect(Collectors.toList());
            customerServiceMappingRepository.saveAll(newCustomerServiceMappings);
        }

        List<Customers> customers = (List<Customers>) customersRepository.findAll(booleanExpression);
        customers.add(oldParent);
        customers.forEach(customer -> {
            customer.setParentCustomers(newParentCustomer);
            customer.setInvoiceType("Group");
            customersRepository.save(customer);
        });
        newParentCustomer.setParentCustomers(null);
        newParentCustomer.setInvoiceType(null);
        customersRepository.save(newParentCustomer);
    }

    @Transactional
    public Boolean isParentCustomer(Integer custId) {
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isDeleted.eq(false).and(qCustomers.parentCustomers.id.eq(custId));
        List<Customers> customers = (List<Customers>) customersRepository.findAll(booleanExpression);
        return customers.size() > 0;
    }

    public Page<Customers> searchParentCustomersByCustomerType(List<GenericSearchModel> filterList, Integer page, Integer pageSize, String sortBy, Integer sortOrder, String type, String status,Integer mvnoId) {
        String SUBMODULE = MODULE + " [search()] ";
        Pageable pageable = generatePageRequest(page, pageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        StringBuilder whereCondition = new StringBuilder();
        StringBuilder join = new StringBuilder();
        String finalQuery = "";
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false)).and(qCustomers.parentCustomers.id.isNull());
        if (Objects.isNull(status)) {
            booleanExpression = booleanExpression.and(qCustomers.status.notEqualsIgnoreCase(CommonConstants.CUSTOMER_STATUS_NEW_ACTIVATION));
            booleanExpression = booleanExpression.and(qCustomers.status.notEqualsIgnoreCase(CommonConstants.CUSTOMER_STATUS_REJECTED));
        } else if (status.equals(CommonConstants.CUSTOMER_STATUS_NEW_ACTIVATION)) {
            booleanExpression = booleanExpression.and(qCustomers.status.eq(status));
        }
        // TODO: pass mvnoID manually 6/5/2025
        if (mvnoId != 1)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.in(mvnoId, 1));
        if (getBUIdsFromCurrentStaff().size() != 0)
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(mvnoId).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        if (!type.isEmpty() && !type.equalsIgnoreCase("both")) {
            booleanExpression = booleanExpression.and(qCustomers.custtype.eq(type));
        }
        try {
            for (GenericSearchModel searchModel : filterList) {
                if (searchModel.getFilterColumn().trim().contains(SearchConstants.SERVICE_AREA)) {
                    if (!searchModel.getFilterValue().isEmpty()) {
                        booleanExpression = booleanExpression.and(qCustomers.servicearea.id.eq(Long.parseLong(searchModel.getFilterValue())));
                    }
                }
                if (searchModel.getFilterColumn().trim().equalsIgnoreCase("status")) {
                    if (!searchModel.getFilterColumn().isEmpty()) {
                        booleanExpression = booleanExpression.and(qCustomers.status.eq(searchModel.getFilterValue()));
                    }
                }
                if (searchModel.getFilterColumn().trim().equalsIgnoreCase(SearchConstants.ANY)) {
                    if (!searchModel.getFilterValue().isEmpty()) {
                        String s1 = searchModel.getFilterValue();
                        booleanExpression = booleanExpression.and((qCustomers.username.like("%" + s1 + "%")).or(qCustomers.firstname.like("%" + s1 + "%")).or(qCustomers.mobile.contains(searchModel.getFilterValue())).or(qCustomers.servicearea.name.like("%" + s1 + "%")).or(qCustomers.acctno.eq(searchModel.getFilterValue())));
                        if (getLoggedInUserPartnerId() != CommonConstants.DEFAULT_PARTNER_ID) {
                            booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
                            booleanExpression = booleanExpression.or(qCustomers.partner.name.eq(s1));
                        }
                        return customersRepository.findAll(booleanExpression, pageRequest);
                    }
                }
                if (null != searchModel.getFilterCondition()) {
                    if (searchModel.getFilterCondition().equalsIgnoreCase(SearchConstants.AND)) {

                        if (searchModel.getFilterColumn().equalsIgnoreCase("plan")) {
                            Integer searchdata = Integer.valueOf(searchModel.getFilterValue());
                            List<CustPlanMappping> custPlanMapppings = custPlanMappingRepository.findByPlanId(searchdata);
                            List<Integer> idlist = new ArrayList<>();
                            for (CustPlanMappping custPlanMappping : custPlanMapppings) {
                                idlist.add(custPlanMappping.getCustomer().getId());
                            }
                            booleanExpression = booleanExpression.and(qCustomers.id.in(idlist));
                            return customersRepository.findAll(booleanExpression, pageable);
                        }
                        if (searchModel.getFilterColumn().equalsIgnoreCase(SearchConstants.CUST_USERNAME)) {
                            String s1 = searchModel.getFilterValue();
                            booleanExpression = booleanExpression.and((qCustomers.username.like("%" + s1 + "%")));
                            if (getLoggedInUserPartnerId() != CommonConstants.DEFAULT_PARTNER_ID) {
                                booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
                            }
                            return customersRepository.findAll(booleanExpression, pageRequest);
                        }
                        if (searchModel.getFilterColumn().equalsIgnoreCase(SearchConstants.CUST_FULLNAME)) {
                            booleanExpression=booleanExpression.and((qCustomers.firstname).concat(" ").concat(qCustomers.lastname).eq(searchModel.getFilterValue()));
                            if (getLoggedInUserPartnerId() != CommonConstants.DEFAULT_PARTNER_ID) {
                                booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
                            }
                            return customersRepository.findAll(booleanExpression, pageRequest);
                        }
                        return customersRepository.findAll(generateAndCondition(searchModel, booleanExpression), pageable);
                    } else {
                        generateOrCondition(searchModel, whereCondition, join);
                    }
                } else {
                    return customersRepository.findAll(generateAndCondition(searchModel, booleanExpression), pageable);
                }
            }
        } catch (Exception ex) {
            logger.error(" Unable to search parent customer by type: error{};exception{}", APIConstants.FAIL, ex.getStackTrace());
            throw ex;
        }
        return null;
    }

