    public Page<Customers> searchByInvoiceType(List<GenericSearchModel> filterList, Integer page, Integer pageSize, String sortBy, Integer sortOrder, String invoiceType, String status,Integer mvnoId) {
        String SUBMODULE = MODULE + " [search()] ";
        Pageable pageable = generatePageRequest(page, pageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        StringBuilder whereCondition = new StringBuilder();
        StringBuilder join = new StringBuilder();
        String finalQuery = "";
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false));
//        if (Objects.isNull(status)) {
//            booleanExpression = booleanExpression.and(qCustomers.status.notEqualsIgnoreCase(CommonConstants.CUSTOMER_STATUS_NEW_ACTIVATION));
//        } else if (status.equals(CommonConstants.CUSTOMER_STATUS_NEW_ACTIVATION)) {
//            booleanExpression = booleanExpression.and(qCustomers.status.eq(status));
//        }
        if (!invoiceType.isEmpty()) {
            booleanExpression = booleanExpression.and(qCustomers.invoiceType.ne(invoiceType).or(qCustomers.invoiceType.isNull()));
        }
        if (getBUIdsFromCurrentStaff().size() != 0)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(mvnoId).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        try {
            for (GenericSearchModel searchModel : filterList) {
                if (mvnoId != 1) {
                    List<java.lang.Long> serviceAreaList = getServiceAreaIdList();
                    if (serviceAreaList.size() > 0 && !serviceAreaList.isEmpty()) {
                        // TODO: pass mvnoID manually 6/5/2025
                        booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(mvnoId).and(qCustomers.servicearea.id.in(serviceAreaList)));
                    } else {
                        // TODO: pass mvnoID manually 6/5/2025
                        booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(mvnoId));
                    }
                }
                if (searchModel.getFilterColumn().trim().contains(SearchConstants.SERVICE_AREA)) {
                    if (!searchModel.getFilterValue().isEmpty()) {
                        booleanExpression = booleanExpression.and(qCustomers.servicearea.id.eq(Long.parseLong(searchModel.getFilterValue())));
                    }
                }
                if (searchModel.getFilterColumn().trim().equalsIgnoreCase("status")) {
                    if (!searchModel.getFilterColumn().isEmpty()) {
                        booleanExpression = booleanExpression.and(qCustomers.status.eq(searchModel.getFilterValue()));
                    }
                }

                if (searchModel.getFilterColumn().trim().equalsIgnoreCase("service")) {
                    if (!searchModel.getFilterColumn().isEmpty()) {
                        String searchdata = searchModel.getFilterValue();
                        List<PlanService> planServices = planServiceRepository.findAllByName(searchdata);
                        List<CustomerServiceMapping> customerServiceMappings = customerServiceMappingRepository.findAllByServiceIdIn(planServices.stream().map(planService1 -> planService1.getId().longValue()).collect(Collectors.toList()));
                        List<Integer> customerIds = customerServiceMappings.stream().map(CustomerServiceMapping::getCustId).collect(Collectors.toList());
                        booleanExpression = booleanExpression.and(qCustomers.id.in(customerIds));
                    }
                }
                if (searchModel.getFilterColumn().trim().equalsIgnoreCase(SearchConstants.ANY) || searchModel.getFilterColumn().trim().equalsIgnoreCase(SearchConstants.CUST_USERNAME)) {
                    if (!searchModel.getFilterValue().isEmpty()) {
                        String s1 = searchModel.getFilterValue();
                        booleanExpression = booleanExpression.and((qCustomers.username.like("%" + s1 + "%")).or(qCustomers.firstname.like("%" + s1 + "%")).or(qCustomers.mobile.contains(searchModel.getFilterValue())).or(qCustomers.servicearea.name.like("%" + s1 + "%")).or(qCustomers.acctno.eq(searchModel.getFilterValue())));
                        if (getLoggedInUserPartnerId() != CommonConstants.DEFAULT_PARTNER_ID) {
                            booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
                            booleanExpression = booleanExpression.or(qCustomers.partner.name.eq(s1));
                        }
                        return customersRepository.findAll(booleanExpression, pageRequest);
                    }
                }

                if (null != searchModel.getFilterCondition()) {
                    List<Integer> idlist = new ArrayList<>();
                    if (searchModel.getFilterColumn().equalsIgnoreCase("PLAN")) {
                        QPostpaidPlan qPostpaidPlan = QPostpaidPlan.postpaidPlan;
                        List<CustPlanMappping> custPlanMapppings = new ArrayList<>();
                        BooleanExpression booleanExpression1 = qPostpaidPlan.isNotNull();
                        booleanExpression1 = booleanExpression1.and(qPostpaidPlan.id.eq(Integer.valueOf(searchModel.getFilterValue())));
                        List<PostpaidPlan> postpaidPlan = IterableUtils.toList(postpaidPlanRepo.findAll(booleanExpression1));
                        List<CustPlanMappping> custPlanMapppingList = new ArrayList<>();
                        for (PostpaidPlan plan : postpaidPlan) {
                            custPlanMapppingList.addAll(custPlanMappingRepository.findByPlanId(plan.getId()));
                        }
                        for (CustPlanMappping custPlanMappping : custPlanMapppingList) {
                            idlist.add(custPlanMappping.getCustomer().getId());
                        }
                        booleanExpression = booleanExpression.and(qCustomers.id.in(idlist));
                        booleanExpression = booleanExpression.and(qCustomers.status.equalsIgnoreCase("Active"));
                        return customersRepository.findAll(booleanExpression, pageable);
                    }
                    if (searchModel.getFilterCondition().equalsIgnoreCase(SearchConstants.AND)) {
                        return customersRepository.findAll(generateAndCondition(searchModel, booleanExpression), pageable);
                    } else {
                        generateOrCondition(searchModel, whereCondition, join);
                    }
                } else {
                    return customersRepository.findAll(generateAndCondition(searchModel, booleanExpression), pageable);
                }


            }
        } catch (Exception ex) {
            ApplicationLogger.logger.error(SUBMODULE + ex.getMessage(), ex);
            throw ex;
        }
        return null;
    }

    @Override
    public Customers get(Integer id,Integer mvnoId) {//TODO redis
        String cacheKey = cacheKeys.CUSTOMERS + id;
        Customers customers = null;
//        long startTime = System.currentTimeMillis();
        try {
            // Try to get from cache
            customers = (Customers) cacheService.getFromCache(cacheKey, Customers.class);
//            long endTimeCache = System.currentTimeMillis();
//            log.warn("Total time to get Customers from cache: " + (endTimeCache - startTime) + "ms");

            if (customers != null) {
                log.info("Customer from cache ::::::::::::::::" + customers.getId() + " ::::: Username :::::: " + customers.getUsername() + " :::: status :::: " + customers.getStatus());
                // Return the cached data if available
                return customers;
            }

            // Fetch from DB if not found in cache
            customers = super.get(id,mvnoId);

            if (customers != null) {
                // TODO: pass mvnoID manually 6/5/2025
//                Integer mvnoId = customers.getMvnoId();

                if (customers.getId().equals(1) || customers.getId().equals(2)) {
                    if (mvnoId == 1 || (customers.getMvnoId().equals(mvnoId) || customers.getMvnoId() == 1)) {
                        // Cache the fetched data
                        log.info("Customer from Database query ::::::::::::::::" + customers.getId() + " ::::: Username :::::: " + customers.getUsername() + " :::: status :::: " + customers.getStatus());
                        log.info("Customer stored in cache ::::::::::::::::");
                        cacheService.putInCacheWithExpire(cacheKey, customers);
                        return customers;
                    }
                } else {
                    if (mvnoId == 1 || (customers.getMvnoId().equals(mvnoId) || customers.getMvnoId() == 1) && (customers.getMvnoId() == 1 || getBUIdsFromCurrentStaff().size() == 0 || getBUIdsFromCurrentStaff().contains(customers.getBuId()))) {
                        // Cache the fetched data
                        log.info("Customer from Database query ::::::::::::::::" + customers.getId() + " ::::: Username :::::: " + customers.getUsername() + " :::: status :::: " + customers.getStatus());
                        log.info("Customer stored in cache ::::::::::::::::");
                        cacheService.putInCacheWithExpire(cacheKey, customers);
                        return customers;
                    }
                }
            }
        } catch (Exception e) {
            log.error("Error while fetching Customers: ", e);
        }

//        long endTime = System.currentTimeMillis();
//        log.warn("Total execution time for Customers.get: " + (endTime - startTime) + "ms");
        return null;  // Return null if no data found or conditions aren't met

    }

