    public boolean checkCustomerTerminationFlow(int custId) {
        boolean isAvailabe = true;
        DecimalFormat df = new DecimalFormat("#.00");
        try {
            Optional<Customers> customers = customersRepository.findById(custId);
            if (customers.isPresent()) {
                List<DebitDocument> debitDocumentList = debitDocRepository.findAllByCustomerAndBillrunstatusIsNot(customers.get(), "VOID");
                List<Integer> cprList = debitDocumentList.stream().map(DebitDocument::getCustpackrelid).collect(Collectors.toList());
                QCustPlanMappping qCustPlanMappping = QCustPlanMappping.custPlanMappping;
                BooleanExpression exp = qCustPlanMappping.isNotNull().and(qCustPlanMappping.id.in(cprList)).and(qCustPlanMappping.custPlanStatus.notEqualsIgnoreCase("STOP"));
                List<CustPlanMappping> custPlanMapppings = (List<CustPlanMappping>) custPlanMappingRepository.findAll(exp);
                List<Integer> activeCprs = custPlanMapppings.stream().map(CustPlanMappping::getId).collect(Collectors.toList());
                if (!CollectionUtils.isEmpty(debitDocumentList)) {
                    Optional<DebitDocument> debitDocument = null;
                    if (CollectionUtils.isEmpty(custPlanMapppings)) {
                        debitDocument = debitDocumentList.stream().filter(debidDoc -> (debidDoc.getStartdate().toLocalDate().isBefore(LocalDate.now()) || debidDoc.getStartdate().toLocalDate().isEqual(LocalDate.now())) && (debidDoc.getEndate().toLocalDate().isEqual(LocalDate.now()) || debidDoc.getEndate().toLocalDate().isAfter(LocalDate.now()))).findFirst();

                    } else {
                        debitDocument = debitDocumentList.stream().filter(debidDoc -> (debidDoc.getStartdate().toLocalDate().isBefore(LocalDate.now()) || debidDoc.getStartdate().toLocalDate().isEqual(LocalDate.now())) && (debidDoc.getEndate().toLocalDate().isEqual(LocalDate.now()) || debidDoc.getEndate().toLocalDate().isAfter(LocalDate.now())) && activeCprs.contains(debidDoc.getCustpackrelid().intValue())).findFirst();
                    }
                    RecordPaymentPojo pojo = new RecordPaymentPojo();
                    if (debitDocument.isPresent()) {
                        Double totalAmount = debitDocument.get().getTotalamount();
                        if (debitDocument.get().getAdjustedAmount() != null) {
                            totalAmount = totalAmount - debitDocument.get().getAdjustedAmount();
                        }
                        LocalDateTime startDate = debitDocument.get().getStartdate();
                        LocalDateTime endDate = debitDocument.get().getEndate();
                        LocalDateTime todayDate = LocalDateTime.now();
                        Long invoiceDays = ChronoUnit.DAYS.between(startDate, endDate);
                        Long usedDays = ChronoUnit.DAYS.between(startDate, todayDate);
                        List<Integer> invoiceId = new ArrayList<>();
                        invoiceId.add(debitDocument.get().getId());
                        if (usedDays <= 0) usedDays = 0L;
                        else usedDays = usedDays;
                        Double dbr = 0d;
                        if (!invoiceDays.equals(usedDays)) {
                            Double edr = totalAmount / invoiceDays;
                            dbr = edr * usedDays;
                        }
                        totalAmount = totalAmount - dbr;
                        pojo.setPaytype("invoice");
                        pojo.setInvoiceId(invoiceId);
                        pojo.setAmount(Double.valueOf(df.format(totalAmount)));
                        pojo.setCustomerid(custId);
                        pojo.setPaymentdate(LocalDate.now());
                        pojo.setPaymode("Credit Note");
                        pojo.setReferenceno(debitDocument.get().getId().toString());
                        pojo.setRemark("Create credit-note for terminate customer!");
                        pojo.setType("creditnote");
                        pojo.setLoggedInuserid(getLoggedInUserId());
                        //if (totalAmount > 0)
                        //creditDocService.save(pojo, false, false, false);
                        debitDocumentList.remove(debitDocument.get());
                    }
                    if (debitDocumentList.size() > 1) {
                        Optional<DebitDocument> finalDebitDocument = debitDocument;
                        Double totalCreditNoteAmount = debitDocumentList.stream().filter(debitDocument1 -> !debitDocument1.getId().equals(finalDebitDocument.get().getId())).mapToDouble(DebitDocument::getTotalamount).sum();
                        Double totalAdjustedAmount = debitDocumentList.stream().filter(debitDocument1 -> !debitDocument1.getId().equals(finalDebitDocument.get().getId()) && debitDocument1.getAdjustedAmount() != null).mapToDouble(DebitDocument::getAdjustedAmount).sum();
                        if (totalAdjustedAmount != null) {
                            totalCreditNoteAmount = totalCreditNoteAmount - totalAdjustedAmount;
                        }
                        pojo.setPaytype("advance");
                        pojo.setAmount(totalCreditNoteAmount);
                        pojo.setCustomerid(custId);
                        pojo.setPaymentdate(LocalDate.now());
                        pojo.setPaymode("auto");
                        pojo.setReferenceno("123");
                        pojo.setRemark("Create credit-note for terminate customer!");
                        pojo.setType("creditnote");
                        //if (totalCreditNoteAmount > 0)
                        //creditDocService.save(pojo, false, false, false);

                    }
                }
            } else {
                throw new RuntimeException("Invalid customer id: " + custId);
            }
        } catch (Exception ex) {
            throw new CustomValidationException(HttpStatus.BAD_REQUEST.value(), ex.getMessage(), null);
        }
        return isAvailabe;
    }

    public boolean checkCustomerTerminationFlow1(int custId) {
        boolean isAvailabe = true;
        try {
            Optional<Customers> customers = customersRepository.findById(custId);
            if (customers.isPresent()) {
                List<DebitDocument> debitDocumentList = debitDocRepository.findAllByCustomerAndBillrunstatusIsNot(customers.get(), "VOID");
                if (!CollectionUtils.isEmpty(debitDocumentList)) {
                    Optional<DebitDocument> debitDocument = debitDocumentList.stream().filter(debidDoc -> (debidDoc.getStartdate().toLocalDate().isBefore(LocalDate.now()) || debidDoc.getStartdate().toLocalDate().isEqual(LocalDate.now())) && (debidDoc.getEndate().toLocalDate().isEqual(LocalDate.now()) || debidDoc.getEndate().toLocalDate().isAfter(LocalDate.now()))).findFirst();

                    if (debitDocument.isPresent()) {

                        Double totalDue = debitDocument.get().getTotaldue();
                        if (debitDocument.get().getAdjustedAmount() != null)
                            totalDue = debitDocument.get().getTotaldue() - debitDocument.get().getAdjustedAmount();
                        Double totalAmount = debitDocument.get().getTotalamount();
                        Double remainingAmount = totalAmount - totalDue;
                        if (totalDue > 0) {
                            throw new RuntimeException("Please clear due from customer: " + totalDue);
                        } else if (totalDue <= 0) {

                            if (customers.get().getCusttype().equalsIgnoreCase("PREPAID")) {
                                //Check invoice status
                                // If invoice status has pending then set exception to clear invoice.
                                String paymentStatus = debitDocument.get().getPaymentStatus();
                                if (paymentStatus.equalsIgnoreCase(UtilsCommon.PAYMENT_STATUS_PENDING_APPROVED) || paymentStatus.equalsIgnoreCase(UtilsCommon.PAYMENT_STATUS_PENDING_APPROVED)) {
                                    throw new RuntimeException("Please clear invoice Pending Status.");
                                }
                                LocalDateTime startDate = debitDocument.get().getStartdate();
                                LocalDateTime billDate = debitDocument.get().getBilldate();
                                LocalDateTime todayDate = LocalDateTime.now();
                                Long invoiceDifference = ChronoUnit.SECONDS.between(billDate, startDate);
                                Long currentDifference = ChronoUnit.SECONDS.between(todayDate, startDate);
                                Long remainingDays = invoiceDifference - currentDifference;
                                Double dbr = 0d;
                                if (remainingDays > 0) {
                                    Double edr = totalAmount / remainingDays;
                                    dbr = edr * remainingDays;
                                }
                                RecordPaymentPojo pojo = new RecordPaymentPojo();
                                pojo.setReferenceno(debitDocument.get().getDocnumber() + "- VOID");
                                List<Integer> invoiceId = new ArrayList<>();
                                invoiceId.add(0);
                                pojo.setInvoiceId(invoiceId);
                                pojo.setPaymode("Automatic");
                                pojo.setPaytype("advance");
                                pojo.setType(CommonConstants.TRANS_CATEGORY_PAYMENT);
                                pojo.setCustomerid(custId);
                                pojo.setPaymentdate(LocalDate.now());
                                pojo.setRemark("Add credit note on terminate customer for invoice: " + debitDocument.get().getId());

                                if (paymentStatus.equalsIgnoreCase(UtilsCommon.PAYMENT_STATUS_APPROVED)) {
                                    // If invoice status is CommonUtils.PAYMENT_STATUS_APPROVED then check start and enddate  and calculate by dbr with amountDue from ledger.
                                    pojo.setAmount(dbr);
                                }
                                if (paymentStatus.equalsIgnoreCase(UtilsCommon.PAYMENT_STATUS_PARTIAL_APPROVED)) {
                                    // IF invoice status is PAYMENT_STATUS_PARTIAL_APPROVED then check start and enddate and calculate by dbr with amountDue from ledger.
                                    if (dbr < remainingAmount) {
                                        throw new RuntimeException("Please clear due first from customer: " + remainingAmount);
                                    }
                                    pojo.setAmount(dbr - remainingAmount);
                                }
                                try {
                                    creditDocService.addLedgerAndLedgerDetailEntry(pojo, null, false);
                                } catch (Exception e) {
                                    throw new RuntimeException("Exception to save credit note on terminate customer: " + e.getMessage());
                                }
                            } else {
                                //update nextBillDate in customer.
                                customers.get().setNextBillDate(LocalDate.now());
                                LocalDate nextQuotaReset = customersService.getNextQuotaResetDate(customers.get(), customers.get().getNextBillDate());
                                if (nextQuotaReset != null) {
                                    customers.get().setNextQuotaResetDate(nextQuotaReset);
                                } else {
                                    customers.get().setNextQuotaResetDate(LocalDate.now());
                                }
                                customersRepository.save(customers.get());
                                isAvailabe = true;
                            }
                        }
                    }
                    debitDocService.voidInvoiceInBatch(debitDocumentList.stream().map(DebitDocument::getId).collect(Collectors.toList()),customers.get().getMvnoId());
                } else {
                    throw new RuntimeException("Invalid customer id: " + custId);
                }
            }
        } catch (RuntimeException ex) {
            throw new CustomValidationException(404, ex.getMessage(), null);
        }
        return isAvailabe;
    }

