    public void addNewCprAndUpdateChargeHistoryCprId(NewCprMessage message) {
        CustPlanMappping mappping = custPlanMappingRepository.findById(message.getCustPackageId()).get();
        if (mappping != null) {
            CustPlanMappping custPlanMappping = new CustPlanMappping();
            custPlanMappping.setCustomer(mappping.getCustomer());
            custPlanMappping.setPostpaidPlan(mappping.getPostpaidPlan());
            custPlanMappping.setService(mappping.getService());
            custPlanMappping.setPlanId(mappping.getPlanId());
            custPlanMappping.setCustRefId(mappping.getCustRefId());
            custPlanMappping.setStartDate(message.getStartDate());
            custPlanMappping.setEndDate(message.getEndDate());
            custPlanMappping.setExpiryDate(message.getEndDate());
            custPlanMappping.setBillTo(mappping.getBillTo());
            custPlanMappping.setDiscount(mappping.getDiscount());
            custPlanMappping.setIsDelete(mappping.getIsDelete());
            custPlanMappping.setNewAmount(mappping.getNewAmount());
            custPlanMappping.setTaxAmount(mappping.getTaxAmount());
            custPlanMappping.setCustRefId(mappping.getCustRefId());
            custPlanMappping.setCreatedByName(mappping.getCreatedByName());
            custPlanMappping.setLastModifiedByName(mappping.getLastModifiedByName());
            custPlanMappping.setOnlinePurchaseId(mappping.getOnlinePurchaseId());
            custPlanMappping.setOfferPrice(mappping.getOfferPrice());
            custPlanMappping.setPurchaseFrom(mappping.getPurchaseFrom());
            custPlanMappping.setPurchaseType(mappping.getPurchaseType());
            custPlanMappping.setQospolicy(mappping.getQospolicy());
            custPlanMappping.setPlanValidityDays(mappping.getPlanValidityDays());
            custPlanMappping.setIsInvoiceToOrg(mappping.getIsInvoiceToOrg());
            custPlanMappping.setWalletBalUsed(mappping.getWalletBalUsed());
            custPlanMappping.setPlanGroup(mappping.getPlanGroup());
            mappping = custPlanMappingRepository.save(custPlanMappping);
        }
        updateChargeHistoryCprId(mappping.getId(), message.getCustomerId(), message.getPlanId(), message.getCustPackageId());
    }

    private void updateChargeHistoryCprId(Integer id, Long customerId, Long planId, Long custPackageId) {
        CustomerChargeHistory customerChargeHistory = customerChargeHistoryRepo.findByPlandIdAndCustIdAndCprId(customerId, planId, custPackageId);
        if (customerChargeHistory != null) {
            customerChargeHistory.setCustPlanMapppingId(id);
            customerChargeHistoryRepo.save(customerChargeHistory);
        }
    }

    public List<CustomerApprove> findAllCustomerApprove(Integer customerId) {
        try {
            QCustomerApprove qCustomerApprove = QCustomerApprove.customerApprove;
            List<CustomerApprove> customerApproveList = IterableUtils.toList(customerApproveRepo.findAll(qCustomerApprove.customerID.eq(customerId)));
            return customerApproveList;
        } catch (Throwable exception) {
            throw new RuntimeException();
        }

    }

