    public Double getTotalAmountOfPlanPriceOfCustomer(ChangePlanRequestDTOList requestDTOs, Partner partner,Integer mvnoId) {
        AtomicReference<Double> amount = new AtomicReference<>(0.0);
        if (requestDTOs != null && partner != null) {
            if (null != requestDTOs.getChangePlanRequestDTOList() && 0 < requestDTOs.getChangePlanRequestDTOList().size()) {
                for (int i = 0; i < requestDTOs.getChangePlanRequestDTOList().size(); i++) {
                    ChangePlanRequestDTO dto = requestDTOs.getChangePlanRequestDTOList().get(i);
                    if (dto.getPlanId() != null && (dto.getPlanBindWithOldPlans() == null || dto.getPlanBindWithOldPlans().isEmpty())) {
                        PostpaidPlan plan = postpaidPlanService.get(requestDTOs.getChangePlanRequestDTOList().get(i).getPlanId(),mvnoId);
                        if (plan != null) amount.updateAndGet(v -> v + plan.getOfferprice());
                    }

                    if (dto.getPlanBindWithOldPlans() != null && !dto.getPlanBindWithOldPlans().isEmpty()) {
                        List<NewPlanBindWithOldPlan> newPlanBindWithOldPlanList = dto.getPlanBindWithOldPlans();
                        newPlanBindWithOldPlanList.stream().forEach(data -> {
                            if (data.getNewPlanId() != null) {
                                PostpaidPlan plan = postpaidPlanService.get(data.getNewPlanId(),mvnoId);
                                if (plan != null) amount.updateAndGet(v -> v + plan.getOfferprice());
                            }
                        });
                    }
                }
            }

            if (requestDTOs.getCustChargeDetailsList() != null && !requestDTOs.getCustChargeDetailsList().isEmpty()) {
                List<CustChargeOverrideDTO> custChargeDetails = requestDTOs.getCustChargeDetailsList();
                custChargeDetails.stream().forEach(data -> {
                    List<CustChargeDetailsPojo> details = data.getCustChargeDetailsPojoList();
                    for (CustChargeDetailsPojo pojo : details) {
                        if (pojo.getPrice() != null) amount.updateAndGet(v -> v + pojo.getPrice());
                    }
                });
            }
        }
        return amount.get();
    }

    public Double getTotalAmountOfPlanPriceOfCustomer(CustChargeOverrideDTO custChargeOverrideDTO,Integer mvnoId) {
        Double amount = 0.0;
        if (custChargeOverrideDTO != null) {
            for (CustChargeDetailsPojo pojo : custChargeOverrideDTO.getCustChargeDetailsPojoList()) {
                Double offerPrice = pojo.getPrice();
                Charge charge = chargeService.get(pojo.getChargeid(),mvnoId);
                Tax tax = dbrService.getTax(charge.getTax().getId());
                Double taxAmount = dbrService.getTaxAmount(tax, offerPrice);
                Double offerPriceWithTax = offerPrice + taxAmount;
                amount += offerPriceWithTax;
            }
        }
        return amount;
    }

    public Double getTotalAmountOfPlanPriceOfCustomer(DeactivatePlanReqDTO requestDTOs,Integer mvnoId) {
        Double amount = 0.0;
        if (requestDTOs != null) {
            if (!requestDTOs.getDeactivatePlanReqModels().isEmpty()) {
                for (DeactivatePlanReqModel model : requestDTOs.getDeactivatePlanReqModels()) {
                    if (model.getNewPlanId() != null) {
                        PostpaidPlan plan = postpaidPlanService.get(model.getNewPlanId(),mvnoId);
                        if (plan != null) amount += plan.getOfferprice();
                    } else if (model.getNewPlanGroupId() != null) {
                        PlanGroup planGroup = planGroupRepository.findById(model.getPlanGroupId()).orElse(null);
                        if (planGroup != null) amount += planGroup.getOfferprice();
                    }
                }
            }
        }
        return amount;
    }

