    public void generatePrepaidInvoiceForFlutterWave(CustomersPojo subscriber, Integer custPackId, Integer loggedInUserId, HashSet<Integer> oldDebitDocId, String createdByName, String updateByName, String creditDocumentId, String isFromFlutterWave) {
        String SUBMODULE = MODULE + " [generatePrepaidInvoice()] ";
        try {
            DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyyMMdd");
            String strDate = LocalDate.now().format(formatter);

            if (null != subscriber.getCusttype() && subscriber.getCusttype().equalsIgnoreCase(CommonConstants.CUST_TYPE_PREPAID)) {
                CustomerBillingMessage message = new CustomerBillingMessage(strDate, subscriber.getId(), custPackId, null, null, subscriber.getPartnerLedgerMappingId(), loggedInUserId, oldDebitDocId, createdByName, updateByName, creditDocumentId, isFromFlutterWave, "", null);
//                messageSender.send(message, RabbitMqConstants.QUEUE_BILLING_INVOICE);
                kafkaMessageSender.send(new KafkaMessageData(message, CustomerBillingMessage.class.getSimpleName()));
            }
        } catch (Exception e) {
            ApplicationLogger.logger.error(":Billing API Call Fail response{};exception{}:", APIConstants.FAIL, e.getMessage());
        }
    }

