    public void updateCustPlanPlappingTrialPeriod(CustomersPojo subscriber) {

        Double trialPlanPeirodConstant = Double.valueOf(clientServiceSrv.getByNameAndMvnoIdEquals(Constants.TRIAL_PLAN_PERIOD_THRESHOLD, getMvnoIdFromCurrentStaff(subscriber.getId())).getValue());
        Integer tpValidityCount = Integer.valueOf(clientServiceSrv.getByNameAndMvnoIdEquals(Constants.ALLOW_NUMBER_OF_TIME_TRAIL, getMvnoIdFromCurrentStaff(subscriber.getId())).getValue());
        subscriber.getPlanMappingList().forEach(custPlanMapppingPojo -> {
            if (custPlanMapppingPojo.getIsTrialValidityDays() != null) {
                Integer count = custPlanMapppingPojo.getTrialPlanValidityCount();
                Double tpvDays = custPlanMapppingPojo.getIsTrialValidityDays();
                if (custPlanMapppingPojo.getId() != null) {
                    CustPlanMappping custPlanMappping1 = custPlanMappingRepository.findById(custPlanMapppingPojo.getId());
                    tpvDays = tpvDays + custPlanMappping1.getIsTrialValidityDays();
                }
                if (tpvDays > trialPlanPeirodConstant || custPlanMapppingPojo.getIsTrialValidityDays() > trialPlanPeirodConstant || custPlanMapppingPojo.getTrialPlanValidityCount() >= tpValidityCount) {
                    throw new CustomValidationException(HttpStatus.NOT_ACCEPTABLE.value(), "Trial Plan Period Validity cannot be extended more than 3 times or 90 days", null);
                } else if (tpvDays <= trialPlanPeirodConstant && custPlanMapppingPojo.getIsTrialValidityDays() <= trialPlanPeirodConstant && custPlanMapppingPojo.getTrialPlanValidityCount() < tpValidityCount) {
                    custPlanMapppingPojo.setEndDate(custPlanMapppingPojo.getEndDate().plusDays((long) (custPlanMapppingPojo.getIsTrialValidityDays() - 1)));
                    custPlanMapppingPojo.setExpiryDate(custPlanMapppingPojo.getExpiryDate().plusDays((long) (custPlanMapppingPojo.getIsTrialValidityDays() - 1)));
                    count = count + 1;
                    custPlanMapppingPojo.setTrialPlanValidityCount(count);
                    custPlanMapppingPojo.setIsTrialValidityDays(tpvDays);
                }
            } else if (custPlanMapppingPojo.getIsTrialValidityDays() == null) {
                custPlanMapppingPojo.setIsTrialValidityDays(0.0);
            }
            CustPlanMappping custPlanMappping = custPlanMappingService.save(custPlanMappingService.convertDTOToDomain(custPlanMapppingPojo), "");
        });
    }

