    @Transactional
    public GenericDataDTO approveCustomerServiceAdd(Integer customerServiceMappingId, Boolean isApproveRequest, String remarks, String token) {
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        try {
            StaffUser assignedStaff = new StaffUser();
            CustomerServiceMapping customerServiceMapping = customerServiceMappingRepository.findById(customerServiceMappingId).orElse(null);
            StaffUser staffUser = staffUserRepository.findById(customerServiceMapping.getNextStaff()).orElse(null);
            Map<String, String> map = new HashMap<>();
            Boolean isFinalApproved = false;
            Customers customers = customersRepository.findById(customerServiceMapping.getCustId()).orElse(null);
            List<CustPlanMappping> custPlanMapppingList = custPlanMappingRepository.findAllByCustServiceMappingId(customerServiceMapping.getId());
            ClientService clientCDATAService = clientServiceRepository.getByNameAndMvnoId(CommonConstants.CDATA_CONSTANTS.CONFIG_NAME, getLoggedInMvnoId(customers.getId()));
            if (customerServiceMapping != null) {
                if (customers.getParentCustomers() != null && customers.getInvoiceType() != null && !customers.getInvoiceType().equalsIgnoreCase("independent")) {
                    if (!subscriberService.canChildApprove(customers, customerServiceMapping.getServiceId())) {
                        throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "Not Allowed as Parent customer doesn't contain the requested service!", null);
                    }
                }
                if (!staffUser.getUsername().equalsIgnoreCase("admin")) {
                    if (clientServiceSrv.getValueByName(ClientServiceConstant.WORKFLOW_AUTOMATIC_ASSIGN,customers.getMvnoId()).equals("TRUE")) {
                        map = hierarchyService.getTeamForNextApproveForAuto(customers.getMvnoId(), customers.getBuId(), CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, CommonConstants.HIERARCHY_TYPE, false, true, customerServiceMapping);
                        int staffId = 0;
                        if (map.containsKey("staffId") && map.containsKey("nextTatMappingId")) {
                            staffId = Integer.parseInt(map.get("staffId"));
                            assignedStaff = staffUserService.get(staffId,customers.getMvnoId());
                            customerServiceMapping.setNextTeamHierarchyMappingId(Integer.valueOf(map.get("nextTatMappingId")));
                            customerServiceMapping.setNextStaff(staffId);
                            if (customerServiceMapping != null) {
                                String action = CommonConstants.WORKFLOW_MSG_ACTION.CUSTOMER_SERVICE_ADD + " with for customer : " + " ' " + customers.getUsername() + " ' ";
                                hierarchyService.sendWorkflowAssignActionMessage(assignedStaff.getCountryCode(), assignedStaff.getPhone(), assignedStaff.getEmail(), assignedStaff.getMvnoId(), assignedStaff.getFullName(), action,assignedStaff.getId().longValue());

                            }
                            workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), assignedStaff.getId(), assignedStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                            workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), staffId, assignedStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.ASSIGNED, LocalDateTime.now(), "Assigned to :- " + assignedStaff.getUsername());
                            if (assignedStaff.getStaffUserparent() != null && !CollectionUtils.isEmpty(map)) {
                                if (map.get("current_tat_id") != null && map.get("current_tat_id") != "null")
                                    map.put("tat_id", map.get("current_tat_id"));
                                tatUtils.saveOrUpdateDataForTatMatrix(map, assignedStaff, customerServiceMapping.getId(), null);
                            }
                        } else {
                            StaffUser currentStaff = staffUserService.get(getLoggedInUserId(),customers.getMvnoId());
                            assignedStaff = currentStaff;
                            customerServiceMapping.setNextTeamHierarchyMappingId(null);
                            customerServiceMapping.setNextStaff(null);
                            customerServiceMapping.setIsDelete(true);
                            if (isApproveRequest.equals(true)) {
                                customerServiceMapping.setStatus("Active");
                                updateCustomerServiseToActive(customerServiceMapping, customers);
                                List<CustInvParamsDto> custInvParamsDtos = cmsClientUtil.getCustInvParamsByCustSerMappId(customerServiceMapping.getId());
                                if (Objects.nonNull(custInvParamsDtos)) {
                                    customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                                    String username = customersRepository.findCustomerName(customerServiceMapping.getCustId());
                                    customersService.createHSNService(customerServiceMapping.getCustId(), username, getLoggedInUser().getUsername(), getLoggedInMvnoId(customers.getId()), customerServiceMapping.getCustId(), customerServiceMapping.getId());
                                }
                                // generate CDATA API call request
                                if (clientCDATAService != null && clientCDATAService.getValue().equalsIgnoreCase("true")) {
                                    String manufacturerName = getVendorName(customerServiceMapping.getCustId(), customerServiceMapping.getConnectionNo());
                                    // String manufacturerName = inventoryClientService.getVerifiedManufacturerName(token, customerServiceMapping.getCustId(), customerServiceMapping.getConnectionNo());
                                    ClientService clientService = clientServiceRepository.getByNameAndMvnoId(CommonConstants.CDATA_CONSTANTS.CDATA_MANUFACTURER, getMvnoIdFromCurrentStaff(customers.getId()));
                                    if (clientService != null) {
                                        if (clientService.getValue().equalsIgnoreCase(manufacturerName)) {
                                            customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                                            log.debug("Customer inventroy parameter found, initiating C-DATA api call");
                                            createCDATAServiceRequest(setCDATAdetails(null, null, null, customerServiceMapping.getCustId(), customerServiceMapping.getCustId(), customerServiceMapping.getId()), token);
                                        }
                                    }
                                }

                                if (!CollectionUtils.isEmpty(custPlanMapppingList)) {
                                    custPlanMapppingList.stream().peek(custPlanMappping -> custPlanMappping.setCustPlanStatus(CommonConstants.ACTIVE_STATUS)).collect(Collectors.toList());
                                }
                                isFinalApproved = true;
                            } else {
                                customerServiceMapping.setStatus(SubscriberConstants.REJECT);
                                if (!CollectionUtils.isEmpty(custPlanMapppingList)) {
                                    custPlanMapppingList.stream().peek(custPlanMappping -> custPlanMappping.setCustPlanStatus(SubscriberConstants.REJECT)).collect(Collectors.toList());
                                }
                                updateCustomerServiseToReject(customerServiceMapping, customers);
                            }
                            workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                        }
                    } else {

                        if (customerServiceMapping != null && isApproveRequest.equals(false) && customerServiceMapping.getNextTeamHierarchyMappingId() == null) {
                            hierarchyService.rejectDirectFromCreatedStaff(CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId());
                            customerServiceMapping.setNextStaff(null);
                            workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), CommonConstants.WORKFLOW_AUDIT_ACTION.REJECTED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");

                        } else {
                            Map<String, Object> mapForManual = hierarchyService.getTeamForNextApprove(customers.getMvnoId(), customers.getBuId(), CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, CommonConstants.HIERARCHY_TYPE, isApproveRequest, customerServiceMapping.getNextTeamHierarchyMappingId() == null, customerServiceMapping);
                            if (mapForManual.containsKey("assignableStaff")) {
                                genericDataDTO.setDataList((List<StaffUserPojo>) mapForManual.get("assignableStaff"));
                            } else {
                                StaffUser currentStaff = staffUserService.get(getLoggedInUserId(),customers.getMvnoId());
                                assignedStaff = currentStaff;
                                customerServiceMapping.setNextTeamHierarchyMappingId(null);
                                customerServiceMapping.setNextStaff(null);
                                if (isApproveRequest.equals(true)) {
                                    List<CustInvParamsDto> custInvParamsDtos = cmsClientUtil.getCustInvParamsByCustSerMappId(customerServiceMapping.getId());
                                    if (custInvParamsDtos.size() > 0) {
                                        customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                                        String username = customersRepository.findCustomerName(customerServiceMapping.getCustId());
                                        customersService.createHSNService(customerServiceMapping.getCustId(), username, getLoggedInUser().getUsername(), getLoggedInMvnoId(customers.getId()), customerServiceMapping.getCustId(), customerServiceMapping.getId());
                                    }
                                    // generate CDATA API call request
                                    if (clientCDATAService != null && clientCDATAService.getValue().equalsIgnoreCase("true")) {
                                        String manufacturerName = inventoryClientService.getVerifiedManufacturerName(token, customerServiceMapping.getCustId(), customerServiceMapping.getConnectionNo());
                                        ClientService clientService = clientServiceRepository.getByNameAndMvnoId(CommonConstants.CDATA_CONSTANTS.CDATA_MANUFACTURER, getMvnoIdFromCurrentStaff(customers.getId()));
                                        if (clientService != null) {
                                            if (clientService.getValue().equalsIgnoreCase(manufacturerName)) {
                                                customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                                                log.debug("Customer inventroy parameter found, initiating C-DATA api call");
                                                createCDATAServiceRequest(setCDATAdetails(null, null, null, customerServiceMapping.getCustId(), customerServiceMapping.getCustId(), customerServiceMapping.getId()), token);
                                            }
                                        }
                                    }

                                    if (custInvParamsDtos.size() == 0) {
                                        customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                                    }
//                                    customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                                    if (!CollectionUtils.isEmpty(custPlanMapppingList)) {
//                                            customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                                        custPlanMapppingList.stream().peek(custPlanMappping -> custPlanMappping.setCustPlanStatus(CommonConstants.ACTIVE_STATUS)).collect(Collectors.toList());
                                        custPlanMappingRepository.saveAll(custPlanMapppingList);
                                    }

                                    updateCustomerServiseToActive(customerServiceMapping, customers);
                                    isFinalApproved = true;
                                } else {
                                    customerServiceMapping.setStatus(SubscriberConstants.REJECT);
                                    updateCustomerServiseToReject(customerServiceMapping, customers);
                                }
                                workflowAuditService.saveAudit(null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                            }
                        }
                    }
                } else {
                    customerServiceMapping.setNextStaff(null);
                    customerServiceMapping.setNextTeamHierarchyMappingId(null);
                    if (isApproveRequest.equals(true)) {
//                        customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                        isFinalApproved = true;
                        List<CustInvParamsDto> custInvParamsDtos = cmsClientUtil.getCustInvParamsByCustSerMappId(customerServiceMapping.getId());
                        if (custInvParamsDtos.size() > 0) {
                            customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                            String username = customersRepository.findCustomerName(customerServiceMapping.getCustId());
                            customersService.createHSNService(customerServiceMapping.getCustId(), username, getLoggedInUser().getUsername(), getLoggedInMvnoId(customers.getId()), customerServiceMapping.getCustId(), customerServiceMapping.getId());
                        }
                        // generate CDATA API call request
                        if (clientCDATAService != null && clientCDATAService.getValue().equalsIgnoreCase("true")) {
                            String manufacturerName = inventoryClientService.getVerifiedManufacturerName(token, customerServiceMapping.getCustId(), customerServiceMapping.getConnectionNo());
                            ClientService clientService = clientServiceRepository.getByNameAndMvnoId(CommonConstants.CDATA_CONSTANTS.CDATA_MANUFACTURER, getMvnoIdFromCurrentStaff(customers.getId()));
                            if (clientService != null) {
                                if (clientService.getValue().equalsIgnoreCase(manufacturerName)) {
                                    customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                                    log.debug("Customer inventroy parameter found, initiating C-DATA api call");
                                    createCDATAServiceRequest(setCDATAdetails(null, null, null, customerServiceMapping.getCustId(), customerServiceMapping.getCustId(), customerServiceMapping.getId()), token);
                                }
                            }
                        }

                        if (custInvParamsDtos.size() == 0) {
                            customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                        }
                        if (!CollectionUtils.isEmpty(custPlanMapppingList)) {
//                                customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                            custPlanMapppingList = custPlanMapppingList.stream().peek(custPlanMappping -> custPlanMappping.setCustPlanStatus(CommonConstants.ACTIVE_STATUS)).collect(Collectors.toList());
                            custPlanMappingRepository.saveAll(custPlanMapppingList);
                        }

                        workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_TERMINATION, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                    } else {
                        customerServiceMapping.setStatus(SubscriberConstants.REJECT);
                        workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_TERMINATION, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), CommonConstants.WORKFLOW_AUDIT_ACTION.REJECTED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                    }

                }
                custPlanMappingRepository.saveAll(custPlanMapppingList);
                customerServiceMappingRepository.save(customerServiceMapping);
            }
            if (customers != null && isFinalApproved) {
                Set<CustomerChargeHistory> customerChargeHistoryList = customerChargeHistoryRepo.findByCustPlanMapppingIdIn(custPlanMapppingList.stream().map(i -> i.getId()).collect(Collectors.toList()));
                List<CustomerServiceMapping> customerServiceMappingList = new ArrayList<>();
                customerServiceMappingList.add(customerServiceMapping);
                createDataSharedService.sendChangePlanForAllMicroService(custPlanMapppingList, null, customerChargeHistoryList, "addNewService", null, customerServiceMappingList, null, null, "", null, null, null, false, false, null,null,null,null);

//                    debitDocService.createInvoiceAfterStartBilling(customers);
            }
        } catch (CustomValidationException e) {
            throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), e.getMessage(), null);
        } catch (Exception e) {
            e.printStackTrace();
            //throw new RuntimeException(e);

        }
        genericDataDTO.setResponseCode(HttpStatus.OK.value());
        genericDataDTO.setResponseMessage(HttpStatus.OK.getReasonPhrase());
        return genericDataDTO;
    }

    /**
     * Activate customer all services
     *
     * @param custID
     * @author akshay
     */
    public void setServiceAddActive(Integer custID) {
        Optional<Customers> customers = customersRepository.findById(custID);
        if (customers.isPresent()) {
            List<CustomerServiceMapping> customerServiceMappings = new ArrayList<>();
            QCustomerServiceMapping qCustomerServiceMapping = QCustomerServiceMapping.customerServiceMapping;
            BooleanExpression booleanExpression = qCustomerServiceMapping.isNotNull().and(qCustomerServiceMapping.custId.eq(custID)).and(qCustomerServiceMapping.status.eq("NewActivation"));
            customerServiceMappings = (List<CustomerServiceMapping>) customerServiceMappingRepository.findAll(booleanExpression);
            if (customerServiceMappings.size() > 0) {
                for (CustomerServiceMapping customerServiceMapping : customerServiceMappings) {
                    customerServiceMapping.setStatus("Active");
                    customerServiceMapping.setNextStaff(null);
                    customerServiceMapping.setNextTeamHierarchyMappingId(null);
                    updateCustomerServiseToActive(customerServiceMapping, customers.get());
                    customerServiceMappingRepository.save(customerServiceMapping);
                }
            }
            QCustPlanMappping qCustPlanMappping = QCustPlanMappping.custPlanMappping;
            BooleanExpression expcpr = qCustPlanMappping.isNotNull().and(qCustPlanMappping.customer.id.eq(custID));
            List<CustPlanMappping> custPlanMappping = (List<CustPlanMappping>) custPlanMappingRepository.findAll(expcpr);
            List<CustPlanMappping> custpacksave = new ArrayList<>();
            for (CustPlanMappping custPlanMappping1 : custPlanMappping) {
                custPlanMappping1.setIsInvoiceCreated(false);
                custPlanMappping1.setDebitdocid(null);
                custpacksave.add(custPlanMappping1);
            }
            custPlanMappingRepository.saveAll(custpacksave);


            QCustomerInventoryMapping qCustomerInventoryMapping = QCustomerInventoryMapping.customerInventoryMapping;
            BooleanExpression expInventoryMapping = qCustomerInventoryMapping.isNotNull().and(qCustomerInventoryMapping.customer.id.eq(custID));
            List<CustomerInventoryMapping> customerInventoryMappingList = (List<CustomerInventoryMapping>) customerInventoryMappingRepo.findAll(expInventoryMapping);
            List<CustomerInventoryMapping> custinventorySave = new ArrayList<>();
            for (CustomerInventoryMapping customerInventoryMapping : customerInventoryMappingList) {
                customerInventoryMapping.setIsInvoiceCreated(false);
                custinventorySave.add(customerInventoryMapping);
            }
            customerInventoryMappingRepo.saveAll(custinventorySave);

            QCustChargeDetails qCustChargeDetails = QCustChargeDetails.custChargeDetails;
            BooleanExpression expChargeDtls = qCustChargeDetails.isNotNull().and(qCustChargeDetails.customer.id.eq(custID));
            List<CustChargeDetails> custChargeDetailsList = (List<CustChargeDetails>) custChargeDetailsRepository.findAll(expChargeDtls);
            List<CustChargeDetails> saveCustchargedtls = new ArrayList<>();

            for (CustChargeDetails custChargeDetails : custChargeDetailsList) {
                custChargeDetails.setIsUsed(false);
                saveCustchargedtls.add(custChargeDetails);
            }
            custChargeDetailsRepository.saveAll(saveCustchargedtls);


        }


    }

    public void setServiceAddReject(Integer custID) {
        Optional<Customers> customers = customersRepository.findById(custID);
        if (customers.isPresent()) {
            List<CustomerServiceMapping> customerServiceMappings = new ArrayList<>();
            QCustomerServiceMapping qCustomerServiceMapping = QCustomerServiceMapping.customerServiceMapping;
            BooleanExpression booleanExpression = qCustomerServiceMapping.isNotNull().and(qCustomerServiceMapping.custId.eq(custID)).and(qCustomerServiceMapping.status.eq("NewActivation"));
            customerServiceMappings = (List<CustomerServiceMapping>) customerServiceMappingRepository.findAll(booleanExpression);
            if (customerServiceMappings.size() > 0) {
                for (CustomerServiceMapping customerServiceMapping : customerServiceMappings) {
                    customerServiceMapping.setStatus("Reject");
                    updateCustomerServiseToReject(customerServiceMapping, customers.get());
                    customerServiceMappingRepository.save(customerServiceMapping);
                }
            }
        }
    }

    /**
     * Activate customer specific services
     *
     * @param customerServiceMapping
     * @param customers
     * @author yogesh
     */
    public void updateCustomerServiseToActive(CustomerServiceMapping customerServiceMapping, Customers customers) {
        List<CustPlanMappping> custPlanMapppingList = custPlanMappingRepository.findAllByCustServiceMappingId(customerServiceMapping.getId());
        for (CustPlanMappping custPlanMappping : custPlanMapppingList) {
            if (custPlanMappping.getIstrialplan() != null && !custPlanMappping.getIstrialplan()) {
                custPlanMappping.setIsinvoicestop(false);
            }
            LocalDate startDate = custPlanMappping.getStartDate().toLocalDate();
            Long daysDiff = ChronoUnit.DAYS.between(startDate, LocalDate.now());
//            if (daysDiff > 0) {
            custPlanMappping.setStartDate(custPlanMappping.getStartDate().plusDays(daysDiff));
            if (customers.getParentCustomers() == null) {
                custPlanMappping.setEndDate(custPlanMappping.getEndDate().plusDays(daysDiff));
                custPlanMappping.setExpiryDate(custPlanMappping.getExpiryDate().plusDays(daysDiff));

            }
            custPlanMappping.setStartDate(LocalDateTime.now());
            custPlanMappping.setCustPlanStatus(CommonConstants.ACTIVE_STATUS);
            custPlanMappingRepository.save(custPlanMappping);
//            }
        }
    }

    /**
     * Stop customer specific services
     *
     * @param customerServiceMapping
     * @param customers
     * @author yogesh
     */
    public void updateCustomerServiseToReject(CustomerServiceMapping customerServiceMapping, Customers customers) {
        List<CustPlanMappping> custPlanMapppingList = custPlanMappingRepository.findAllByCustServiceMappingId(customerServiceMapping.getId());
        for (CustPlanMappping custPlanMappping : custPlanMapppingList) {
            custPlanMappping.setIsinvoicestop(true);
            custPlanMappping.setCustPlanStatus(CommonConstants.STOP_STATUS);
            custPlanMappping.setIsDelete(true);
            custPlanMappping.setEndDate(LocalDateTime.now().minusMinutes(1));
            custPlanMappping.setExpiryDate(LocalDateTime.now().minusMinutes(1));
            custPlanMappingRepository.save(custPlanMappping);
        }
    }

    @Transactional
    public GenericDataDTO approveBulkCustomerServiceAdd(List<Integer> customerServiceMappingId, Boolean isApproveRequest, String remarks) {
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        try {
            Customers customers = null;
            boolean isFinalApproved = false;
            for (int i = 0; i < customerServiceMappingId.size(); i++) {
                try {
                    StaffUser assignedStaff = new StaffUser();
                    CustomerServiceMapping customerServiceMapping = customerServiceMappingRepository.findById(customerServiceMappingId.get(i)).orElse(null);
                    StaffUser staffUser = staffUserRepository.findById(customerServiceMapping.getNextStaff()).orElse(null);
                    Map<String, String> map = new HashMap<>();
                    if (customerServiceMapping != null) {
                        customers = customersRepository.findById(customerServiceMapping.getCustId()).orElse(null);
                        if (customers.getParentCustomers() != null) {
                            if (!subscriberService.canChildApprove(customers, customerServiceMapping.getServiceId())) {
                                throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "Not Allowed as Parent customer service expired!", null);
                            }
                        }
                        if (!staffUser.getUsername().equalsIgnoreCase("admin")) {
                            if (clientServiceSrv.getValueByName(ClientServiceConstant.WORKFLOW_AUTOMATIC_ASSIGN,customers.getMvnoId()).equals("TRUE")) {
                                map = hierarchyService.getTeamForNextApproveForAuto(customers.getMvnoId(), customers.getBuId(), CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, CommonConstants.HIERARCHY_TYPE, false, true, customerServiceMapping);
                                int staffId = 0;
                                if (map.containsKey("staffId") && map.containsKey("nextTatMappingId")) {
                                    staffId = Integer.parseInt(map.get("staffId"));
                                    assignedStaff = staffUserService.get(staffId,customers.getMvnoId());
                                    customerServiceMapping.setNextTeamHierarchyMappingId(Integer.valueOf(map.get("nextTatMappingId")));
                                    customerServiceMapping.setNextStaff(staffId);
                                    if (customerServiceMapping != null) {
                                        String action = CommonConstants.WORKFLOW_MSG_ACTION.CUSTOMER_SERVICE_ADD + " with for customer : " + " ' " + customers.getUsername() + " ' ";
                                        hierarchyService.sendWorkflowAssignActionMessage(assignedStaff.getCountryCode(), assignedStaff.getPhone(), assignedStaff.getEmail(), assignedStaff.getMvnoId(), assignedStaff.getFullName(), action,assignedStaff.getId().longValue());

                                    }
                                    workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), assignedStaff.getId(), assignedStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                                    workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), staffId, assignedStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.ASSIGNED, LocalDateTime.now(), "Assigned to :- " + assignedStaff.getUsername());
                                    if (assignedStaff.getStaffUserparent() != null && !CollectionUtils.isEmpty(map)) {
                                        if (map.get("current_tat_id") != null && map.get("current_tat_id") != "null")
                                            map.put("tat_id", map.get("current_tat_id"));
                                        tatUtils.saveOrUpdateDataForTatMatrix(map, assignedStaff, customerServiceMapping.getId(), null);
                                    }
                                } else {
                                    StaffUser currentStaff = staffUserService.get(getLoggedInUserId(),customers.getMvnoId());
                                    assignedStaff = currentStaff;
                                    customerServiceMapping.setNextTeamHierarchyMappingId(null);
                                    customerServiceMapping.setNextStaff(null);
                                    customerServiceMapping.setIsDelete(true);
                                    if (isApproveRequest.equals(true)) {
                                        updateCustomerServiseToActive(customerServiceMapping, customers);
                                        customerServiceMapping.setStatus("Active");
                                        isFinalApproved = true;
                                    } else {
                                        customerServiceMapping.setStatus(SubscriberConstants.REJECT);
                                        updateCustomerServiseToReject(customerServiceMapping, customers);
                                    }
                                    workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                                }
                            } else {
                                Map<String, Object> mapForManual = hierarchyService.getTeamForNextApprove(customers.getMvnoId(), customers.getBuId(), CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, CommonConstants.HIERARCHY_TYPE, isApproveRequest, customerServiceMapping.getNextTeamHierarchyMappingId() == null, customerServiceMapping);
                                if (mapForManual.containsKey("assignableStaff")) {
                                    genericDataDTO.setDataList((List<StaffUserPojo>) mapForManual.get("assignableStaff"));
                                } else {
                                    StaffUser currentStaff = staffUserService.get(getLoggedInUserId(),customers.getMvnoId());
                                    assignedStaff = currentStaff;
                                    customerServiceMapping.setNextTeamHierarchyMappingId(null);
                                    customerServiceMapping.setNextStaff(null);
                                    if (isApproveRequest.equals(true)) {
                                        updateCustomerServiseToActive(customerServiceMapping, customers);
                                        customerServiceMapping.setStatus("Active");
                                        isFinalApproved = true;
                                    } else {
                                        customerServiceMapping.setStatus(SubscriberConstants.REJECT);
                                        updateCustomerServiseToReject(customerServiceMapping, customers);
                                    }
                                    workflowAuditService.saveAudit(null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_ADD, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), currentStaff.getId(), currentStaff.getUsername(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                                }
                            }
                        } else {
                            customerServiceMapping.setNextStaff(null);
                            customerServiceMapping.setNextTeamHierarchyMappingId(null);
                            if (isApproveRequest.equals(true)) {
                                customerServiceMapping.setStatus(SubscriberConstants.ACTIVE);
                                workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_TERMINATION, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), CommonConstants.WORKFLOW_AUDIT_ACTION.APPROVED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                            } else {
                                customerServiceMapping.setStatus(SubscriberConstants.REJECT);
                                workflowAuditService.saveAudit(map.containsKey("eventId") ? Integer.parseInt(map.get("eventId")) : null, CommonConstants.WORKFLOW_EVENT_NAME.CUSTOMER_SERVICE_TERMINATION, customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), customerServiceMapping.getId(), customerServiceMapping.getConnectionNo(), CommonConstants.WORKFLOW_AUDIT_ACTION.REJECTED, LocalDateTime.now(), "Remarks  : " + remarks + "\n");
                            }

                        }
                        customerServiceMappingRepository.save(customerServiceMapping);
                    }
                } catch (CustomValidationException e) {
                    throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), e.getMessage(), null);
                } catch (Exception e) {
                    e.printStackTrace();
                    //throw new RuntimeException(e);

                }
            }
            if (customers != null && isFinalApproved) {
                try {
                    debitDocService.createInvoiceAfterStartBilling(customers);
                } catch (InterruptedException e) {
                    logger.error("Exception on create invoice after service approval: " + e.getMessage());
                }
            }
            genericDataDTO.setResponseCode(HttpStatus.OK.value());
            genericDataDTO.setResponseMessage(HttpStatus.OK.getReasonPhrase());
            return genericDataDTO;
        } catch (CustomValidationException e) {
            throw new RuntimeException(e);
        }


    }

