    @Transactional
    public void convertCustomerPlangroupToIndividual(CustPlanMappping custPlanMappping) {
        if (custPlanMappping.getPlanGroup() != null) {
            QCustPlanMappping qCustPlanMappping = QCustPlanMappping.custPlanMappping;
            BooleanExpression expression = qCustPlanMappping.isNotNull();
            expression = expression.and(qCustPlanMappping.customer.id.eq(custPlanMappping.getCustomer().getId())).and(qCustPlanMappping.planGroup.planGroupId.eq(custPlanMappping.getPlanGroup().getPlanGroupId()));
            List<CustPlanMappping> custPlanMapppingList = (List<CustPlanMappping>) custPlanMappingRepository.findAll(expression);
            if (!CollectionUtils.isEmpty(custPlanMapppingList)) {
                custPlanMapppingList = custPlanMapppingList.stream().peek(custPlanMap -> custPlanMap.setPlanGroup(null)).collect(Collectors.toList());
                custPlanMappingRepository.saveAll(custPlanMapppingList);
            }
        }
    }

    @Transactional
    public Map<String, Object> deriveChildCustomersFromOrgCust(String custLabel, CustomersPojo customerObj) throws Exception {
        log.info("Intializing fetching process for child customer list from organization customers for : " + customerObj.getUsername());
        List<CustomersPojo> newChildCustList = new ArrayList<>();
        Map<String, Object> allFinalCafList = new HashMap<>();

        if ((custLabel != null && custLabel.equalsIgnoreCase("organization")) && (customerObj.getIsCustCaf() != null && customerObj.getIsCustCaf().equalsIgnoreCase("yes"))) {

            List<CustPlanMappping> custPlanMappingList = new ArrayList<>();

            if (customerObj.getPlanMappingList() != null && customerObj.getPlanMappingList().size() > 0) {
                for (CustPlanMapppingPojo custPlanInstance : customerObj.getPlanMappingList()) {
                    CustomersPojo childNewCustPojo = new CustomersPojo();
                    childNewCustPojo = convertCircuitToChildCustomer(customerObj, custPlanInstance);
                    if (childNewCustPojo != null) newChildCustList.add(childNewCustPojo);
                }
            }
            if (newChildCustList != null && newChildCustList.size() > 0) {
                customerObj.getPlanMappingList().clear();
                allFinalCafList.put("orgCaf", customerObj);
                allFinalCafList.put("childCustList", newChildCustList);
            }
        }
        log.info("Fetching process for child customer list from organization customers for : " + customerObj.getUsername() + " Completed");
        return allFinalCafList;
    }

    public CustomersPojo convertCircuitToChildCustomer(CustomersPojo customerObj, CustPlanMapppingPojo custPlanMappingInstance) {
        CustomersPojo newCustomer = new CustomersPojo();
        log.info("Processing convertCircuitToChildCustomer method for customer : " + customerObj.getUsername());
        if (customerObj != null && custPlanMappingInstance != null) {
            if (customerObj.getTitle() != null) newCustomer.setTitle(customerObj.getTitle());

            if (custPlanMappingInstance != null && custPlanMappingInstance.getPlanId() != null) {
                Optional<PostpaidPlan> planInstance = postpaidPlanRepo.findById(custPlanMappingInstance.getPlanId());
                if (planInstance.isPresent()) {
                    if (planInstance.get().getName() != null) {
                        newCustomer.setFirstname(planInstance.get().getName());
                        newCustomer.setLastname(planInstance.get().getName());
                        newCustomer.setUsername(planInstance.get().getName());
                        newCustomer.setPassword(planInstance.get().getName());
                    }
                }
            }
            if (customerObj.getServiceareaid() != null) newCustomer.setServiceareaid(customerObj.getServiceareaid());
            if (customerObj.getMobile() != null) newCustomer.setMobile(customerObj.getMobile());

            if (customerObj.getBillday() != null) newCustomer.setBillday(customerObj.getBillday());

            if (customerObj.getBranch() != null) {
                newCustomer.setBranch(customerObj.getBranch());
            } else {
                if (customerObj.getPartnerid() != null) newCustomer.setPartnerid(customerObj.getPartnerid());
            }
            if (customerObj.getIsorgcust() != null) newCustomer.setIsorgcust(customerObj.getIsorgcust());
            if (customerObj.getAddressList() != null && customerObj.getAddressList().size() > 0)
                newCustomer.setAddressList(customerObj.getAddressList());
            if (customerObj.getEmail() != null) newCustomer.setEmail(customerObj.getEmail());

            if (custPlanMappingInstance != null)
                newCustomer.setPlanMappingList(Collections.singletonList(custPlanMappingInstance));

            newCustomer.setStatus(SubscriberConstants.NEW_ACTIVATION);
            newCustomer.setCustomerType("Customer");
            if (customerObj.getContactperson() != null) newCustomer.setContactperson(customerObj.getContactperson());

            if (customerObj.getCustcategory() != null) newCustomer.setCustcategory(customerObj.getCustcategory());

            if (customerObj.getCalendarType() != null) newCustomer.setCalendarType(customerObj.getCalendarType());

            if (customerObj.getCusttype() != null) newCustomer.setCusttype(customerObj.getCusttype());
            newCustomer.setInvoiceType("group");
            newCustomer.setParentExperience(CommonConstants.PARENT_EXPERIENCE_SINGLE);
        }
        log.info("Process for convertCircuitToChildCustomer method for customer : " + customerObj.getUsername() + " completed");
        return newCustomer;
    }

