    public long getChildCustomerCount(Integer customerId, String invoiceType) {
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isDeleted.eq(false).and(qCustomers.parentCustomers.id.eq(customerId));
        if (getBUIdsFromCurrentStaff().size() != 0)
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(customerId)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        JPAQueryFactory queryFactory = new JPAQueryFactory(entityManager);
        return queryFactory.selectFrom(qCustomers).where(booleanExpression).fetchCount();
    }

    public boolean checkPlanCustomerBindingIsFreePlanAddon(Integer id) {
        List<CustPlanMappping> custPlanMapppingList = custPlanMappingRepository.findAllByCustomerId(id);
        custPlanMapppingList = custPlanMapppingList.stream().filter(custPlanMappping -> custPlanMappping.getPlanId().equals(14)).collect(Collectors.toList());
        custPlanMapppingList = custPlanMapppingList.stream().filter(custPlanMappping -> ChronoUnit.DAYS.between(custPlanMappping.getExpiryDate().toLocalDate(), LocalDateTime.now().toLocalDate()) < 0).collect(Collectors.toList());
        return !custPlanMapppingList.isEmpty();
    }
