    public Page<Customers> getAllActiveCustomerList(Integer pageNumber, Integer customPageSize, String sortBy, Integer sortOrder, List<GenericSearchModel> filterList) {
        Page<Customers> customers = null;
        PageRequest pageRequest = generatePageRequest(pageNumber, customPageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        QCustomers qCustomers = QCustomers.customers;
        BooleanExpression booleanExpression = qCustomers.isNotNull().and(qCustomers.isDeleted.eq(false)).and(qCustomers.status.equalsIgnoreCase(CommonConstants.ACTIVE_STATUS));
        if (getLoggedInUserId() != 1) {
            if (!super.getServiceAreaIdList().isEmpty())
                booleanExpression = booleanExpression.and(qCustomers.servicearea.id.in(super.getServiceAreaIdList()));
        }

        if (!getLoggedInUser().getLco()) booleanExpression = booleanExpression.and(qCustomers.lcoId.isNull());
        else booleanExpression = booleanExpression.and(qCustomers.lcoId.eq(getLoggedInUserPartnerId()));

        // TODO: pass mvnoID manually 6/5/2025
        if (getMvnoIdFromCurrentStaff(null) != 1)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.in(getMvnoIdFromCurrentStaff(null), 1));
        if (getBUIdsFromCurrentStaff().size() != 0)
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.eq(1).or(qCustomers.mvnoId.eq(getMvnoIdFromCurrentStaff(null)).and(qCustomers.buId.in(getBUIdsFromCurrentStaff()))));
        if (getLoggedInUserPartnerId() == CommonConstants.DEFAULT_PARTNER_ID) {
            customers = customersRepository.findAll(booleanExpression, pageRequest);
        } else {
            booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
            customers = customersRepository.findAll(booleanExpression, pageRequest);
        }
        return customers;
    }

    public Page<CustomerListingPojo> getAllActiveCustomerList1(Integer pageNumber, Integer customPageSize, String sortBy, Integer sortOrder, List<GenericSearchModel> filterList,Integer mvnoId) {
        PageRequest pageRequest = generatePageRequest(pageNumber, customPageSize, "createdate", CommonConstants.SORT_ORDER_DESC);
        QCustomers qCustomers = QCustomers.customers;

        BooleanExpression booleanExpression = qCustomers.isNotNull()
                .and(qCustomers.isDeleted.eq(false))
                .and(qCustomers.status.equalsIgnoreCase(CommonConstants.ACTIVE_STATUS));

        if (getLoggedInUserId() != 1 && !super.getServiceAreaIdList().isEmpty()) {
            booleanExpression = booleanExpression.and(qCustomers.servicearea.id.in(super.getServiceAreaIdList()));
        }

        if (!getLoggedInUser().getLco()) {
            booleanExpression = booleanExpression.and(qCustomers.lcoId.isNull());
        } else {
            booleanExpression = booleanExpression.and(qCustomers.lcoId.eq(getLoggedInUserPartnerId()));
        }

        // TODO: pass mvnoID manually 6/5/2025
        if (mvnoId != 1) {
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(qCustomers.mvnoId.in(mvnoId, 1));
        }

        if (!getBUIdsFromCurrentStaff().isEmpty()) {
            // TODO: pass mvnoID manually 6/5/2025
            booleanExpression = booleanExpression.and(
                    qCustomers.mvnoId.eq(1)
                            .or(qCustomers.mvnoId.eq(mvnoId)
                                    .and(qCustomers.buId.in(getBUIdsFromCurrentStaff())))
            );
        }

        if (getLoggedInUserPartnerId() != CommonConstants.DEFAULT_PARTNER_ID) {
            booleanExpression = booleanExpression.and(qCustomers.partner.id.eq(getLoggedInUserPartnerId()));
        }


        JPAQueryFactory queryFactory = new JPAQueryFactory(entityManager);
        JPQLQuery<CustomerListingPojo> query = queryFactory
                .select(Projections.constructor(CustomerListingPojo.class,
                        qCustomers.id,
                        qCustomers.firstname,
                        qCustomers.lastname,
                        qCustomers.username,
                        qCustomers.mobile,
                        qCustomers.email,
                        qCustomers.acctno,
                        qCustomers.outstanding,
                        qCustomers.status,
                        qCustomers.custtype,
                        //set if neccessary
//                        qCustomers.ConnectionMode,
                        qCustomers.calendarType,
                        qCustomers.isinvoicestop,
                        qCustomers.istrialplan,
                        qCustomers.leadNo,
                        qCustomers.leadId,
                        qCustomers.nextTeamHierarchyMapping,
                        qCustomers.servicearea,
                        qCustomers.title
                ))
                .from(qCustomers)
                .where(booleanExpression)
                .orderBy(qCustomers.id.desc())
                .offset(pageRequest.getOffset())
                .limit(pageRequest.getPageSize());

        List<CustomerListingPojo> list = query.fetch();
        list.forEach(this::computeFullName);
        long total = query.fetchCount();

        return new PageImpl<>(list, pageRequest, total);
    }

    private void computeFullName(CustomerListingPojo customer) {
        StringBuilder fullNameBuilder = new StringBuilder();

        if (customer.getTitle() != null && !customer.getTitle().isEmpty())
            fullNameBuilder.append(customer.getTitle()).append(" ");
        if (customer.getFirstname() != null && !customer.getFirstname().isEmpty())
            fullNameBuilder.append(customer.getFirstname()).append(" ");
        if (customer.getLastname() != null && !customer.getLastname().isEmpty())
            fullNameBuilder.append(customer.getLastname());

        String fullName = fullNameBuilder.toString().trim();
        customer.setName(fullName.isEmpty() ? "-" : fullName);
    }

