    public List<CustomerPlanDetail> updateCustomerEndDate(String endDate, String username, Integer mvnoId, String ctype, Boolean isSendRadius) {
        List<CustomerPlanDetail> customerPlanDetails = new LinkedList<>();
        try {
            if (username.contains("$")) {
                username = username.substring(0, username.indexOf("$")).trim();
                ctype = "GUEST";
            }
            QCustomers qCustomer = QCustomers.customers;
            BooleanExpression expression = qCustomer.isNotNull().and(qCustomer.mvnoId.eq(mvnoId));//.and(qCustomer.customerStatus.equalsIgnoreCase("Active"));
            if (ctype.equalsIgnoreCase("GUEST")) {
                expression = expression.and(qCustomer.username.contains(username));
            } else {
                expression = expression.and(qCustomer.username.eq(username));
            }
            List<Customers> customers = (List<Customers>) customersRepository.findAll(expression);
            if (CollectionUtils.isEmpty(customers)) {
                throw new IllegalArgumentException("No record found for the customer to update the end date");
            } else {
                for (Customers customer : customers) {
                    List<CustPlanMappping> custplan = custPlanMappingRepository.findAllByCustomerId(customer.getId());
                    DateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm");
                    Date date = sdf.parse(endDate);
                    LocalDateTime dateTime = LocalDateTime.ofInstant(date.toInstant(), ZoneId.systemDefault());
                    if (dateTime.isAfter(LocalDateTime.now())) {
                        customer.setStatus("Active");
                    } else {
                        customer.setStatus("Inactive");
                    }
                    for (CustPlanMappping customerPlanDetail : custplan) {
                        customerPlanDetail.setEndDate(dateTime);
                        custPlanMappingRepository.save(customerPlanDetail);
                        if (isSendRadius) {
                            custPlanMappingService.updateCustPlanEndDateInRadius(customerPlanDetail, "");
                        }
                    }
                    customersRepository.save(customer);
                }

            }
        } catch (Throwable e) {
            throw new RuntimeException(e.getMessage());
        }
        return customerPlanDetails;
    }

    @Transactional
    public void recieveCustomerEnddateMessage(CustomerEndDateUpdateMessage message) {
        Map<String, Object> data = message.getCustomerData();
        if (data.get("username") == null) {
            throw new IllegalArgumentException("username is not found");
        }
        if (data.get("endDate") == null) {
            throw new IllegalArgumentException("Enddate is not found");
        }
        if (data.get("mvnoId") == null) {
            throw new IllegalArgumentException("MvnoId is not found");
        }
        String username = data.get("username").toString();
        String enddate = data.get("endDate").toString();
        Integer mvnoId = Integer.parseInt(data.get("mvnoId").toString());
        updateCustomerEndDate(enddate, username, mvnoId, "Member", false);
    }

