    public Boolean isCustomerIsNotOrgCust(String username) {
        // TODO: pass mvnoID manually 6/5/2025
        Integer mvnoId = getMvnoIdFromCurrentStaff(null);
        Customers customers = new Customers();
        if (mvnoId != null) {
            try {
                customers = customersRepository.findByUsernameAndMvnoIdAndStatusNot(username, mvnoId, "Terminate").orElse(null);
            } catch (Exception e) {
                throw new CustomValidationException(404, "username already exist", null);
            }
        } else {
            customers = customersRepository.findByUserName(username);
        }
        if (customers != null) {
            if (username.contains("@") && customers.getCustlabel() != null && customers.getCustlabel().equalsIgnoreCase("organization")) {
                String isOrgCustNotificationEnable = clientServiceRepository.findValueByNameandMvnoId("ORGANIZATIONCUSTNOTIFICATION", customers.getMvnoId());
                if (isOrgCustNotificationEnable != null) {
                    return !isOrgCustNotificationEnable.equalsIgnoreCase("0") && !isOrgCustNotificationEnable.equalsIgnoreCase("false");
                } else {
                    return true;
                }
            } else {
                return true;
            }
        } else {
            return true;
        }
    }

    public void sendCustPaymentFailedMessage(String message, String customerName, Double paymentAmount, String paymentMode, Integer mvnoId, String countryCode, String mobileNumber, String emailId, Integer userId, String reciptNo, String paymentdate, Long buId, Integer planId) {
        try {
            {
                String currencySymbol = RabbitMqConstants.CURRENCY_SYMBOLE;
                if (!currencySymbol.isEmpty()) {
                    Optional<TemplateNotification> optionalTemplate = templateRepository.findByTemplateName(RabbitMqConstants.CUSTOMER_PAYMENT_FAILED);
                    if (optionalTemplate.isPresent()) {
                        if (optionalTemplate.get().isSmsEventConfigured() || optionalTemplate.get().isEmailEventConfigured()) {
                            // Set message in queue to send notification after opt generated successfully.
                            String planName = "";
                            if (planId != null) {
                                Optional<PostpaidPlan> postpaidPlan = postpaidPlanRepo.findById(planId);
                                if (postpaidPlan.isPresent()) {
                                    planName = postpaidPlan.get().getName();
                                }
                            }
                            String password = "";
                            Optional<Customers> customers = customersRepository.findById(userId);
                            if (customers.isPresent()) {
                                password = customers.get().getPassword();
                            }

                            PaymentFailedMessage paymentFailedMessage = new PaymentFailedMessage(message, customerName, currencySymbol, paymentAmount, paymentMode, mvnoId, optionalTemplate.get(), RabbitMqConstants.SOURCE_NAME_ADOPT_BSS_GATEWAY, countryCode, mobileNumber, emailId, userId, reciptNo, paymentdate, buId, planName, password,customers.get());
                            Gson gson = new Gson();
                            gson.toJson(paymentFailedMessage);
                            kafkaMessageSender.send(new KafkaMessageData(paymentFailedMessage, PaymentFailedMessage.class.getSimpleName()));
//                            messageSender.send(paymentFailedMessage, RabbitMqConstants.QUEUE_SEND_CUSTOMER_PAYMENT_FAILED);
                        }
                    }
                }
            }
        } catch (Throwable e) {
            ApplicationLogger.logger.error("Unable to Sed Payment response  response{};exception{}", APIConstants.FAIL, e.getStackTrace());
            throw new RuntimeException(e.getMessage());
        }
    }

