    public Boolean ifIpForCustomerExit(List<CustIpMapping> custIpMappings) {
        List<String> IpAddressList = custIpMappings.stream().map(custIpMapping -> custIpMapping.getIpAddress()).collect(Collectors.toList());
        Customers customer = customersService.getRepository().findById(custIpMappings.get(0).getCustid()).orElse(null);
        Boolean flag = true;
        if (customer != null) {
            flag = custIpMappingRepo.existsByIpAddressIn(IpAddressList);
            if (flag) {
                if (customer.getStatus().equalsIgnoreCase("Terminate")) {
                    flag = !flag;
                }
            }
        }
        return flag;
    }


