    public void updateCustPlanStatusFromRadius(CustomerPackageRelMessage message) {
        Map<String, Object> map = message.getData();
        if (map.containsKey("custPlanId")) {
            Integer custPlanId = Double.valueOf(map.get("custPlanId").toString()).intValue();
            CustPlanMappping custPlanMappping = custPlanMappingRepository.findById(custPlanId);
            if (custPlanMappping != null) {
                if (map.containsKey("endDate")) {
                    String endDate = map.get("endDate").toString();
                    LocalDateTime endDateTime;
                    try {
                        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
                        endDateTime = LocalDateTime.parse(endDate, formatter);
                    }catch (Exception e){
                        endDateTime = LocalDateTime.parse(endDate);
                    }
                    if(map.containsKey("custPlanStatus")) {
                        custPlanMappping.setStatus(map.get("custPlanStatus").toString());
                    }
                    custPlanMappping.setEndDate(endDateTime);
                    custPlanMappping.setExpiryDate(endDateTime);
                    custPlanMappingRepository.save(custPlanMappping);
                }
            }
        }
    }

    public CustomerPaymentDto sharedCustomerDataForm(CustomersPojo pojo, Boolean isCaptivePortal, CustomerPaymentDto customerPaymentDto) {
        Customers customers = customerMapper.dtoToDomain(pojo, new CycleAvoidingMappingContext());
        List<CustPlanMappping> custPlanMapppingList = custPlanMappingRepository.findAllByCustomerId(customers.getId());
        List<CustomerServiceMapping> customerServiceMappingList = customerServiceMappingRepository.findAllByCustId(customers.getId());
        List<CustomerChargeHistory> customerChargeHistories = customerChargeHistoryRepo.findAllByCustomerId(customers.getId());
        if (pojo.getPaymentDetails() != null) {
            if (pojo.getPaymentDetails().getChequedate() != null) {
                pojo.getPaymentDetails().setChequedatestr(pojo.getPaymentDetails().getChequedate().toString());
                pojo.getPaymentDetails().setChequedate(null);
            }
            if (pojo.getPaymentDetails().getPaymentdate() != null) {
                pojo.getPaymentDetails().setPaymentdatestr(pojo.getPaymentDetails().getPaymentdate().toString());
                pojo.getPaymentDetails().setPaymentdate(null);
            }
        }
        CustomMessage customMessage = new CustomMessage(pojo);
//        messageSender.send(customMessage, RabbitMqConstants.QUEUE_APIGW_CUSTOMER);
        kafkaMessageSender.send(new KafkaMessageData(customMessage, CustomMessage.class.getSimpleName()));
        CustomerPaymentDto customerPayment = null;
        if (customerPaymentDto != null) {
            customerPaymentDto.setCustId(customers.getId());
            customerPaymentDto.setCustomerId(customers.getId());
            customerPaymentDto.setAccountNumber(customers.getAcctno());
            customerPaymentDto.setMobileNumber(customers.getMobile());
            customerPaymentDto.setMvnoId(customers.getMvnoId());
            customerPaymentDto.setIsFromCaptive(isCaptivePortal);
            customerPayment = customersService.addPaymentStatus(customerPaymentDto);
            pojo.setReferenceNo(customerPayment.getOrderId());
        }
        createDataSharedService.sendCustomerEntityForAllMicroService(customers, custPlanMapppingList, customerServiceMappingList, customerChargeHistories, pojo, isCaptivePortal, null);

        for (CustPlanMappping planMapppingPojo : custPlanMapppingList) {
            CustPackageRelMessage message = new CustPackageRelMessage(custPlanMappingService.convertDomainToDto(planMapppingPojo), "");
            message.setCustomerCreated(pojo.isCustomerCreated());
            message.getData().put("status", null);
            kafkaMessageSender.send(new KafkaMessageData(message, CustPackageRelMessage.class.getSimpleName()));
//            messageSender.send(message, RabbitMqConstants.QUEUE_APIGW_CUSTOMER_PACKAGE_REL);
        }
        return customerPayment;
    }

    public void deleteCustomerMACFromApigateway(CustMacMappingMessage message) {
        Map<String, Object> data = message.getData();
        if (!CollectionUtils.isEmpty(data)) {
            QCustomers qCustomer = QCustomers.customers;
            BooleanExpression boolExp = qCustomer.isNotNull();
            if (Objects.nonNull(data.get("mvnoId"))) {
                Integer mvnoId = (Integer) data.get("mvnoId");
                boolExp = boolExp.and(qCustomer.mvnoId.in(ValidateCrudTransactionData.validateMvnoId(Integer.valueOf(data.get("mvnoId").toString())), 1));
            }
            boolExp = boolExp.and(qCustomer.username.eq(data.get("userName").toString()));
            Optional<Customers> customer = customersRepository.findOne(boolExp);
            if (Objects.isNull(customer)) {
                throw new IllegalArgumentException("No record found with customer name '" + data.get("userName") + "'. Please enter valid customer name");
            }
            QCustMacMappping qCustMacMappping = QCustMacMappping.custMacMappping;
            String macAddress = data.get("macAddress").toString();
            custMacMapppingRepository.deleteInBatch(custMacMapppingRepository.findAll(qCustMacMappping.customer.id.eq(customer.get().getId()).and(qCustMacMappping.macAddress.eq(macAddress))));
//            terminateLiveUserSessionAfterMacUpdateOrDelete(macAddress, customer.get().getMvnoId(), customer.get().getUsername());
        }
    }

    public void updateCustomerMacFromApiGTW(CustMacMappingMessage message) {
        Map<String, Object> data = message.getData();
        if (!CollectionUtils.isEmpty(data)) {
            CustMacMappping custMacMappping = new CustMacMappping();
//            custMacMappping.setCustomerId(Long.valueOf(data.get("custid").toString()));
            custMacMappping.setMacAddress(data.get("macAddress").toString());

            if (message.getMessageDate() != null) {
                Date date = message.getMessageDate();
                LocalDateTime localDateTime = date.toInstant().atZone(ZoneId.systemDefault()).toLocalDateTime();

                custMacMappping.setCreatedate(localDateTime);
            } else {
                custMacMappping.setCreatedate(LocalDateTime.now());

            }

            QCustomers qCustomer = QCustomers.customers;
            BooleanExpression boolExp = qCustomer.isNotNull();
            if (Objects.nonNull(data.get("mvnoId"))) {
                Integer mvnoId = (Integer) data.get("mvnoId");
                boolExp = boolExp.and(qCustomer.mvnoId.in(ValidateCrudTransactionData.validateMvnoId(Integer.valueOf(data.get("mvnoId").toString())), 1));
            }
            boolExp = boolExp.and(qCustomer.username.eq(data.get("userName").toString()));
            Optional<Customers> customer = customersRepository.findOne(boolExp);
            Customers customers = customersRepository.findAllById(((Integer) data.get("custid")));
            custMacMappping.setCustomer(customers);
            if (!customer.isPresent()) {
                throw new IllegalArgumentException("No record found with customer name '" + data.get("userName") + "'. Please enter valid customer name");
            }
            if (Objects.nonNull(data.get("custsermapid"))) {
                custMacMappping.setCustsermappingid((Integer) data.get("custsermapid"));
            }
            QCustMacMappping qCustMacMappping = QCustMacMappping.custMacMappping;
            List<CustMacMappping> oldMac = (List<CustMacMappping>) custMacMapppingRepository.findAll(qCustMacMappping.customer.id.eq(customer.get().getId()).and(qCustMacMappping.macAddress.eq(data.get("macAddress").toString()).or(qCustMacMappping.custsermappingid.eq((Integer) data.get("custsermapid")))));

            if (oldMac.size() == 0) {
                oldMac.add(custMacMappping);
                this.saveCustMapping(new HashSet<CustMacMappping>(oldMac), Long.valueOf(data.get("custid").toString()), Integer.valueOf(data.get("mvnoId").toString()));
            } else {
                CustMacMappping oldCustMacMapping = custMacMapppingRepository.findByCustomerIdAndCustsermappingid(custMacMappping.getCustsermappingid().longValue(), custMacMappping.getCustsermappingid());
                if (oldCustMacMapping != null) {
                    //macAddressMappingRepository.deleteById(oldmacAddressMapping.getMacAddressId());
                    oldCustMacMapping.setMacAddress(custMacMappping.getMacAddress());
//                    terminateLiveUserSessionAfterMacUpdateOrDelete(macMapping.getMacAddress(), customer.get().getMvnoId(), customer.get().getUsername());
                    custMacMapppingRepository.save(oldCustMacMapping);
                }
            }
        }
    }

