    private void saveserviceAudit(CustPlanMappping custPlanMappping, Integer resonId, String custPlanStatus) {
        try {
            ServiceAudit serviceAudit = new ServiceAudit();
            serviceAudit.setAction(custPlanStatus);
            if (custPlanMappping.getServiceHoldDate() != null)
                serviceAudit.setServiceStopTime(custPlanMappping.getServiceHoldDate());
            if (custPlanMappping.getStartServiceDate() != null)
                serviceAudit.setServicestarttime(custPlanMappping.getStartServiceDate());
            if (custPlanMappping.getServiceHoldDate() != null) {
                serviceAudit.setServiceStopTime(LocalDateTime.now());
            }
            serviceAudit.setCprid(Long.valueOf(custPlanMappping.getId()));
            serviceAudit.setRemarks(custPlanStatus);
//            if (pojo.getReasonId() != -1) {
            serviceAudit.setReasonId(resonId.toString());
//            }
            String reason = commonListRepository.findByReasonId(resonId);
            // CommonList commonList = commonListRepository.findCategoryReasonById(pojo.getReasonId());
            serviceAudit.setReason(reason);
            serviceAudit.setStaffId(Long.valueOf(getLoggedInUserId()));
            StaffUser staffUser = staffUserRepository.findById(getLoggedInUserId()).get();
            serviceAudit.setStaffName(staffUser.getUsername());
            serviceAudit.setCustServiceMappingId(custPlanMappping.getCustServiceMappingId());
            serviceAuditRepository.save(serviceAudit);

        } catch (Exception ex) {
            ex.printStackTrace();
        }

    }

    public void updateMvnoCustomerAddress(Mvno mvno, UpdateMvnoSharedDataMessage mvnoSharedDataMessage) {
        try {
            if (mvno.getCustInvoiceRefId() != null) {
                CustomerAddress address = custAddressService.findAddressByCustomerId(mvno.getCustInvoiceRefId());
                if (address != null) {
                    address.setLandmark(mvnoSharedDataMessage.getAddress());
                    address.setVersion("NEW");
                    custAddressService.save(address);
                } else {
                    Customers mvnoCustomers = customersRepository.findById(mvno.getCustInvoiceRefId()).orElse(null);
                    if (mvnoCustomers != null) {
                        CustomerAddress addressForSave = new CustomerAddress();
                        addressForSave.setCustomer(mvnoCustomers);
                        addressForSave.setAddressType("Present");
                        addressForSave.setVersion("NEW");
                        addressForSave.setCreatedById(getLoggedInUserId());
                        addressForSave.setIsDelete(false);
                        addressForSave.setLastModifiedById(getLoggedInUserId());
                        addressForSave.setLandmark(mvnoSharedDataMessage.getAddress());
                        custAddressService.save(addressForSave);
                    }
                }

            }
        } catch (Exception ex) {
            ex.printStackTrace();
        }

    }


