    /**
     * This method is not common method This is created for a specific case
     **/
    public List<LightCustomerPlanMappingDTO> getCustomerListByMobileNumberOrEmail(String mobileNumber, String email) {
        List<LightCustomerPlanMappingDTO> customerPlanMappingDTOList = custPlanMappingRepository.findAllByMobileOrEmail(mobileNumber, email);
        Map<Long, LightCustomerPlanMappingDTO> customerMap = new HashMap<>();
        for (LightCustomerPlanMappingDTO plan : customerPlanMappingDTOList) {
            if (!"Volume Booster".equals(plan.getPlanGroup()) && !"Bandwidthbooster".equals(plan.getPlanGroup()) && !"DTV Addon".equals(plan.getPlanGroup())) {
                customerMap.putIfAbsent(plan.getCustId().longValue(), plan);
            }
        }
        Iterator<LightCustomerPlanMappingDTO> iterator = customerPlanMappingDTOList.iterator();
        while (iterator.hasNext()) {
            LightCustomerPlanMappingDTO plan = iterator.next();

            if ("Volume Booster".equals(plan.getPlanGroup()) || "Bandwidthbooster".equals(plan.getPlanGroup()) || "DTV Addon".equals(plan.getPlanGroup())) {
                iterator.remove(); // Remove from main list
                LightCustomerPlanMappingDTO customer = customerMap.get(plan.getCustId().longValue());
                if (customer != null) {
                    // Initialize volumeBoosterList if null
                    if (customer.getBoosterList() == null) {
                        customer.setBoosterList(new ArrayList<>());
                    }
                    // Add the volume booster plan to the customer's volumeBoosterList
                    customer.getBoosterList().add(plan);
                }
            }
        }

        return customerPlanMappingDTOList;
    }


    public Boolean changeCustomerStatus(RemoveAccountRequest request, Integer mvnoid) {
        try {
            String userName = request.getUserName().toLowerCase().trim();
            // Fetch customer or throw an exception if not found
            Customers customers = customersRepository.findByUsernameAndMvnoIdAndStatusNot(userName, mvnoid, "Terminate").orElseThrow(() -> new NoSuchElementException("Customer not found with username: " + request.getUserName()));
            log.error(LogConstants.USERNAME_NOT_FOUND + userName);
            if (!customers.getStatus().equalsIgnoreCase(SubscriberConstants.TERMINATE)) {
                customers.setUsername(customers.getUsername() + "_" + System.currentTimeMillis());
                customers.setStatus("Terminate");
                customersRepository.save(customers);
                CustomerUpdateMessage message = new CustomerUpdateMessage(customers);
                kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));
                removeAllMacFromCustomer(customers);
                removeIpFromCustomer(customers);
                return true;
            }
        } catch (NoSuchElementException e) {
            log.error("Customer not found: {}");
            return false;
        } catch (Exception e) {
            log.error("Error occurred while changing customer status", e);
            throw e;
        }
        return false;
    }

    public Boolean changeSubscriberCustomerStatus(String username, Integer mvnoid) {
        try {
            // Fetch customer or throw an exception if not found
            Customers customers = customersRepository.findByUsernameAndMvnoId(username, mvnoid).orElseThrow(() -> new NoSuchElementException("Customer not found with username: " + username));
            log.error(LogConstants.USERNAME_NOT_FOUND + username);
            if (!customers.getStatus().equalsIgnoreCase(SubscriberConstants.TERMINATE)) {
                customers.setUsername(customers.getUsername() + "_" + System.currentTimeMillis());
                customers.setStatus("Terminate");
                customersRepository.save(customers);
                CustomerUpdateMessage message = new CustomerUpdateMessage(customers);
                kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));
                removeAllMacFromCustomer(customers);
                removeIpFromCustomer(customers);
                return true;
            }
        } catch (NoSuchElementException e) {
            log.error("Customer not found: {}");
            return false;
        } catch (Exception e) {
            log.error("Error occurred while changing customer status", e);
            throw e;
        }
        return false;
    }

    public void validateServiceArea(Customers customersCaf) {
        if ((null != customersCaf) && (null != customersCaf.getServicearea()) && (null != customersCaf.getServicearea().getStatus()) && (!customersCaf.getServicearea().getStatus().equalsIgnoreCase("Active"))) {
            if ((null != customersCaf) && (null != customersCaf.getServicearea()) && (null != customersCaf.getServicearea().getStatus()) && (customersCaf.getServicearea().getStatus().equalsIgnoreCase("Inactive"))) {
                throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "The Service Area is InActive. Please first activate the Service Area", null);
            } else {
                throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "The Service Area is UnderDevelopment. Please first activate the Service Area", null);
            }
        }
    }

    public void updateCustomerAndCustomerPlanDate(CustNextBilldateMessage message) {
        HashMap<Integer, LocalDate> customerWithNextBillDate = message.getCustNextBillDateMap();
        HashMap<Integer, LocalDate> customerWithNextQuotaDate = message.getCustNextQuotaDateMap();
        HashMap<Long, LocalDateTime> cpr = message.getCprEndDateMap();
        for (Entry<Integer, LocalDate> entry : customerWithNextBillDate.entrySet()) {
            if (entry.getKey() != null && entry.getValue() != null)
                customersRepository.updateNextBillDate(entry.getKey(), entry.getValue());
        }

        for (Entry<Integer, LocalDate> entry : customerWithNextQuotaDate.entrySet()) {
            if (entry.getKey() != null && entry.getValue() != null)
                customersRepository.updateNextQuotaDate(entry.getKey(), entry.getValue());
        }

        for (Entry<Long, LocalDateTime> entry : cpr.entrySet()) {
            if (entry.getKey() != null && entry.getValue() != null)
                custPlanMappingRepository.updateCustPlanMappingEnddateAndExpiryDate(entry.getKey().intValue(), entry.getValue(), entry.getValue());
        }
    }

    public void removeAllMacFromCustomer(Customers customer) {
        try {
            List<CustMacMappping> custMacMappingList = new ArrayList<>();
            custMacMappingList = custMacMapppingRepository.findByCustomerId(customer.getId());
            if (!custMacMappingList.isEmpty() && custMacMappingList != null) {
                custMacMappingList.stream().forEach(mac -> mac.setDeleteFlag(true));

                CustMacMappingMessage message = new CustMacMappingMessage(customer);
                kafkaMessageSender.send(new KafkaMessageData(message, message.getClass().getSimpleName()));
                custMacMapppingRepository.saveAll(custMacMappingList);
            }
        } catch (Exception e) {
            log.error(e.getMessage());
        }
    }

    public void removeIpFromCustomer(Customers customer) {
        try {
            List<CustIpMapping> custIpMappingList = new ArrayList<>();
            custIpMappingList = custIpMappingRepo.getAllByCustid(customer.getId());
            if (!custIpMappingList.isEmpty() && custIpMappingList != null) {
                custIpMappingRepo.deleteInBatch(custIpMappingList);
                CustIPMessage custIPMessage = new CustIPMessage(custIpMappingList, true);
                kafkaMessageSender.send(new KafkaMessageData(custIPMessage, custIPMessage.getClass().getSimpleName(), "CUSTOMER_IP_TO_DELETE_RADIUS"));
            }
        } catch (Exception e) {
            log.error(e.getMessage());
        }
    }

