    public String getServiceName(Integer serviceId) {
        // Generate the cache key for serviceName based on the serviceId
        String cacheKey = cacheKeys.SERVICENAME + serviceId;
        String serviceName = null;

        try {
            serviceName = (String) cacheService.getFromCache(cacheKey, String.class);
            if (serviceName != null) {
                return serviceName;
            }

            serviceName = serviceRepository.findServiceNameById(serviceId);

            if (serviceName != null) {
                cacheService.putInCache(cacheKey, serviceName);
                return serviceName;
            }
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }

        return null;
    }

    public CustomerNotesDto saveNotes(CustomerNotesDto customerNotesDto, Long staffId) {
        String SUBMODULE = MODULE + "saveNotes()";

        try {
            CustomerNotes customerNotes = new CustomerNotes(customerNotesDto, staffId);
            // Fetch staff user in a single query
            StaffUser staffUser = staffId != null ? staffUserRepository.findById(staffId.intValue()).orElse(null) : null;
            customerNotes.setCreatedByName(staffUser != null ? staffUser.getUsername() : "-");
            // Audit log message
            if (staffUser != null) {
                String auditName = staffUser.getFirstname() + " added lead note in Lead. Note: "
                        + customerNotesDto.getNotes() + ".";
                logger.info(auditName);
            }

            // Save note and return DTO
            CustomerNotes savedNote = customerNotesRepository.save(customerNotes);
            logger.info("LeadNote has been added successfully");
            return new CustomerNotesDto(savedNote);

        } catch (Exception ex) {
            logger.error(SUBMODULE + " Error: " + ex.getMessage(), ex);
            ex.printStackTrace();
            throw ex;
        }
    }

    public Page<CustomerNotesDto> findAllCustomerNoteWithPagination(PaginationRequestDTO paginationRequestDTO, Long id) {
        String SUBMODULE = MODULE + "findAllCustomerNoteWithPagination()";
        try {
            PageRequest pageRequest = super.generatePageRequest(paginationRequestDTO.getPage(),
                    paginationRequestDTO.getPageSize(), paginationRequestDTO.getSortBy(),
                    paginationRequestDTO.getSortOrder());

            Optional<Customers> customers = customersRepository.findById(Math.toIntExact(id));
            if (!customers.isPresent()) {
                throw new CustomValidationException(APIConstants.INTERNAL_SERVER_ERROR,
                        "Customer is not found for ID: " + id, null);
            }

            Page<CustomerNotesDto> pojoPageList = customerNotesRepository
                    .findByCustomerId(customers.get().getId(), pageRequest)
                    .map(CustomerNotesDto::new);

            return pojoPageList;

        } catch (Exception ex) {
            logger.error(SUBMODULE + ex.getMessage(), ex);
            ex.printStackTrace();
            throw ex;
        }
    }


