    public void ServiceActiveActionsForNMS(ClientService clientService, ClientService clientCDATAService, String nmsEnable, Customers customersCaf, HttpServletRequest req) {

        //HSN SERVICE CODE
        if (clientService != null) {
            if (clientService.getValue().equalsIgnoreCase("true")) {
                //calling below function to create hsn service when customer is get activated
                boolean isSuccess = createHSNService(customersCaf.getId(), customersCaf.getUsername(), getLoggedInUser().getUsername(), getLoggedInMvnoId(customersCaf.getId()), null);
                if (isSuccess) {
                    customersCaf.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                    List<CustomerServiceMapping> customerServiceMappings = customersCaf.getCustomerServiceMappingList();
                    if (!CollectionUtils.isEmpty(customerServiceMappings)) {
                        customerServiceMappings = customerServiceMappings.stream().peek(customerServiceMapping -> customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING)).collect(Collectors.toList());
                        customerServiceMappingRepository.saveAll(customerServiceMappings);
                    }
                }
            }
        }
        //NMS SERVICE CODE
        if (nmsEnable != null && nmsEnable.equalsIgnoreCase(NMSIntegrationConstants.NMS_INTEGRATION.TRUE_FLAG)) {
            String token = req.getHeader(NMSIntegrationConstants.NMS_INTEGRATION.AUTHORIZATION);
            NMSIntegrationResDto nmsIntegrationResDto = inventoryMappingService.sendNMSIntegration(token, customersCaf.getId(), customersCaf.getUsername(), customersCaf.getPassword());
            if (!nmsIntegrationResDto.isApiFlag()) {
                log.warn(":::::::::::::: Going to set ACTIVATION_PENDING ::::::::::::::: " + nmsIntegrationResDto.isApiFlag());
                customersCaf.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                List<CustomerServiceMapping> customerServiceMappings = customersCaf.getCustomerServiceMappingList();
                if (!CollectionUtils.isEmpty(customerServiceMappings)) {
                    customerServiceMappings = customerServiceMappings.stream().peek(customerServiceMapping -> customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING)).collect(Collectors.toList());
                    customerServiceMappingRepository.saveAll(customerServiceMappings);
                }
            }
        }
        // CDATA SERVICE CODE
        if (clientCDATAService != null && clientCDATAService.getValue().equalsIgnoreCase("true")) {
            String token = req.getHeader("Authorization");
            log.warn("Customer inventroy parameter found, initiating C-DATA api call");
            boolean isSuccess = createCDATAServiceRequest(setCDATAdetails(null, null, null, customersCaf.getId(), null, null), token);
            if (!isSuccess) {
                customersCaf.setStatus(SubscriberConstants.ACTIVATION_PENDING);
                List<CustomerServiceMapping> customerServiceMappings = customersCaf.getCustomerServiceMappingList();
                if (!CollectionUtils.isEmpty(customerServiceMappings)) {
                    customerServiceMappings = customerServiceMappings.stream().peek(customerServiceMapping -> customerServiceMapping.setStatus(SubscriberConstants.ACTIVATION_PENDING)).collect(Collectors.toList());
                    customerServiceMappingRepository.saveAll(customerServiceMappings);
                }
            }
        }
    }


    public CustFieldsPojo getCustomerRequiredData(Integer id) {
        CustFieldsPojo custFieldsPojo = new CustFieldsPojo();
        try {
            custFieldsPojo = customersRepository.findCustomerDetailsByIdAndIsDeletedIsFalse(id);
            List<NewCustPlanMappingPojo> custPlanMappingPojoList = custPlanMappingRepository.findAllCustPlanMappingByCustId(id);
            for (NewCustPlanMappingPojo newCustPlanMappingPojo : custPlanMappingPojoList) {
                String planName = postpaidPlanRepo.findPlanNameByPlanId(newCustPlanMappingPojo.getPlanId());
                List<String> billableCustAddress = customerAddressRepository.findLandMarkByCustId(newCustPlanMappingPojo.getBillableCustomerId());
                if (!billableCustAddress.isEmpty()) {
                    newCustPlanMappingPojo.setBillableAddress(billableCustAddress.get(0));
                }
                newCustPlanMappingPojo.setPlanName(planName);
            }

            List<ChildCustomer> childCustomerList = childCustomerRepo.findBasicInfo(id.longValue(),Arrays.asList(custFieldsPojo.getMvnoId().longValue(),1L));
            if(!childCustomerList.isEmpty()){
                ChildCustomer childCustomer = childCustomerList.get(0);
                custFieldsPojo.setLoginUsername(childCustomer.getUserName());
                custFieldsPojo.setLoginPassword(childCustomer.getPassword());
            }
//            Integer billableCustomerId = custPlanMappingPojoList.get(0).getBillableCustomerId();
            List<NewAddressListPojo> addressList = customerAddressRepository.findAddressListByCustomerId(id);
            Long cityId = serviceAreaRepository.findCityId(custFieldsPojo.getServiceareaid());
            CityPojo cityPojo = cityRepository.findCityDetailsByCityId(cityId.intValue());
            custFieldsPojo.setDistrict(cityPojo.getStateName());
            custFieldsPojo.setProvince(cityPojo.getName());
            Area area = areaRepository.findAreaById(addressList.get(0).getAreaId().longValue());
            custFieldsPojo.setWard(area.getName());
            String pincode = pincodeRepository.findPincodeNameById(area.getPincode().getId());
            custFieldsPojo.setMuncipalities(pincode);
//            String subArea = subAreaRepository.findSubAreaNameByCityId(cityId.intValue());
//            custFieldsPojo.setSubArea(subArea);
            Map<String, Object> objectMap = customerAddressRepository.findBuildingAndSubareaNames(id);
            custFieldsPojo.setBuildingName(objectMap.get("name") != null ? objectMap.get("name").toString() : null);
            custFieldsPojo.setSubArea(objectMap.get("building_name") != null ? objectMap.get("building_name").toString() : null);
//            BuildingManagement buildingManagement = buildingMgmtRepository.findBuildingNameByAreaId(area.getId().intValue());
//            custFieldsPojo.setBuildingName(buildingManagement.getBuildingName());
//            String buildingNum = buildingMappingRepository.findBuildingNumFromId(buildingManagement.getBuildingMgmtId());
//            custFieldsPojo.setBuildingNum(buildingNum);
//            if(billableCustomerId!=null){
//                NewAddressListPojo address = customerAddressRepository.findLatestAddressByCustomerId(billableCustomerId);
//                custFieldsPojo.setBillableCustomerAddress(address.getFullAddress());
//            }
//            List<Object[]> customerLocations = customerLocationRepository.findAllByCustomerId(Long.valueOf(id));
//            List<CustomerLocationMappingDto> customerLocationMappingDtos = customerLocations.stream()
//                    .map(obj ->{
//                        CustomerLocationMapping customerLocationMapping = (CustomerLocationMapping) obj[0];
//                             return new CustomerLocationMappingDto(
//                            customerLocationMapping.getLocationId(), customerLocationMapping.getLocationName(),
//                            customerLocationMapping.getIsParentLocation(),customerLocationMapping.getMac());
//                    })
//                    .collect(Collectors.toList());
            custFieldsPojo.setCustPlanMappingPojoList(custPlanMappingPojoList);
            custFieldsPojo.setAddressListPojos(addressList);
//            custFieldsPojo.setCustomerLocationMappingDtos(customerLocationMappingDtos);
            List<Timestamp> macRetentionDate = custMacMapppingRepository.findNearestMacRetentionDateByCustomerId(id);
            if (!org.apache.commons.collections4.CollectionUtils.isEmpty(macRetentionDate)) {
                if (macRetentionDate.get(0) != null) {
                    custFieldsPojo.setNearestMacRetentionDate(macRetentionDate.get(0).toLocalDateTime().toLocalDate());
                }
            }
            String parentQuotaType = customersService.getParentQuotaByCustomerId(id);
            if (parentQuotaType != null) {
                custFieldsPojo.setParentQuotaType(parentQuotaType);
            }
            List<Long> itemId = customerInventoryMappingRepo.findItemIdByCustomerId(id);
            List<String> serialNum = itemRepository.getSerialNumberListByItemId(itemId);
            custFieldsPojo.setOnuSerialNumber(serialNum);
//            LocalDateTime chargeDate = custChargeDetailsRepository.findChargeDateByCustomerId(id);
//            custFieldsPojo.setCharge_date(chargeDate);
            String branchName = "";
            List<RegionBranchMapping> regionBranchList = new ArrayList<>();
            if (custFieldsPojo.getBranch() != null) {
                branchName = branchRepository.findNameById(custFieldsPojo.getBranch());
                regionBranchList = regionBranchRepository.findAllBybranchId(custFieldsPojo.getBranch());
            } else {
                branchName = partnerRepository.findNameByPartnerId(custFieldsPojo.getPartnerid());
            }
            custFieldsPojo.setBranchName(branchName);
            // Process regions and business verticals efficiently
            if (!regionBranchList.isEmpty()) {
                List<Long> regionIds = regionBranchList.stream()
                        .map(mapping -> mapping.getRegionid().getId())
                        .collect(Collectors.toList());

                // Fetch business verticals in a single query
                List<BusinessVerticalsMapping> businessVerticals = businessVerticalsMappingRepository.findByRegionIds(regionIds);
                Set<String> regionNames = regionBranchList.stream()
                        .map(mapping -> mapping.getRegionid().getRname())
                        .collect(Collectors.toSet());
                // Extract business vertical names
                Set<String> buVerticalNames = businessVerticals.stream()
                        .map(bv -> bv.getBusinessVerticals().getVname())
                        .collect(Collectors.toSet());
                custFieldsPojo.setRegionName(String.join(",", regionNames));
                custFieldsPojo.setBuVerticals(String.join(",", buVerticalNames));
            }
//            List<NewCreditDocPojo> creditDocumentPojos = creditDocRepository.getAllListByCustId(id);
//            custFieldsPojo.setCreditDocPojoList(creditDocumentPojos);
        } catch (Exception e) {
            log.error("Something Went Wrong while fetch details regarding customer data." + e.getMessage());
            throw new RuntimeException(e);
        }
        return custFieldsPojo;
    }

    public boolean checkstaffExistinCAFworkflow(Integer staffId, Integer nextTeamHierarchyMappingId) {
        try {
            TeamHierarchyMapping teamHierarchyMapping = teamHierarchyMappingRepo.findById(nextTeamHierarchyMappingId).orElse(null);
            if (teamHierarchyMapping != null) {
                //workflow first team
                Teams team = teamsRepository.findById(teamHierarchyMapping.getTeamId().longValue()).orElse(null);
                if (team != null) {
                    //loggedinsuer staff teams
                    List<Long> teamIds = teamUserMappingsRepocitory.teamIds(staffId.longValue());
                    for (Long teamIDs : teamIds) {
                        if (teamIDs.equals(team.getId())) {
                            return true;
                        }
                    }
                }
                return false;
            }
            return false;
        } catch (Exception e) {
            e.printStackTrace();
        }
        return false;
    }
