    @Transactional
    public void resetCustomerQuota(CustQuotaResetDTO custQuotaResetDTO) {
        LocalDateTime today = LocalDateTime.now();
        log.info("Message Received for reset customer quota from Radius at: "+today+" milli: "+System.currentTimeMillis());
        HashMap<Integer, String> custNextQuotaResetDate = custQuotaResetDTO.getCustNextQuotaResetDate();
        HashMap<Integer, String> custNextBillDate = custQuotaResetDTO.getCustNextBillDate();
        HashMap<Long, String> cprLastQuotaResetDate = custQuotaResetDTO.getCprLastQuotaResetDate();
        HashMap<Long, String> cprEndDate = custQuotaResetDTO.getCprEndDate();

        DateTimeFormatter dtf = DateTimeFormatter.ofPattern("yyyy-MM-dd");

        if(!CollectionUtils.isEmpty(custNextQuotaResetDate)) {
            log.info("Update Next Quota Reset Date");
            for (Map.Entry<Integer, String> entry : custNextQuotaResetDate.entrySet()) {
                Integer key = entry.getKey();
                String value = entry.getValue();
                log.info("custNextQuotaResetDate Key: " + key + ", Value: " + value);
                try{
                    customersRepository.updateNextQuotaDate(entry.getKey(), LocalDate.parse(value,dtf));
                } catch(Exception ex){
                    ex.printStackTrace();
                    log.error("Exception to update next Quota Reset Date: "+key+" value: "+value);
                }
            }
        }
        if(!CollectionUtils.isEmpty(custNextBillDate)) {
            log.info("Update Next Bill Date");
            for (Map.Entry<Integer, String> entry : custNextBillDate.entrySet()) {
                Integer key = entry.getKey();
                String value = entry.getValue();
                log.info("custNextBillDate Key: " + key + ", Value: " + value);
                try{
                    customersRepository.updateNextBillDate(entry.getKey(), LocalDate.parse(value,dtf));
                } catch(Exception ex){
                    ex.printStackTrace();
                    log.error("Exception to update next Quota Reset Date: "+key+" value: "+value);
                }
            }
        }
        if(!CollectionUtils.isEmpty(cprLastQuotaResetDate)) {
            log.info("Update Last Quota Reset Date");
            for (Map.Entry<Long, String> entry : cprLastQuotaResetDate.entrySet()) {
                Long key = entry.getKey();
                String value = entry.getValue();
                log.info("cprLastQuotaResetDate Key: " + key + ", Value: " + value);
                try{
                    LocalDateTime lasteQuotaResetDate = DateTimeUtil.getLocaldateTimefromString(value);
                    custQuotaRepository.updateQuotaDetailsAndLastQuotaResetDateByCprIds(lasteQuotaResetDate, entry.getKey().intValue());
                } catch(Exception ex){
                    ex.printStackTrace();
                    log.error("Exception to update next Quota Reset Date: "+key+" value: "+value);
                }
            }
        }
        if(!CollectionUtils.isEmpty(cprEndDate)) {
            log.info("Update CPR End Date");
            for (Map.Entry<Long, String> entry : cprEndDate.entrySet()) {
                Long key = entry.getKey();
                String value = entry.getValue();
                log.info("cprEndDate Key: " + key + ", Value: " + value);
                try{
                    LocalDateTime endDate = DateTimeUtil.getLocaldateTimefromString(value);
                    custPlanMappingRepository.updateCustPlanMappingEnddateAndExpiryDate(key.intValue(), endDate, endDate);
                } catch(Exception ex) {
                    ex.printStackTrace();
                    log.error("Exception to update CPR End Date: "+key+" value: "+value);
                }
            }
        }
        log.info("Message Received for reset customer quota from Radius at: "+LocalDateTime.now()+" milli: "+System.currentTimeMillis());


    }
