    public List<CustChargeDetails> custChargeDetailsPojoListToCustChargeDetailsList(List<CustChargeDetailsPojo> list, CycleAvoidingMappingContext context) {
        List<CustChargeDetails> target = context.getMappedInstance( list, List.class );
        if ( target != null ) {
            return target;
        }

        if ( list == null ) {
            return null;
        }

        List<CustChargeDetails> list1 = new ArrayList<CustChargeDetails>( list.size() );
        context.storeMappedInstance( list, list1 );

        for ( CustChargeDetailsPojo custChargeDetailsPojo : list ) {
            list1.add( custChargeDetailsPojoToCustChargeDetails( custChargeDetailsPojo, context ) );
        }

        return list1;
    }


